import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Scanner;

public class Main {
	public static void main(String[] args) {
		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Initialize a list to store the input strings
		List<String> list = new ArrayList<String>();

		// Read the number of strings to be input
		int n = sc.nextInt();

		// Loop to read each string and add it to the list
		for(int i = 0; n > i; i++) {
			String a = sc.next(); // Read the next string
			list.add(a); // Add the string to the list
		}

		// Sort the list of strings in lexicographical order
		Collections.sort(list);

		// Initialize a list to store the count of consecutive duplicates
		List<Integer> list_count = new ArrayList<Integer>();

		// Loop through the sorted list to count consecutive duplicates
		for(int i = 0; n - 1 > i; i++) {
			int count = 0; // Initialize count for current string

			// Check if the current string is equal to the next string
			if(list.get(i).equals(list.get(i + 1))) {
				count++; // Increment count for the first duplicate
				i++; // Move to the next string

				// Continue counting while the next strings are equal
				while(true) {
					if(i == n - 1) // Break if at the end of the list
						break;
					if(!list.get(i).equals(list.get(i + 1))) // Break if strings are not equal
						break;
					count++; // Increment count for each duplicate
					i++; // Move to the next string
				}
			}
			// Add the count of duplicates to the list
			list_count.add(count);
		}

		// Find the maximum count of duplicates
		int max = Collections.max(list_count);

		// Initialize a list to store the strings with the maximum duplicates
		List<String> list_answer = new ArrayList<String>();

		// If no duplicates were found, print all strings and exit
		if(max == 0) {
			for(int i = 0; list.size() > i; i++) {
				System.out.println(list.get(i)); // Print each string
			}
			System.exit(0); // Exit the program
		}

		// Loop through the sorted list again to find strings with the maximum duplicates
		for(int i = 0; n - 1 > i; i++) {
			int count = 0; // Initialize count for current string

			// Check if the current string is equal to the next string
			if(list.get(i).equals(list.get(i + 1))) {
				count++; // Increment count for the first duplicate
				i++; // Move to the next string

				// Continue counting while the next strings are equal
				while(true) {
					if(i == n - 1) // Break if at the end of the list
						break;
					if(!list.get(i).equals(list.get(i + 1))) // Break if strings are not equal
						break;
					count++; // Increment count for each duplicate
					i++; // Move to the next string
				}
			}
			// If the count matches the maximum, add the string to the answer list
			if(count == max)
				list_answer.add(list.get(i));
		}

		// Print each string that has the maximum number of duplicates
		for(int i = 0; list_answer.size() > i; i++) {
			System.out.println(list_answer.get(i));
		}
	}
}

