		// Apply conditional logic based on the value of 'a'
		if (a <= 5) 
			b = 0; // If 'a' is 5 or less, set 'b' to 0
		else if (a <= 12) 
			b /= 2; // If 'a' is between 6 and 12, halve the value of 'b'

		// Print the final value of 'b'
		System.out.println(b);
	}

	// Placeholder method for future implementation
	public static void solver() {

	}

	// Custom input reader class
	static class FS {
		private final InputStream in = System.in; // Input stream for reading data
		private final byte[] buffer = new byte[1024]; // Buffer to store input data
		private int ptr = 0; // Pointer to track current position in buffer
		private int buflen = 0; // Length of valid data in buffer

		// Check if there is another byte to read
		private boolean hasNextByte() {
			if (ptr < buflen) {
				return true; // There is more data in the buffer
			} else {
				ptr = 0; // Reset pointer
				try {
					// Read more data into the buffer
					buflen = in.read(buffer);
				} catch (IOException e) {
					e.printStackTrace(); // Print stack trace if an error occurs
				}
				if (buflen <= 0) {
					return false; // No more data to read
				}
			}
			return true; // Data is available
		}

		// Read the next byte from the buffer
		private int readByte() { 
			return hasNextByte() ? buffer[ptr++] : -1;
		}

		// Check if a character is printable
		private boolean isPrintableChar(int c) {
			return 33 <= c && c <= 126;
		}

		// Skip non-printable characters
		private void skipUnprintable() {
			while(hasNextByte() && !isPrintableChar(buffer[ptr])) 
				ptr++;
		}

		// Check if there is another token to read
		public boolean hasNext() { 
			skipUnprintable(); 
			return hasNextByte();
		}

		// Read the next token as a String
		public String next() {
			if (!hasNext()) 
				throw new NoSuchElementException();
			StringBuilder sb = new StringBuilder();
			int b = readByte();
			while(isPrintableChar(b)) {
				sb.appendCodePoint(b);
				b = readByte();
			}
			return sb.toString();
		}

		// Read the next token as an integer
		public int nextInt() {
			return (int)nextLong();
		}

		// Read the next token as a long
		public long nextLong() {
			if (!hasNext()) 
				throw new NoSuchElementException();
			long n = 0;
			boolean minus = false;
			int b = readByte();
			if (b == '-') {
				minus = true; // Handle negative numbers
				b = readByte();
			}
			if (b < '0' || '9' < b) {
				throw new NumberFormatException(); // Invalid number format
			}
			while(true) {
				if ('0' <= b && b <= '9') {
					n *= 10;
					n += b - '0'; // Convert character to digit and add to number
				} else if(b == -1 || !isPrintableChar(b)) {
					return minus ? -n : n; // Return the number, negated if necessary
				} else {
					throw new NumberFormatException(); // Invalid character in number
				}
				b = readByte();
			}
		}
	}
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.*;

public class Main {

	public static void main(String[] args) {
		// Create an InputReader object to read input from the standard input stream
		InputReader sc = new InputReader(System.in);
		// Create a PrintWriter object to write output to the standard output stream
		PrintWriter pw = new PrintWriter(System.out);

		// Read a string from input and convert it to a character array
		char[] num = sc.readString().toCharArray();
		int sum = 0; // Initialize sum to store the sum of digits

		// Iterate over each character in the character array
		for(char n : num){
			// Convert character to integer and add to sum
			sum += (int)(n -'0');
		}

		// Check if the sum of digits is divisible by 9
		String ans = (sum % 9 == 0) ? "Yes" : "No";
		// Print the result
		pw.println(ans);

		// Close the PrintWriter
		pw.close();
	}

	// Custom InputReader class to handle input operations
	static class InputReader {
		private InputStream stream; // Input stream to read data
		private byte[] buf = new byte[5]; // Buffer to store bytes read from the stream
		private int curChar; // Current character index in the buffer
		private int numChars; // Number of characters read into the buffer
		private SpaceCharFilter filter; // Optional filter for space characters

		// Constructor to initialize the InputReader with an input stream
		public InputReader(InputStream stream) {
			this.stream = stream;
		}

		// Method to read the next byte from the input stream
		public int read() {
			if (numChars == -1)
				throw new InputMismatchException(); // Throw exception if end of stream is reached
			if (curChar >= numChars) {
				curChar = 0;
				try {
					// Read bytes into the buffer
					numChars = stream.read(buf);
				} catch (IOException e) {
					throw new InputMismatchException(); // Throw exception on IO error
				}

				if (numChars <= 0)
					return -1; // Return -1 if no more characters are available
			}

			return buf[curChar++]; // Return the next character from the buffer
		}

		// Method to read the next line from the input stream
		public String nextLine() {
			BufferedReader br = new BufferedReader(new InputStreamReader(stream));
			String stock = "";
			try {
				stock = br.readLine(); // Read a line of text
			} catch (IOException e) {
				e.printStackTrace(); // Print stack trace on IO error
			}
			return stock; // Return the line read
		}

		// Method to read the next integer from the input stream
		public int nextInt() {
			int c = read();
			while (isSpaceChar(c))
				c = read(); // Skip space characters

			int sgn = 1; // Sign of the number

			if (c == '-') {
				sgn = -1; // Set sign to negative if '-' is encountered
				c = read();
			}

			int res = 0; // Resulting integer
			do {
				if (c < '0' || c > '9')
					throw new InputMismatchException(); // Throw exception if non-digit is encountered
				res *= 10;
				res += c - '0'; // Convert character to integer
				c = read();
			} while (!isSpaceChar(c)); // Continue until a space character is encountered

			return res * sgn; // Return the integer with the correct sign
		}

		// Method to read the next long integer from the input stream
		public long nextLong() {
			int c = read();
			while (isSpaceChar(c))
				c = read(); // Skip space characters
			int sgn = 1; // Sign of the number
			if (c == '-') {
				sgn = -1; // Set sign to negative if '-' is encountered
				c = read();
			}
			long res = 0; // Resulting long integer

			do {
				if (c < '0' || c > '9')
					throw new InputMismatchException(); // Throw exception if non-digit is encountered
				res *= 10;
				res += c - '0'; // Convert character to integer
				c = read();
			} while (!isSpaceChar(c)); // Continue until a space character is encountered
			return res * sgn; // Return the long integer with the correct sign
		}

		// Method to read the next double from the input stream
		public double nextDouble() {
			int c = read();
			while (isSpaceChar(c))
				c = read(); // Skip space characters
			int sgn = 1; // Sign of the number
			if (c == '-') {
				sgn = -1; // Set sign to negative if '-' is encountered
				c = read();
			}
			double res = 0; // Resulting double
			while (!isSpaceChar(c) && c != '.') {
				if (c == 'e' || c == 'E')
					return res * Math.pow(10, nextInt()); // Handle scientific notation
				if (c < '0' || c > '9')
					throw new InputMismatchException(); // Throw exception if non-digit is encountered
				res *= 10;
				res += c - '0'; // Convert character to integer
				c = read();
			}
			if (c == '.') {
				c = read();
				double m = 1;
				while (!isSpaceChar(c)) {
					if (c == 'e' || c == 'E')
						return res * Math.pow(10, nextInt()); // Handle scientific notation
					if (c < '0' || c > '9')
						throw new InputMismatchException(); // Throw exception if non-digit is encountered
					m /= 10;
					res += (c - '0') * m; // Add fractional part
					c = read();
				}
			}
			return res * sgn; // Return the double with the correct sign
		}

		// Method to read the next string from the input stream
		public String readString() {
			int c = read();
			while (isSpaceChar(c))
				c = read(); // Skip space characters
			StringBuilder res = new StringBuilder();
			do {
				res.appendCodePoint(c); // Append character to the result
				c = read();
			} while (!isSpaceChar(c)); // Continue until a space character is encountered

			return res.toString(); // Return the string read
		}

		// Method to check if a character is a space character
		public boolean isSpaceChar(int c) {
			if (filter != null)
				return filter.isSpaceChar(c); // Use custom filter if available
			return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
		}

		// Method to read the next token as a string
		public String next() {
			return readString(); // Delegate to readString method
		}

		// Interface for custom space character filter
		public interface SpaceCharFilter {
			public boolean isSpaceChar(int ch);
		}
	}

}

import java.io.*;
