class hayami implements Closeable {
    // Input stream for reading data
    private final InputStream in = System.in;

    // Buffer for storing input data
    private final byte[] hayami = new byte[1024];

    // Pointers for managing buffer reading
    private int Hayami = 0;
    private int saori = 0;

    // Method to check if there is more data to read
    private boolean HayamiSaori() {
        if (Hayami < saori) {
            return true; // There is still data in the buffer
        } else {
            Hayami = 0; // Reset buffer pointer
            try {
                // Read more data into the buffer
                saori = in.read(hayami);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no more data is available
            if (saori <= 0) {
                return false;
            }
        }
        return true;
    }

    // Method to get the next byte from the buffer
    private int SaoriHayami() {
        if (HayamiSaori()) {
            return hayami[Hayami++]; // Return the next byte and increment the pointer
        } else {
            return -1; // Indicate end of stream
        }
    }

    // Check if a byte is a printable ASCII character
    private static boolean hayami_saori(int hayami) {
        return 33 <= hayami && hayami <= 126;
    }

    // Skip non-printable characters and check if more data is available
    public boolean hayamisaori() {
        while (HayamiSaori() && !hayami_saori(hayami[Hayami])) Hayami++;
        return HayamiSaori();
    }

    // Read the next word from the input
    public String nextHayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        StringBuilder hayamin = new StringBuilder();
        int saori = SaoriHayami();
        while (hayami_saori(saori)) {
            hayamin.appendCodePoint(saori); // Append character to the string
            saori = SaoriHayami(); // Read next character
        }
        return hayamin.toString();
    }

    // Read the next long integer from the input
    public long saorihayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        long hayami = 0;
        boolean misao = false;
        int saori = SaoriHayami();

        // Check for negative sign
        if (saori == '-') {
            misao = true;
            saori = SaoriHayami();
        }

        // Ensure the first character is a digit
        if (saori < '0' || '9' < saori) {
            throw new NumberFormatException();
        }

        // Parse the number
        while (true) {
            if ('0' <= saori && saori <= '9') {
                hayami *= 10;
                hayami += saori - '0'; // Convert character to digit and add to number
            } else if (saori == -1 || !hayami_saori(saori)) {
                return misao ? -hayami : hayami; // Return the parsed number
            } else {
                throw new NumberFormatException();
            }
            saori = SaoriHayami(); // Read next character
        }
    }

    // Read the next integer from the input
    public int saori_hayami() {
        long hayami = saorihayami();
        // Check if the long value fits into an integer
        if (hayami < Integer.MIN_VALUE || hayami > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) hayami;
    }

