public class Main {

    public static void main(String[] args) {
        // Create an instance of FastScanner to read input
        FastScanner fs = new FastScanner();

        // Read three integers from input
        int a = fs.nextInt(); // The interval at which 'b' is added to 'ans'
        int b = fs.nextInt(); // The value to be added to 'ans' at each interval
        int t = fs.nextInt(); // The time limit up to which the loop runs

        int ans = 0; // Initialize the answer to 0

        // Loop from 'a' to 't' with increments of 'a'
        // The loop condition uses 't + 0.5f' to ensure it includes the last interval if 't' is exactly a multiple of 'a'
        for (float i = a; i < t + 0.5f; i += a) {
            ans += b; // Add 'b' to 'ans' at each interval
        }

        // Output the final result
        System.out.println(ans);
    }

    // FastScanner class for efficient input reading
    static class FastScanner {
        private final InputStream in = System.in; // Input stream for reading data
        private final byte[] buffer = new byte[1024]; // Buffer to store input data
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true; // There is more data in the buffer
            } else {
                ptr = 0; // Reset pointer
                try {
                    buflen = in.read(buffer); // Read more data into the buffer
                } catch (IOException e) {
                    e.printStackTrace(); // Print stack trace if an error occurs
                }
                if (buflen <= 0) {
                    return false; // No more data to read
                }
            }
            return true; // Data is available
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) {
                return buffer[ptr++]; // Return the next byte and increment the pointer
            } else {
                return -1; // No more bytes to read
            }
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126; // ASCII range for printable characters
        }

        // Check if there is another token to read
        public boolean hasNext() {
            // Skip non-printable characters
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
                ptr++;
            }
            return hasNextByte(); // Return true if there is more data
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) {
                throw new NoSuchElementException(); // No more tokens available
            }
            StringBuilder sb = new StringBuilder(); // Use StringBuilder for efficient string construction
            int b = readByte(); // Read the first byte
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b); // Append the character to the StringBuilder
                b = readByte(); // Read the next byte
            }
            return sb.toString(); // Return the constructed string
        }

        // Read the next token as a long integer
        public long nextLong() {
            if (!hasNext()) {
                throw new NoSuchElementException(); // No more tokens available
            }
            long n = 0; // Initialize the result
            boolean minus = false; // Flag for negative numbers
            int b = readByte(); // Read the first byte
            if (b == '-') {
                minus = true; // Number is negative
                b = readByte(); // Read the next byte
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException(); // Invalid number format
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10; // Shift digits left
                    n += b - '0'; // Add the new digit
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n; // Return the result, negated if necessary
                } else {
                    throw new NumberFormatException(); // Invalid number format
                }
                b = readByte(); // Read the next byte
            }
        }

        // Read the next token as an integer
        public int nextInt() {
            long nl = nextLong(); // Read the token as a long
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) {
                throw new NumberFormatException(); // Value out of integer range
            }
            return (int) nl; // Cast the long to an int
        }

        // Read the next token as a double
        public double nextDouble() {
            return Double.parseDouble(next()); // Parse the token as a double
        }
    }
}

