import java.util.Scanner;

public class Main{

	public static void main(String[] args) {

		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Initialize variables
		int n = 0; // Number of test scores
		String[] Test_String; // Array to hold the input test scores as strings
		int[] Test_Score; // Array to hold the test scores as integers
		String input_n = ""; // String to hold the input for number of test scores
		String input_test = ""; // String to hold the input test scores
		boolean judge_n = true; // Flag to check if the input for n is valid
		boolean judge_test = true; // Flag to check if the input test scores are valid
		double m = 0.0; // Mean of the test scores
		double V = 0.0; // Variance of the test scores
		int MAX = 1000; // Maximum number of test scores allowed
		double[] SD = new double[MAX]; // Array to store standard deviations for each set of test scores
		int data_count = 0; // Counter to keep track of the number of valid data sets

		// Outer loop to continuously read input until a termination condition is met
		out: while (true) {
			// Read the number of test scores
			input_n = sc.nextLine();
			n = Integer.parseInt(input_n); // Convert input to integer

			// If n is 0, break out of the loop (termination condition)
			if (n == 0) {
				break out;
			}

			// If n is negative or greater than 1000, set judge_n to false and break out
			if (n < 0 || n > 1000) {
				judge_n = false;
				break out;
			}

			// Read the test scores
			input_test = sc.nextLine();
			Test_String = input_test.split(" "); // Split the input string into an array of strings

			// If the number of test scores does not match n, set judge_test to false and break out
			if (Test_String.length != n) {
				judge_test = false;
				break out;
			}

			// Initialize mean to 0
			m = 0.0;
			Test_Score = new int[n]; // Initialize the array to hold test scores

			// Calculate the sum of test scores and store them in Test_Score array
			for (int i = 0; i < n; i++) {
				Test_Score[i] = Integer.parseInt(Test_String[i]); // Convert each score to integer
				m += Test_Score[i]; // Add score to the sum
			}

			// Calculate the mean of the test scores
			m = m / n;

			// Initialize variance to 0
			V = 0.0;

			// Calculate the variance of the test scores
			for (int j = 0; j < n; j++) {
				V += ((double) (Test_Score[j] - m)) * ((double) (Test_Score[j] - m)); // Sum of squared differences from the mean
			}

			// Calculate the variance
			V = V / n;

			// Calculate the standard deviation and store it in the SD array
			SD[data_count] = Math.sqrt(V);
			data_count++; // Increment the data count
		}

		// If both n and test scores are valid, print the standard deviations
		if (judge_n == true && judge_test == true) {
			for (int k = 0; k < data_count; k++) {
				System.out.printf("%.5f", SD[k]); // Print each standard deviation with 5 decimal places
                System.out.println(); // Print a new line after each standard deviation
			}
		}
	}
}

