class FastScanner {
    // InputStream to read from standard input
    private final InputStream in = System.in;

    // Buffer to store bytes read from the input stream
    private final byte[] buffer = new byte[1024];

    // Pointer to track the current position in the buffer
    private int ptr = 0;

    // Number of bytes currently in the buffer
    private int buflen = 0;

    // Check if there is another byte to read from the buffer
    private boolean hasNextByte() {
        if (ptr < buflen) {
            // If the pointer is less than the buffer length, there is a next byte
            return true;
        } else {
            // Reset the pointer and try to read more bytes into the buffer
            ptr = 0;
            try {
                buflen = in.read(buffer);
            } catch (Exception e) {
                e.printStackTrace();
            }
            // If no bytes were read, return false
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte()) {
            return buffer[ptr++];
        } else {
            return -1; // Return -1 if no more bytes are available
        }
    }

    // Check if a character is printable (ASCII range 33 to 126)
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Check if there is another token in the input
    public boolean hasNext() {
        // Skip non-printable characters
        while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
            ptr++;
        }
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder while they are printable
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long integer
    public long nextLong() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        long n = 0;
        boolean minus = false;
        int b = readByte();

        // Check for a negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }

        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }

        // Read digits and construct the long integer
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an integer
    public int nextInt() {
        long nl = nextLong();
        // Check if the long value is within the range of an integer
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) {
            throw new NumberFormatException();
        }
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next());
    }
}

import java.util.*;

public class Main {
    // Static variables to hold the input string, its character array, and a flag to indicate success
    static String str;
    static char[] c;
    static boolean ok;

    public static void main(String[] args) throws Exception {

        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read the next token (word) from the input and store it in the static variable 'str'
        str = sc.next();

        // Convert the input string into a character array for easier manipulation
        c = str.toCharArray();

        // Start the depth-first search from the first character
        dfs(0);

        // If the 'ok' flag is set to true, print "YES", otherwise print "NO"
        if (ok) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }

    // Recursive method to perform depth-first search on the character array
    public static void dfs(int i) {

        // Base case: If the index reaches the end of the array, set 'ok' to true and return
        if (i == c.length) {
            ok = true;
            return;
        }

        // Flags to check if certain patterns are found starting from the current index
        boolean ok5 = false; // For patterns of length 5
        boolean ok7 = false; // For patterns of length 7
        boolean ok6 = false; // For patterns of length 6

        // Check for the pattern "dream" or "erase" of length 5
        if (i+4 < c.length && c[i] == 'd' && c[i+1] == 'r' && c[i+2] == 'e' && c[i+3] == 'a' && c[i+4] == 'm') ok5 = true;
        if (i+4 < c.length && c[i] == 'e' && c[i+1] == 'r' && c[i+2] == 'a' && c[i+3] == 's' && c[i+4] == 'e') ok5 = true;

        // Check for the pattern "dreamer" of length 7
        if (i+6 < c.length && c[i] == 'd' && c[i+1] == 'r' && c[i+2] == 'e' && c[i+3] == 'a' && c[i+4] == 'm' && c[i+5] == 'e' && c[i+6] == 'r') ok7 = true;

        // Check for the pattern "eraser" of length 6
        if (i+5 < c.length && c[i] == 'e' && c[i+1] == 'r' && c[i+2] == 'a' && c[i+3] == 's' && c[i+4] == 'e' && c[i+5] == 'r') ok6 = true;

        // If any of the patterns are found, recursively call dfs with the next index after the pattern
        if (ok5) {
            dfs(i + 5);
        }
        if (ok7) {
            dfs(i + 7);
        }
        if (ok6) {
            dfs(i + 6);
        }
    }
}

