                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                // Parse the number
                long ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
