import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.NoSuchElementException;

public class Main {

    // Define a constant for the modulus value used in calculations
    static final int mod = 1000000007;
    // Arrays to store factorials, inverses, and factorial inverses
    static long[] fac;
    static long[] inv;
    static long[] finv;

    public static void main(String[] args) {

        // Initialize a FastScanner instance for fast input reading
        FastScanner sc = new FastScanner();
        // Initialize a PrintWriter for fast output
        PrintWriter out = new PrintWriter(System.out);

        // Read integers N, A, and B from input
        int N = sc.nextInt();
        int A = sc.nextInt();
        int B = sc.nextInt();

        // Compare N*A with B and print the smaller value
        if (N * A < B) {
            out.println(N * A);
        } else {
            out.print(B);
        }

        // Flush the output buffer to ensure all data is printed
        out.flush();
    }

    // Method to initialize factorials and inverses up to N
    static void calcNumOfCombinationInit(int N) {

        // Initialize arrays to store factorials, inverses, and factorial inverses
        fac = new long[N];
        inv = new long[N];
        finv = new long[N];

        // Base cases for factorials and inverses
        fac[0] = 1;
        fac[1] = 1;
        finv[0] = 1;
        finv[1] = 1;
        inv[1] = 1;

        // Calculate factorials, inverses, and factorial inverses using modular arithmetic
        for (int i = 2; i < N; i++) {
            fac[i] = fac[i - 1] * i % mod;
            inv[i] = mod - inv[mod % i] * (mod / i) % mod;
            finv[i] = finv[i - 1] * inv[i] % mod;
        }

    }

    // Method to calculate the number of combinations C(n, r)
    static long calcNumOfCombination(int n, int r) {
        // Return 0 if n < r or if n or r are negative
        if (n < r || n < 0 || r < 0) {
            return 0;
        }
        // Calculate C(n, r) using precomputed factorials and inverses
        return fac[n] * (finv[r] * finv[n - r] % mod) % mod;
    }

}

class FastScanner {
    // InputStream for reading input
    private final InputStream in = System.in;
    // Buffer for storing input bytes
    private final byte[] buffer = new byte[1024];
    // Pointer to the current position in the buffer
    private int ptr = 0;
    // Length of valid data in the buffer
    private int buflen = 0;

    // Check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                // Read more data into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte())
            return buffer[ptr++];
        else
            return -1;
    }

    // Check if a character is printable
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Check if there is another token to read
    public boolean hasNext() {
        while (hasNextByte() && !isPrintableChar(buffer[ptr]))
            ptr++;
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext())
            throw new NoSuchElementException();
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long
    public long nextLong() {
        if (!hasNext())
            throw new NoSuchElementException();
        long n = 0;
        boolean minus = false;
        int b = readByte();
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an int
    public int nextInt() {
        long nl = nextLong();
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
            throw new NumberFormatException();
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next());
    }

    // Read a 2D array of characters with dimensions H x W
    public char[][] nextCharsHW(int H, int W) {
        char[][] chars = new char[H][W];
        for (int i = 0; i < H; i++) {
            String str = next();
            for (int j = 0; j < W; j++) {
                chars[i][j] = str.charAt(j);
            }
        }
        return chars;
    }

    // Read a 2D array of integers with dimensions N x M
    public int[][] nextIntsNM(int N, int M) {
        int[][] ints = new int[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                ints[i][j] = nextInt();
            }
        }
        return ints;
    }
}

