class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read the number of points (N) from the input
        int N = sc.nextInt();

        // Initialize arrays to store time (t), x-coordinates (x), and y-coordinates (y) for each point
        int[] t = new int[N];
        int[] x = new int[N];
        int[] y = new int[N];

        // Loop to read the time and coordinates for each point
        for (int i = 0; i < N; i++) {
            t[i] = sc.nextInt(); // Read time for the i-th point
            x[i] = sc.nextInt(); // Read x-coordinate for the i-th point
            y[i] = sc.nextInt(); // Read y-coordinate for the i-th point
        }

        // Variables to store differences in x, y, and time
        int dx = 0;
        int dy = 0;
        int dt = 0;

        // Loop through each point to check if the travel is possible
        for (int i = 0; i < N; i++) {
            if (i == 0) {
                // For the first point, calculate the absolute differences from the origin (0,0)
                dx = Math.abs(x[i]);
                dy = Math.abs(y[i]);
                dt = t[i];

                // Check if the travel to the first point is possible
                // The sum of dx and dy must be less than or equal to dt
                // The parity (even or odd) of dx+dy and dt must match
                if (!(dx + dy <= dt && (((dx + dy) % 2 == 0 && (dt % 2) == 0) || ((dx + dy) % 2 != 0 && (dt % 2) != 0)))) {
                    System.out.println("No"); // Print "No" if travel is not possible
                    System.exit(0); // Exit the program
                }
            } else {
                // For subsequent points, calculate the differences from the previous point
                dx = Math.abs(x[i] - x[i - 1]);
                dy = Math.abs(y[i] - y[i - 1]);
                dt = t[i] - t[i - 1];

                // Check if the travel to the current point is possible
                // The sum of dx and dy must be less than or equal to dt
                // The parity (even or odd) of dx+dy and dt must match
                if (!(dx + dy <= dt && (((dx + dy) % 2 == 0 && (dt % 2) == 0) || ((dx + dy) % 2 != 0 && (dt % 2) != 0)))) {
                    System.out.println("No"); // Print "No" if travel is not possible
                    System.exit(0); // Exit the program
                }
            }
        }

        // If all points are reachable, print "Yes"
        System.out.println("Yes");
    }
}

