    /**
     * This method compares two strings character by character and counts how many characters match at the same position.
     * @param s The first string to compare.
     * @param t The second string to compare.
     * @return The number of matching characters at the same positions in both strings.
     */
    static int matched(String s, String t)
    {
        int count = 0; // Initialize the count of matched characters
        char a[] = s.toCharArray(); // Convert the first string to a character array
        char b[] = t.toCharArray(); // Convert the second string to a character array
        int n = b.length; // Get the length of the second string
        for(int i = 0; i < n; i++)
        {
            // Compare characters at the same position in both arrays
            if(a[i] == b[i])
                count++; // Increment count if characters match
        }
        return count; // Return the total count of matched characters
    }

    public static void main(String [] args) throws Exception
    {
        Foster sc = new Foster(); // Create an instance of the Foster class for input handling
        PrintWriter p = new PrintWriter(out); // Create a PrintWriter for output
        String s = sc.next(); // Read the first string from input
        String t = sc.next(); // Read the second string from input
        int n = s.length(); // Get the length of the first string
        int n2 = t.length(); // Get the length of the second string
        int maxMatch = matched(s, t); // Calculate the initial number of matches
        for(int i = 0; i < n-n2; i++)
        {
            t = "?" + t; // Prepend a '?' to the second string
            maxMatch = Math.max(maxMatch, matched(s, t)); // Update maxMatch if a better match is found
        }
        p.println(n2-maxMatch); // Output the number of unmatched characters
        p.close(); // Close the PrintWriter
    }

    /**
