        }

        /**
         * Converts an integer to its binary representation in an array of bits.
         * @param n The integer to convert.
         * @return An array representing the bits of the integer.
         */
        int[] getBits(int n)                    
        {
            int a[] = new int[31]; // Initialize an array to hold 31 bits
            for(int i = 0; i < 31; i++)
            {
                if(((1<<i) & n) != 0)
                    a[i] = 1; // Set the bit if it is present in the integer
            }
            return a; // Return the array of bits
        }

        /**
         * Calculates the power of a number with optional modulus.
         * @param a The base, exponent, and optional modulus.
         * @return The result of the power operation.
         */
        static long pow(long... a)
        {
            long mod = Long.MAX_VALUE; // Default modulus is the maximum long value
            if(a.length == 3)   mod = a[2]; // Use the provided modulus if available
            long res = 1; // Initialize the result
            while(a[1] > 0)
            {
                if((a[1] & 1) == 1)
                    res = (res * a[0]) % mod; // Multiply result by base if exponent is odd
                a[1] /= 2; // Divide the exponent by 2
                a[0] = (a[0] * a[0]) % mod; // Square the base
            }
            return res; // Return the final result
        }

