import java.io.*;
import java.util.*;
import java.lang.*;

public class Main {
    // FastReader class to efficiently read input from the input stream
    public static class FastReader {
        private InputStream stream; // Input stream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter to identify space characters

        // Constructor to initialize the FastReader with an input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            if (numChars == -1)
                throw new InputMismatchException(); // Throw exception if end of stream is reached
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Handle IO exceptions
                }
                if (numChars <= 0)
                    return -1; // Return -1 if no more data is available
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to read the next line of input as a String
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the input
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace in case of an exception
            }
            return str; // Return the read line
        }

        // Method to read the next integer from the input
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception if non-digit is encountered
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is encountered
            return res * sgn; // Return the parsed integer
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception if non-digit is encountered
                res *= 10;
                res += c - '0'; // Convert character to long integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is encountered
            return res * sgn; // Return the parsed long integer
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception if non-digit is encountered
                res *= 10;
                res += c - '0'; // Convert character to double
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Throw exception if non-digit is encountered
                    m /= 10;
                    res += (c - '0') * m; // Add fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the parsed double
        }

        // Method to read the next character from the input
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            return (char) c; // Return the next character
        }

        // Method to read the next word (sequence of non-space characters) from the input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is encountered
            return res.toString(); // Return the parsed word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c); // Use custom filter if available
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Method to calculate the greatest common divisor (GCD) of two integers
    static int gcd(int a, int b) {
        if (a == 0)
            return b; // Base case: if a is 0, return b
        return gcd(b % a, a); // Recursive call to find GCD
    }

    // Method to calculate the least common multiple (LCM) of two integers
    static int lcm(int a, int b) {
        return (a * b) / gcd(a, b); // LCM is calculated using GCD
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading data
        OutputStream outputStream = System.out; // Output stream for writing data
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        int n, k, q, i, j; // Variables for input
        long sum = 0; // Variable to store the sum of array elements

        n = in.nextInt(); // Read the number of elements
        k = in.nextInt(); // Read the threshold value
        q = in.nextInt(); // Read the number of queries

        int arr[] = new int[n]; // Array to store the count of queries for each element

        // Process each query
        for (i = 0; i < q; i++) {
            int x = in.nextInt() - 1; // Read the index and adjust for 0-based indexing
            arr[x]++; // Increment the count for the specified index
        }

        // Calculate the total sum of counts
        for (i = 0; i < n; i++) {
            sum += arr[i];
        }

        // Determine if each element can be a winner
        for (i = 0; i < n; i++) {
            if ((long) k - sum + (long) arr[i] > 0) {
                w.println("Yes"); // Print "Yes" if the element can be a winner
            } else {
                w.println("No"); // Print "No" if the element cannot be a winner
            }
        }

        w.close(); // Close the PrintWriter
    }
}

import java.io.OutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.io.Closeable;
import java.io.IOException;
import java.util.NoSuchElementException;
import java.io.InputStream;

public class Main {
    public static void main(String[] args) {
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Create a FastScanner object for efficient input reading
        FastScanner in = new FastScanner(inputStream);

        // Create a PrintWriter object for efficient output writing
        PrintWriter out = new PrintWriter(outputStream);

        // Create an instance of the solver class
        BTimeLimitExceeded solver = new BTimeLimitExceeded();

        // Call the solve method to process the input and produce output
        solver.solve(1, in, out);

        // Close the PrintWriter to flush the output
        out.close();
    }

    static class BTimeLimitExceeded {
        // Method to solve the problem
        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            // Read the number of test cases
            int N = in.nextInt();

            // Read the time limit
            final int T = in.nextInt();

            // Initialize the answer with a large value
            int ans = 10001;

            // Iterate over each test case
            for (int i = 0; i < N; i++) {
                // Read the cost and time for each test case
                int c = in.nextInt();
                int t = in.nextInt();

                // Check if the time is within the limit
                if (t <= T) {
                    // Update the answer with the minimum cost
                    ans = Math.min(ans, c);
                }
            }

            // If no valid cost was found, print "TLE"
            if (ans > 1000) {
                out.println("TLE");
            } else {
                // Otherwise, print the minimum cost found
                out.println(ans);
            }
        }
    }

    static class FastScanner implements Closeable {
        private final InputStream in;
        private final byte[] buffer = new byte[1024];
        private int ptr = 0;
        private int buflen = 0;

        // Constructor to initialize the input stream
        public FastScanner(InputStream in) {
            this.in = in;
        }

        // Method to check if there is a next byte in the buffer
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    // Read more bytes into the buffer
                    buflen = in.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                // Return false if no more bytes are available
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Method to read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            else return -1;
        }

        // Method to check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Method to check if there is a next token
        public boolean hasNext() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
            return hasNextByte();
        }

        // Method to read the next long integer
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Method to read the next integer
        public int nextInt() {
            long nl = nextLong();
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Method to close the input stream
        public void close() {
            try {
                in.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}

