    }

    /* 
     * BPapersPlease class contains the logic to solve the problem.
     */
    static class BPapersPlease {
        public void solve(int testNumber, Scanner in, PrintWriter out) {
            String str = "APPROVED"; // Default result is "APPROVED"
            int n = in.nextInt(); // Read the number of integers
            ArrayList<Integer> array = new ArrayList<>(); // List to store integers
            while (in.hasNext()) {
                array.add(in.nextInt()); // Add each integer to the list
            }
            // Iterate over each integer in the list
            for (int i : array) {
                // Check if the integer is even
                if (i % 2 == 0) {
                    // If even, check if it is not divisible by 3 or 5
                    if (i % 3 != 0 && i % 5 != 0) {
                        str = "DENIED"; // Set result to "DENIED" if condition is met
                    }
                }
            }
            out.println(str); // Output the result
        }
    }

    /* 
     * Custom Scanner class to handle input operations.
     */
    static class Scanner {
        private final InputStream in; // Input stream
        private final byte[] buffer; // Buffer for reading input
        private int ptr; // Pointer to current position in buffer
        private int buflen; // Length of valid data in buffer

        public Scanner(InputStream in) {
            this.in = in;
            this.buffer = new byte[1024]; // Initialize buffer with size 1024
            this.ptr = 0; // Initialize pointer
            this.buflen = 0; // Initialize buffer length
        }

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) return true; // If pointer is within buffer length
            else {
                ptr = 0; // Reset pointer
                try {
                    buflen = in.read(buffer); // Read into buffer
                } catch (IOException e) {
                    e.printStackTrace(); // Print stack trace on exception
                }
                if (buflen <= 0) return false; // Return false if no data read
            }
            return true; // Return true if data is available
        }

        // Read the next byte from the buffer
        private byte readByte() {
            if (hasNextByte()) return buffer[ptr++]; // Return byte and increment pointer
            return -1; // Return -1 if no byte is available
        }

        // Check if a byte is a printable character
        private boolean isPrintableChar(byte c) {
            return '!' <= c && c <= '~'; // Printable ASCII range
        }

        // Skip non-printable characters in the buffer
        private void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
                ptr++; // Increment pointer to skip unprintable characters
            }
        }

        // Check if there is another token to read
        public boolean hasNext() {
            skipUnprintable(); // Skip unprintable characters
            return hasNextByte(); // Check if there is a next byte
        }

        // Read the next integer from the input
        public int nextInt() {
            if (!hasNext()) throw new NoSuchElementException(); // Throw exception if no next element
            int n = 0; // Initialize integer to store result
            boolean minus = false; // Flag for negative numbers
            byte b = readByte(); // Read the first byte
            if (b == '-') {
                minus = true; // Set minus flag if negative
                b = readByte(); // Read next byte
            }
            if (b < '0' || '9' < b) throw new NumberFormatException(); // Throw exception if not a digit
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10; // Multiply current number by 10
                    n += b - '0'; // Add the digit value
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n; // Return the number with correct sign
                } else {
                    throw new NumberFormatException(); // Throw exception if not a valid number
                }
                b = readByte(); // Read next byte
            }
        }
    }
}

