@SuppressWarnings("unused")
public class Main {
    // Fast input scanner
    FastScanner in;
    // Output writer
    PrintWriter out;
    // Modulo constant
    int MOD = (int)1e9+7;

    // Method to calculate the ceiling of a/b
    long ceil(long a, long b) {
        return (a + b - 1) / b;
    }

    // Method to calculate the greatest common divisor (GCD) using Euclidean algorithm
    long gcd(long a, long b) {
        return b == 0 ? a : gcd(b, a % b);
    }

    // Method to calculate the least common multiple (LCM)
    long lcm(long a, long b) {
        return a / gcd(a, b) * b;
    }

    // HashMap to store precomputed results for dynamic programming
    HashMap<Long, Long> map = new HashMap<>();

    // Main problem-solving method
    void solve() {
        // Read the input value H
        long H = in.nextLong();
        // Initialize the base case for dynamic programming
        map.put(1L, 1L);
        // Output the result of the recursive DFS method
        out.println(dfs(H));
    }

    // Recursive method to compute the result using dynamic programming
    long dfs(long h) {
        // Check if the result for h is already computed
        if (map.containsKey(h)) return map.get(h);
        // Compute the result recursively and store it in the map
        long res = dfs(h / 2) * 2 + 1;
        map.put(h, res);
        return res;
    }

    public static void main(String[] args) {
        // Create an instance of Main and call the method m
        new Main().m();
    }

    // Method to initialize input and output streams and solve the problem
    private void m() {
        in = new FastScanner(System.in);
        out = new PrintWriter(System.out);

        // Solve the problem
        solve();
        // Flush the output stream
        out.flush();
        // Close the input and output streams
        in.close();
        out.close();
    }

    // Custom fast input scanner class
    static class FastScanner {
        private Reader input;

        // Constructor with default input stream
        public FastScanner() {
            this(System.in);
        }

        // Constructor with specified input stream
        public FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to close the input stream
        public void close() {
            try {
                this.input.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // Method to read the next integer
        public int nextInt() {
            return (int) nextLong();
        }

        // Method to read the next long integer
        public long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                long ret = b - '0';
                // Read the number
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Method to read the next double
        public double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                double ret = b - '0';
                // Read the integer part
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }
                // Read the fractional part
                if (b != '.') return sign * ret;
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

        // Method to read the next character
        public char nextChar() {
            try {
                int b = input.read();
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                return (char) b;
            } catch (IOException e) {
                e.printStackTrace();
                return 0;
            }
        }

        // Method to read the next string
        public String nextStr() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                // Read the string
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }

        // Method to read the next line
        public String nextLine() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();
                // Read until the end of the line
                while (b != -1 && b != '\n') {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }

        // Method to read an array of integers
        public int[] nextIntArray(int n) {
            int[] res = new int[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextInt();
            }
            return res;
        }

        // Method to read an array of integers and decrement each by 1
        public int[] nextIntArrayDec(int n) {
            int[] res = new int[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextInt() - 1;
            }
            return res;
        }

        // Method to read an array of integers with 1-based indexing
        public int[] nextIntArray1Index(int n) {
            int[] res = new int[n + 1];
            for (int i = 0; i < n; i++) {
                res[i + 1] = nextInt();
            }
            return res;
        }

