import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner scan = new Scanner(System.in);

        // Initialize a 3x3 matrix to store input values
        int[][] c_ = new int[3][3];

        // Read values into the matrix from the user input
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                c_[i][j] = scan.nextInt();
            }
        }

        // Variables to store the maximum values of each column
        int one_max = Integer.MIN_VALUE;
        int two_max = Integer.MIN_VALUE;
        int three_max = Integer.MIN_VALUE;

        // Determine the maximum value in each column
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (i == 0) {
                    // Update one_max if a larger value is found in the first column
                    if (c_[j][i] > one_max)
                        one_max = c_[j][i];
                } else if (i == 1) {
                    // Update two_max if a larger value is found in the second column
                    if (c_[j][i] > two_max)
                        two_max = c_[j][i];
                } else {
                    // Update three_max if a larger value is found in the third column
                    if (c_[j][i] > three_max)
                        three_max = c_[j][i];
                }
            }
        }

        // Initialize matrices a_ and b_ to store intermediate calculations
        int[][] a_ = new int[3][3];
        int[][] b_ = new int[3][3];

        // Flags to check if each row in matrix a_ has equal elements
        boolean[] flag_ = {false, false, false};

        // Iterate over all possible values for b_ matrix elements
        for (int one = 0; one <= one_max; one++) {
            for (int two = 0; two <= two_max; two++) {
                for (int three = 0; three <= three_max; three++) {
                    // Reset flags for each combination of b_ values
                    flag_[0] = false;
                    flag_[1] = false;
                    flag_[2] = false;

                    // Calculate matrix a_ based on current b_ values
                    for (int i = 0; i < 3; i++) {
                        for (int j = 0; j < 3; j++) {
                            // Assign values to b_ based on the current iteration
                            switch (j) {
                                case 0:
                                    b_[i][j] = one;
                                    break;
                                case 1:
                                    b_[i][j] = two;
                                    break;
                                case 2:
                                    b_[i][j] = three;
                                    break;
                            }
                            // Calculate a_ as the difference between c_ and b_
                            a_[i][j] = c_[i][j] - b_[i][j];
                        }
                        // Check if all elements in the current row of a_ are equal
                        if (a_[i][0] == a_[i][1] && a_[i][0] == a_[i][2]) {
                            flag_[i] = true;
                        }
                    }
                }
            }
        }

        // Check if all rows in a_ have equal elements and print the result
        if (flag_[0] == true && flag_[1] == true && flag_[2] == true) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }
}

import java.io.*;
import java.util.InputMismatchException;

public class Main {
    public static void main(String[] xps){
        // Create an InputReader to read input from the standard input stream
        InputReader in = new InputReader(System.in);
        // Create an OutputWriter to write output to the standard output stream
        OutputWriter out = new OutputWriter(System.out);
        // StringBuilder is initialized but not used in this code
        StringBuilder stringBuilder = new StringBuilder();

        // Read two long integers from input
        long n = in.Long();
        long k = in.Long();

        // Check if n is less than or equal to the absolute difference between n and k
        if (n <= Math.abs(n - k))
            out.println(n); // If true, print n
        else {
            // Check if n is perfectly divisible by k
            if (n % k == 0)
                out.println(0); // If true, print 0
            else {
                // Calculate the remainder when n is divided by k
                long happy = n % k;
                // Print the minimum of the remainder and the absolute difference between the remainder and k
                out.println(Math.min(happy, Math.abs(happy - k)));
            }
        }
    }

    // Custom InputReader class to handle input operations
    private static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Reads the next byte of data from the input stream
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Fill the buffer with data from the stream
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    return -1; // End of stream
                }
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Reads an integer from the input
        public int Int() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Reads a string from the input
        public String String() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));
            return res.toString();
        }

        // Reads a double from the input
        public double Double() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    return res * Math.pow(10, Int());
                }
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, Int());
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Reads a long integer from the input
        public long Long() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Checks if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c);
            }
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Reads the next token as a string
        public String next() {
            return String();
        }

        // Interface for filtering space characters
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Custom OutputWriter class to handle output operations
    private static class OutputWriter {
        private final PrintWriter writer;

        public OutputWriter(OutputStream outputStream) {
            writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
        }

        public OutputWriter(Writer writer) {
            this.writer = new PrintWriter(writer);
        }

        // Prints objects to the output stream
        public void print(Object... objects) {
            for (int i = 0; i < objects.length; i++) {
                if (i != 0) {
                    writer.print(' ');
                }
                writer.print(objects[i]);
            }
            writer.flush();
        }

        // Prints objects to the output stream followed by a newline
        public void println(Object... objects) {
            print(objects);
            writer.println();
            writer.flush();
        }

        // Closes the writer
        public void close() {
            writer.close();
        }

        // Flushes the writer
        public void flush() {
            writer.flush();
        }
    }
}

