import java.util.Arrays;
import java.util.Scanner;

public class Main{

	// Method to calculate the Greatest Common Divisor (GCD) using the Euclidean algorithm
	public static long gcm(long a, long b) {
		long result = a;
		long k = 0;
		long n = b;
		// Continue the loop until the remainder is zero
		do {
			k = result % n; // Calculate remainder
			result = n; // Update result to the divisor
			n = k; // Update divisor to the remainder
		} while(k != 0);
		return result; // Return the GCD
	}

	// Method to calculate the Least Common Multiple (LCM) using GCD
	public static long lcm(long a, long b) {
		long g;
		g = gcm(a, b); // Calculate GCD
		return a/g*b; // Return LCM using the formula: LCM(a, b) = (a * b) / GCD(a, b)
	}

	// Another method to calculate GCD using a while loop
	static long gcd (long a, long b) {
		long temp;
		// Continue until remainder is zero
		while((temp = a%b)!=0) {
			a = b; // Update a to b
			b = temp; // Update b to remainder
		}
		return b; // Return the GCD
	}

	// Method to check if a number is prime
	static boolean isPrime (int n) {
		if (n==2) return true; // 2 is a prime number
		if (n<2 || n%2==0) return false; // Numbers less than 2 and even numbers are not prime
		double d = Math.sqrt(n); // Calculate square root of n
		// Check divisibility from 3 to square root of n
		for (int i=3; i<=d; i+=2) if(n%i==0){return false;}
		return true; // Return true if no divisors found
	}

	// Method to check if a number in a given base is a multiple of m
	static boolean isMultiple (String s, int base, int m) {
		int temp = 0;
		// Convert string to number in given base and check divisibility by m
		for (int i=0; i<s.length(); i++) {
			temp = (temp*base+Character.getNumericValue(s.charAt(i)))%m;
		}
		if (temp==0) {return true;} // Return true if divisible
		return false; // Return false otherwise
	}

	// Recursive method to calculate factorial of a number
	static long factorial (int i) {
		if (i==1) {return 1;} // Base case: factorial of 1 is 1
		else {return i*factorial(i-1);} // Recursive call
	}

	// Method to convert a number from base m to base n
	static String toNbase (String sm, int m, int n) {
		return Long.toString(Long.parseLong(sm,m),n); // Convert and return the number in base n
	}

	// Method to calculate GCD of an array of numbers
	public static final long gcd_n(long[] param) {
	    final int len = param.length;
	    long g = gcd(param[0], param[1]); // Calculate GCD of first two numbers
	    // Iterate through the array and calculate GCD with the next number
	    for (int i = 1; i < len - 1; i++) {
	        g = gcd(g, param[i + 1]);       
	    }
	    return g; // Return the GCD of the array
	}

	// Method to calculate LCM of an array of numbers
	public static long lcm_n(long[] numbers) {
		long l;
		l = numbers[0]; // Initialize LCM with the first number
		// Iterate through the array and calculate LCM with the next number
		for (int i = 1; i < numbers.length; i++) {
			l = lcm(l, numbers[i]);
		}
		return l; // Return the LCM of the array
	}

	// Main method to execute the program
	public static void main(String[] args) {
		Scanner sc=new Scanner(System.in); // Create a Scanner object for input
		int A=sc.nextInt(),B=sc.nextInt(); // Read two integers from input
		// Compare the sums, differences, and products of A and B and print the largest
		if(A+B>=A-B&&A-B>=A*B) {
			System.out.println(A+B);
		}else if(A+B>=A*B&&A*B>=A-B) {
			System.out.println(A+B);
		}else if(A-B>=A+B&&A+B>=A*B) {
			System.out.println(A-B);
		}else if(A-B>=A*B&&A*B>=A+B) {
			System.out.println(A-B);
		}else if(A*B>=A+B&&A+B>=A-B) {
			System.out.println(A*B);
		}else if(A*B>=A-B&&A-B>=A+B) {
			System.out.println(A*B);
		}
	}
}

