import java.io.IOException;
import java.io.InputStream;
import java.util.*;

public class Main {

    public static void main(String[] args) {
        // Create an instance of FastScanner to read input
        FastScanner fs = new FastScanner();

        // Read a long integer N from input
        long N = fs.nextLong();

        // Initialize the answer with the number of digits in N
        int ans = Long.toString(N).length();

        // Iterate over all possible divisors i of N
        for (long i = 1; i * i <= N; ++i) {
            // If i is not a divisor of N, continue to the next iteration
            if (N % i != 0) continue;

            // Calculate the corresponding divisor num
            long num = N / i;

            // Calculate the maximum number of digits between i and num
            int tmp = Math.max(Long.toString(i).length(), Long.toString(num).length());

            // Update the answer if a smaller maximum number of digits is found
            if (ans > tmp) ans = tmp;
        }

        // Print the minimum number of digits found
        System.out.println(ans);
    }
}

class FastScanner {
    // InputStream to read from standard input
    private final InputStream in = System.in;
    // Buffer to store bytes read from input
    private final byte[] buffer = new byte[1024];
    // Pointer to the current position in the buffer
    private int ptr = 0;
    // Number of bytes currently in the buffer
    private int buflen = 0;

    // Check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                // Read bytes into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no bytes were read
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() { 
        if (hasNextByte()) return buffer[ptr++]; 
        else return -1;
    }

    // Check if a character is printable
    private static boolean isPrintableChar(int c) { 
        return 33 <= c && c <= 126;
    }

    // Check if there is another token to read
    public boolean hasNext() { 
        while(hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; 
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) throw new NoSuchElementException();
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        while(isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long integer
    public long nextLong() {
        if (!hasNext()) throw new NoSuchElementException();
        long n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        // Read digits and construct the number
        while(true){
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if(b == -1 || !isPrintableChar(b)){
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an integer
    public int nextInt() {
        long nl = nextLong();
        // Ensure the long value fits in an integer
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() { 
        return Double.parseDouble(next());
    }
}

import java.util.StringTokenizer;
