import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Arrays;
import java.util.Scanner;

class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Declare variables
        int x;
        String s;

        // Create a Stack object to store operands
        Stack stack = new Stack();

        // Read a line of input from the user
        s = sc.nextLine();

        // Convert the input string to a character array
        char[] str = s.toCharArray();

        // Get the length of the input string
        int len = s.length();

        // Variable to store numbers parsed from the input
        int num = 0;

        // Iterate over each character in the input string
        for (int i = 0; i < len; i++) {
            num = 0;
            boolean f = false;

            // Parse numbers from the input string
            while (i < len && str[i] <= '9' && str[i] >= '0') {
                num *= 10; // Shift the current number left by one decimal place
                num += str[i] - '0'; // Add the current digit to the number
                i++;
                f = true; // Set flag to true indicating a number was found
            }

            // If a number was parsed, push it onto the stack
            if (f) {
                i--; // Adjust index to account for the extra increment in the while loop
                stack.push(num);
            } else if (str[i] == '+' || str[i] == '-' || str[i] == '*' || str[i] == '/') {
                // If an operator is found, pop two operands from the stack
                int b = (int) stack.pop();
                int a = (int) stack.pop();

                // Perform the operation based on the operator and push the result back onto the stack
                switch (str[i]) {
                    case '+': stack.push(a + b); break;
                    case '-': stack.push(a - b); break;
                    case '*': stack.push(a * b); break;
                    case '/': stack.push(a / b); break;
                    default: break;
                }
            }
        }

        // Output the final result from the stack
        System.out.println((int) stack.pop());
    }
}

class Stack {
    // Initialize the top of the stack
    private int top = 0;

    // Array to store stack elements
    private int[] S = new int[200];

    // Maximum size of the stack
    private static final int MAX = 10;

    // Initialize the stack
    public void initialize() {
        top = 0;
    }

    // Check if the stack is empty
    public boolean isEmpty() {
        return top == 0;
    }

    // Check if the stack is full
    public boolean isFull() {
        return top >= MAX - 1;
    }

    // Push an element onto the stack
    public void push(int x) {
        top++;
        S[top] = x;
    }

    // Pop an element from the stack
    public int pop() {
        top--;
        return S[top + 1];
    }
}

import java.io.*;
import java.util.*;

class Main {
    // FastReader class to efficiently read input from InputStream
    public static class FastReader {
        private InputStream stream; // InputStream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store read data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize FastReader with an InputStream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            // If end of stream is reached, throw an exception
            if (numChars == -1)
                throw new InputMismatchException();

            // If all characters in the buffer are processed, refill the buffer
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException();
                }

                // If no characters are read, return -1 indicating end of stream
                if (numChars <= 0)
                    return -1;
            }

            // Return the next character from the buffer
            return buf[curChar++];
        }

        // Method to read the next line from the input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the input
            } catch (IOException e) {
                e.printStackTrace();
            }
            return str;
        }

        // Method to read the next integer from the input
        public int nextInt() {
            int c = read(); // Read the next character

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            int res = 0; // Resulting integer

            // Read digits and construct the integer
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));

            return res * sgn; // Return the integer with the correct sign
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            int c = read(); // Read the next character

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            long res = 0; // Resulting long integer

            // Read digits and construct the long integer
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));

            return res * sgn; // Return the long integer with the correct sign
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read(); // Read the next character

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            double res = 0; // Resulting double

            // Read digits before the decimal point
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            }

            // Read digits after the decimal point
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9')
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }

            return res * sgn; // Return the double with the correct sign
        }

        // Method to read the next character from the input
        public char nextChar() {
            int c = read(); // Read the next character

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            return (char) c; // Return the character
        }

        // Method to read the next non-space string from the input
        public String next() {
            int c = read(); // Read the next character

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            StringBuilder res = new StringBuilder(); // StringBuilder to construct the string

            // Read characters until a space character is encountered
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString(); // Return the constructed string
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c);
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading input
        OutputStream outputStream = System.out; // Output stream for writing output
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter for output

