            io[arr[i] - 1] = ++c;
        }

        // Print the indices stored in the io array
        for (i = 0; i < n; i++) {
            System.out.print(io[i] + " ");
        }

        w.close(); // Close the PrintWriter
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create an instance of Main and call the run method to start the program
        new Main().run();
    }

    public void run() {
        // Create a Scanner object to read input from the standard input
        Scanner scan = new Scanner(System.in);

        // Continue processing as long as there is more input
        while (scan.hasNext()) {
            // Read the number of processes and the slice time
            int n = scan.nextInt();
            int sTime = scan.nextInt();

            // Initialize an array to hold the processes
            Process[] schedule = new Process[n];
            int count = n; // Number of processes remaining
            int j = 0; // Index for iterating over the processes
            int sumTime = 0; // Total elapsed time

            // Read each process's name and time, and store it in the schedule array
            for (int i = 0; i < n; i++) {
                schedule[i] = new Process(scan.next(), scan.nextInt());
            }

            int a = 0; // Temporary variable to hold the current process time
            int len = schedule.length; // Length of the schedule array

            // Process the schedule until only one process is left
            while (count > 1) {
                // If the number of remaining processes is less than half of the original
                // and the index has reached the end, and there are more than 1000 processes,
                // create a new schedule with only the remaining processes
                if (count < len / 2 && j == len && count > 1000) {
                    Process[] newSchedule = new Process[count];
                    int k = 0; // Index for the new schedule

                    // Copy only the processes with remaining time to the new schedule
                    for (int i = 0; i < len; i++) {
                        if (schedule[i].getTime() == 0) {
                            continue;
                        }
                        newSchedule[k] = new Process(schedule[i].getName(), schedule[i].getTime());
                        k++;
                    }

                    // Update the schedule and its length
                    schedule = newSchedule;
                    len = schedule.length;
                    j = 0; // Reset the index
                }

                // Ensure the index wraps around if it exceeds the length
                if (j >= len) {
                    j %= len;
                }

                // Get the time of the current process
                a = schedule[j].getTime();

                // If the process time is zero, move to the next process
                if (a == 0) {
                    j++;
                    continue;
                } else if (a <= sTime) {
                    // If the process can be completed within the slice time
                    sumTime += a; // Add the process time to the total elapsed time
                    System.out.println(schedule[j].getName() + " " + sumTime); // Output the process name and total time
                    schedule[j++].setTime(0); // Set the process time to zero (completed)
                    count--; // Decrease the count of remaining processes
                    continue;
                }

                // If the process cannot be completed within the slice time
                sumTime += sTime; // Add the slice time to the total elapsed time
                schedule[j++].minusTime(sTime); // Decrease the process time by the slice time
            }

            // Output the last remaining process
            for (int i = 0; i < len; i++) {
                if (schedule[i].getTime() == 0) {
                    continue;
                }
                // Output the last process's name and total time
                System.out.println(schedule[i].getName() + " " + (sumTime + schedule[i].getTime()));
                break;
            }
        }
    }

    // Inner class to represent a process with a name and time
    class Process {
        String name; // Name of the process
        int time; // Time required for the process

        // Default constructor
        public Process() {
        }

        // Constructor to initialize the process with a name and time
        public Process(String name, int time) {
            this.name = name;
            this.time = time;
        }

        // Getter for the process time
        public int getTime() {
            return this.time;
        }

        // Setter for the process time
        public void setTime(int time) {
            this.time = time;
        }

        // Getter for the process name
        public String getName() {
            return this.name;
        }

        // Method to decrease the process time by a specified amount
        public void minusTime(int time) {
            this.time -= time;
        }

        // Setter for the process name
        public void setName(String name) {
            this.name = name;
        }
    }
}

