                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }

            return res * sgn;
        }

        // Method to read the next character from the input stream
        public char nextChar() {
            int c = read();

            while (isSpaceChar(c))
                c = read();

            return (char) c;
        }

        // Method to read the next word (sequence of non-space characters) from the input stream
        public String next() {
            int c = read();

            while (isSpaceChar(c))
                c = read();

            StringBuilder res = new StringBuilder();

            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString();
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c);
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Interface to define a custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading input
        OutputStream outputStream = System.out; // Output stream for writing output
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        double n;
        n = in.nextDouble(); // Read a double value from input

        // Check if the number is even
        if (n % 2 == 0) {
            System.out.println((double) 1 / 2); // Print 1/2 if the number is even
        } else {
            // Calculate and print the result for odd numbers
            System.out.println((double) ((int) (n / 2) + 1) / n);
        }

        w.close(); // Close the PrintWriter
    }
}

import java.util.*;
import java.io.*;

public class Main {
    // Static variable to store the input number
    static int N;

    public static void main(String[] args) {
        // Read the integer input using the FastScanner
        N = sc.nextInt();

        // Initialize the index to track the number of steps
        int index = 1;

        // Use a HashSet to store numbers that have been encountered
        Set<Integer> s = new HashSet<Integer>();

        // Infinite loop to perform operations on N until a cycle is detected
        while(true) {
            // If N is already in the set, a cycle is detected, break the loop
            if (s.contains(N)) break;

            // Add the current value of N to the set
            s.add(N);

            // Increment the step counter
            index++;

            // If N is even, divide it by 2
            if (N%2 == 0) {
                N = N/2;
            } else {
                // If N is odd, apply the 3N + 1 operation
                N = 3 * N + 1;
            }
        }

        // Print the number of steps taken before a cycle was detected
        writer.println(index);

        // Flush the writer to ensure all output is written
        writer.flush();
    }

    // Static instance of FastScanner for reading input
    static final FastScanner sc = new FastScanner(System.in);

    // Static PrintWriter for output
    static PrintWriter writer = new PrintWriter(System.out);

    // Custom FastScanner class for efficient input reading
    static class FastScanner {
        // Reader object to read input
        Reader input;

        // Constructor that initializes the input stream
        FastScanner() {
            this(System.in);
        }

        // Constructor that accepts a custom InputStream
        FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to read the next integer from input
        int nextInt() {
            return (int) nextLong();
        }

        // Method to read the next long integer from input
        long nextLong() {
            try {
                int sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                // Read the numeric value
                long ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Method to read the next double from input
        double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                // Read the numeric value
                double ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }

                // Handle decimal part
                if (b != '.') return sign * ret;
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

        // Method to read the next non-whitespace character from input
        char nextChar() {
            try {
                int b = input.read();

                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                return (char) b;
            } catch (IOException e) {
                e.printStackTrace();
                return 0;
            }
        }

        // Method to read the next string from input
        String nextStr() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();

                // Skip initial whitespace
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }

                // Read characters until whitespace or end of stream
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }
    }

}

import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {

    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner s = new Scanner(System.in);

        // Lists to store the number of rows and columns for each rectangle
        List<Integer> rows = new ArrayList<>();
        List<Integer> columns = new ArrayList<>();

        // Flag to indicate if the input is valid
        boolean flag = true;

        // Infinite loop to continuously read input until a break condition is met
        while (true) {
            // Read the height and width of the rectangle
            int h = s.nextInt();
            int w = s.nextInt();

            // Break the loop if both height and width are zero
            if (h == 0 && w == 0) {
                break;
            }

            // Check if the input dimensions are within the valid range
            if (h >= 3 && w >= 1 && h <= 300 && w <= 300) {
                // Add valid dimensions to the lists
                rows.add(h);
                columns.add(w);
            } else {
                // Set flag to false and break the loop if dimensions are invalid
                flag = false;
                break;
            }
        }

        // If all inputs were valid, proceed to print the rectangles
        if (flag == true) {
            // Iterate over each set of dimensions
            for (int i = 0; i < rows.size(); i++) {
                // Iterate over each row of the current rectangle
                for (int r = 0; r < rows.get(i); r++) {
                    // Iterate over each column of the current row
                    for (int c = 0; c < columns.get(i); c++) {
                        // Print '#' for the first and last row
                        if (r == 0 || r == rows.get(i) - 1) {
                            System.out.print("#");
                        } else {
                            // Print '#' for the first and last column of middle rows
                            if (c == 0 || c == columns.get(i) - 1) {
                                System.out.print("#");
                            } else {
                                // Print '.' for all other positions
                                System.out.print(".");
                            }
                        }
                    }
                    // Move to the next line after printing each row
                    System.out.println();
                }
                // Print an empty line between rectangles
                System.out.println();
            }
        }
    }
}

import java.util.Scanner;

public class Main
{
    public static void main(String[] args)
    {
        // Create a Scanner object to read input from the console
        Scanner In = new Scanner(System.in);
        int N;

        // Prompt the user to enter a valid integer N such that 1 < N < 100
        // The loop will continue until a valid input is provided
        do
        {
            N = In.nextInt();
        } while(1 >= N && N >= 100);

        // Declare variables for iteration
        int i, j;
        // Create an array A of size N to store integers
        int []A = new int[N];

        // Loop to read N integers into the array A
        for(i = 0; i < N; i++)
        {
            // Ensure each integer is between 0 and 1000
            do
            {
                A[i] = In.nextInt();
            } while(0 >= A[i] && A[i] >= 1000);
        }

        // Perform insertion sort on the array A
        for(i = 1; i <= N - 1; i++)
        {
            // Store the current element in v
            int v = A[i];
            // Initialize j to the index before i
            j = i - 1;

            // Print the current state of the array before each insertion
            for(int m = 0; m < N - 1; m++)
                System.out.print(A[m] + " ");
            System.out.print(A[N - 1]);
            System.out.println();

            // Shift elements of A[0..i-1], that are greater than v, to one position ahead
            while(j >= 0 && A[j] > v)
            {
                A[j + 1] = A[j];
                j--;
            }
            // Place v in its correct position
            A[j + 1] = v;
        }

        // Print the sorted array
        for(int l = 0; l < N - 1; l++)
            System.out.print(A[l] + " ");

        System.out.print(A[N - 1]);
        System.out.println();
    }
}

