            // Compare m and n to determine if the situation is "safe" or "unsafe"
            if (m >= n)
                out.println("unsafe");
            else
                out.println("safe");
        }

        // Close the output stream
        out.close();
    }

    // Custom InputReader class for fast input reading
    private static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer for reading input
        private int curChar; // Current character index in buffer
        private int numChars; // Number of characters read into buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read bytes into buffer
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    return -1; // End of stream
                }
            }
            return buf[curChar++]; // Return the next byte
        }

        // Method to read the next integer from input
        public int Int() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Negative number
                c = read();
            }
            int res = 0; // Resulting integer
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the signed integer
        }

        // Method to read the next string from input
        public String String() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c));
            return res.toString(); // Return the resulting string
        }

        // Method to read the next double from input
        public double Double() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Negative number
                c = read();
            }
            double res = 0; // Resulting double
            // Read integer part
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    return res * Math.pow(10, Int());
                }
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            }
            // Read fractional part
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, Int());
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m; // Convert character to fraction
                    c = read();
                }
            }
            return res * sgn; // Return the signed double
        }

        // Method to read the next long integer from input
        public long Long() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Negative number
                c = read();
            }
            long res = 0; // Resulting long integer
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the signed long integer
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c);
            }
            // Default space characters
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Method to read the next token as a string
        public String next() {
            return String();
        }

        // Interface for custom space character filtering
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }
}

