import java.util.ArrayDeque;
import java.util.Queue;
import java.util.Scanner;

public class Main {

    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read two integers A and B from the input
        int A = sc.nextInt();
        int B = sc.nextInt();

        // Initialize two queues to store the prime factors and their counts for A and B
        Queue<Integer[]> a_num = new ArrayDeque<Integer[]>();
        Queue<Integer[]> b_num = new ArrayDeque<Integer[]>();

        // Initialize counters for the number of times each prime divides A and B
        int a_counter = 0;
        int b_counter = 0;

        // Variable to store the final answer, initialized to 1
        long answer = 1;

        // Loop through numbers from 2 to 3199 to find prime factors
        for(int i = 2; i < 3200; i++) {
            a_counter = 0;
            b_counter = 0;

            // Count how many times i divides A and reduce A accordingly
            while(A % i == 0) {
                A /= i;
                a_counter++;
            }
            // If i is a factor of A, add it and its count to the queue
            if(a_counter != 0) {
                Integer[] nums = {i, a_counter};
                a_num.add(nums);
            }

            // Count how many times i divides B and reduce B accordingly
            while(B % i == 0) {
                B /= i;
                b_counter++;
            }
            // If i is a factor of B, add it and its count to the queue
            if(b_counter != 0) {
                Integer[] nums = {i, b_counter};
                b_num.add(nums);
            }
        }

        // If A is still greater than 1, it is a prime number itself
        if(a_num.isEmpty()) {
            Integer[] nums = {A, 1};
            a_num.add(nums);
        } else if(A != 1) {
            Integer[] nums = {A, 1};
            a_num.add(nums);
        }

        // If B is still greater than 1, it is a prime number itself
        if(b_num.isEmpty()) {
            Integer[] nums = {B, 1};
            b_num.add(nums);
        } else if(B != 1) {
            Integer[] nums = {B, 1};
            b_num.add(nums);
        }

        // Add a sentinel value to the end of each queue to mark the end
        Integer[] a_max = {100001, 1};
        a_num.add(a_max);
        Integer[] b_max = {100001, 1};
        b_num.add(b_max);

        // Poll the first elements from each queue
        Integer[] a_tmp = a_num.poll();
        Integer[] b_tmp = b_num.poll();

        // Process the queues until both reach the sentinel value
        while(a_tmp[0] != 100001 || b_tmp[0] != 100001) {
            if(a_tmp[0] < b_tmp[0]) {
                // Multiply the answer by the prime factor from A
                for(int i = 0; i < a_tmp[1]; i++) {
                    answer *= a_tmp[0];
                }
                // Move to the next element in the A queue
                a_tmp = a_num.poll();
            } else if(a_tmp[0] > b_tmp[0]) {
                // Multiply the answer by the prime factor from B
                for(int i = 0; i < b_tmp[1]; i++) {
                    answer *= b_tmp[0];
                }
                // Move to the next element in the B queue
                b_tmp = b_num.poll();
            } else {
                // If both have the same prime factor, multiply by the larger count
                if(a_tmp[1] >= b_tmp[1]) {
                    for(int i = 0; i < a_tmp[1]; i++) {
                        answer *= a_tmp[0];
                    }
                } else {
                    for(int i = 0; i < b_tmp[1]; i++) {
                        answer *= b_tmp[0];
                    }
                }
                // Move to the next elements in both queues
                a_tmp = a_num.poll();
                b_tmp = b_num.poll();
            }
        }

        // Output the final answer
        System.out.println(answer);
    }
}

