            int p = 0;
            // Loop to find the index of the minimum element in the array
            while (min < n - 1 && p < n - 1) {
                p++;
                // Update min if a smaller element is found
                if (num[min] > num[p]) {
                    min = p;
                }
            }

            // Initialize variables to find the index of the maximum element
            int max = 0;
            int q = 0;
            // Loop to find the index of the maximum element in the array
            while (max < n - 1 && q < n - 1) {
                q++;
                // Update max if a larger element is found
                if (num[max] < num[q]) {
                    max = q;
                }
            }

            // Initialize an array to store cumulative sums
            long sum[] = new long[n + 1];
            // Initialize an array to store the values as long for sum calculation
            long value[] = new long[n];
            // Copy the integer values to the long array
            for (int j = 0; j < n; j++) {
                value[j] = num[j];
            }

            // Initialize the first element of the sum array to 0
            sum[0] = 0;
            // Calculate cumulative sums and store them in the sum array
            for (int k = 1; k <= n; k++) {
                sum[k] = value[k - 1] + sum[k - 1];
            }

            // Print the minimum value, maximum value, and the total sum of the array
            System.out.println(num[min] + " " + num[max] + " " + sum[n]);
        } catch (IOException e) {
            // Handle any IO exceptions that occur during input reading
            System.out.println(e);
        } catch (NumberFormatException e) {
            // Handle exceptions that occur during parsing of integers
            System.out.println("error");
        }
    }
}

