        }

        // Method to read an array of integers from input
        int[] readarray(int sz) {
            int[] ret = new int[sz]; // Initialize array of size sz
            for (int i = 0; i < sz; i++)
                ret[i] = nextInt(); // Fill array with integers from input
            return ret; // Return the filled array
        }
