    public static void main(String[] args) {
        IO fs = new IO(); // Create an instance of the IO class
        int n = fs.nextInt(); // Read the number of elements
        int[] h = fs.readarray(n); // Read the array of integers
        int op = 0; // Initialize operation counter

        // Infinite loop to process the array until all elements are zero
        while(true){
            SortedSet<Integer> st = new TreeSet<Integer>(); // TreeSet to store unique elements in sorted order

            int prev = 0; // Variable to track the start of the current segment
            for(int i = 0; i<n; i++){
                if(i == n-1){
                    // Add the last element to the set
                    st.add(h[i]);
                    // Remove zero elements from the set
                    while(!st.isEmpty() && st.first() == 0){
                        st.remove(st.first());
                    }
                    if(!st.isEmpty()){
                        // Get the smallest non-zero element
                        int minval = ((TreeSet<Integer>) st).first();

                        op+=minval; // Increment operation count by minval
                        // Subtract minval from all elements in the current segment
                        for(int j = prev; j<=i; j++){
                            if(h[j]!=0)h[j] -= minval;
                        }
                        st.clear(); // Clear the set for the next segment
                    }
                    prev = i+1; // Update prev to the next index
                }
                else if(h[i] == 0 && !st.isEmpty()){
                    // Remove zero elements from the set
                    while(!st.isEmpty() && st.first() == 0){
                        st.remove(st.first());
                    }
                    if(!st.isEmpty()){
                        // Get the smallest non-zero element
                        int minval = ((TreeSet<Integer>) st).first();

                        op+=minval; // Increment operation count by minval
                        // Subtract minval from all elements in the current segment
                        for(int j = prev; j<=i; j++){
                            if(h[j]!=0)h[j] -= minval;
                        }
                        st.clear(); // Clear the set for the next segment
                    }
                    prev = i+1; // Update prev to the next index
                }
                else if(h[i] == 0 && st.isEmpty())prev+=1; // Move prev forward if current element is zero and set is empty
                else if(!st.contains(h[i]) && h[i] != 0) st.add(h[i]); // Add non-zero elements to the set
                else continue; // Continue if element is already in the set or is zero
            }
            boolean ok = true; // Flag to check if all elements are zero
            for(int i = 0; i<n; i++){
                if(h[i]>0)ok = false; // Set flag to false if any element is greater than zero
            }
            if(ok)break; // Break the loop if all elements are zero
        }
        System.out.println(op); // Print the total number of operations
    }

    // Method to check if all elements in the array are zero
    public static boolean check(int [] h,int n){
        for(int i = 0; i<n; i++){
            if(h[i]>0)return false; // Return false if any element is greater than zero
        }
        return true; // Return true if all elements are zero
    }
}

