class FastScanner {
	private final InputStream in = System.in; // Input stream for reading data
	private final byte[] buffer = new byte[1024]; // Buffer for storing input data
	private int ptr = 0; // Pointer to the current position in the buffer
	private int buflen = 0; // Length of valid data in the buffer

	// Check if there is another byte to read
	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true;
		} else {
			ptr = 0;
			try {
				buflen = in.read(buffer); // Read data into the buffer
			} catch (IOException e) {
				e.printStackTrace();
			}
			if (buflen <= 0) {
				return false; // No more data to read
			}
		}
		return true;
	}

	// Read the next byte from the buffer
	private int readByte() {
		if (hasNextByte())
			return buffer[ptr++];
		else
			return -1; // End of stream
	}

	// Check if a character is printable
	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126;
	}

	// Check if there is another token to read
	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr]))
			ptr++;
		return hasNextByte();
	}

	// Read the next token as a String
	public String next() {
		if (!hasNext())
			throw new NoSuchElementException();
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b);
			b = readByte();
		}
		return sb.toString();
	}

	// Read the next token as a long
	public long nextLong() {
		if (!hasNext())
			throw new NoSuchElementException();
		long n = 0;
		boolean minus = false;
		int b = readByte();
		if (b == '-') {
			minus = true;
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException();
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0';
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n;
			} else {
				throw new NumberFormatException();
			}
			b = readByte();
		}
	}

	// Read the next token as an int
	public int nextInt() {
		long nl = nextLong();
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
			throw new NumberFormatException();
		return (int) nl;
	}

	// Read the next token as a double
	public double nextDouble() {
		return Double.parseDouble(next());
	}

	// Read N integers into an array
	public int[] nextIntsN(int N) {
		int[] ints = new int[N];
		for (int i = 0; i < N; i++) {
			ints[i] = nextInt();
		}
		return ints;
	}

	// Read N long integers into an array
	public long[] nextLongsN(int N) {
		long[] longs = new long[N];
		for (int i = 0; i < N; i++) {
			longs[i] = nextLong();
		}
		return longs;
	}

	// Read N characters into an array
	public char[] nextCharsN(int N) {
		char[] chars = new char[N];
		String msg = next();
		for (int i = 0; i < N; i++) {
			chars[i] = msg.charAt(i);
		}
		return chars;
	}

	// Read a 2D array of characters with dimensions HxW
	public char[][] nextCharsHW(int H, int W) {
		char[][] chars = new char[H][W];
		for (int i = 0; i < H; i++) {
			String str = next();
			for (int j = 0; j < W; j++) {
				chars[i][j] = str.charAt(j);
			}
		}
		return chars;
	}

	// Read a 2D array of integers with dimensions NxM
	public int[][] nextIntsNM(int N, int M) {
		int[][] ints = new int[N][M];
		for (int i = 0; i < N; i++) {
			for (int j = 0; j < M; j++) {
				ints[i][j] = nextInt();
			}
		}
		return ints;
	}

	// Read N integers into a List
	public List<Integer> nextArrayIntsN(int N) {
		ArrayList<Integer> array = new ArrayList<>(N);
		for (int i = 0; i < N; i++) {
			array.add(nextInt());
		}
		return array;
	}

	// Read N long integers into a List
	public List<Long> nextArrayLongsN(int N) {
		ArrayList<Long> array = new ArrayList<>(N);
		for (int i = 0; i < N; i++) {
			array.add(nextLong());
		}
		return array;
	}

	// Read a 2D List of long integers with dimensions NxM
	public List<List<Long>> nextArrayLongsNM(int N, int M) {
		List<List<Long>> arrays = new ArrayList<List<Long>>(M);
		for (int i = 0; i < M; i++) {
			List<Long> array = nextArrayLongsN(N);
			arrays.add(array);
		}
		return arrays;
	}
}

import java.io.*;
import java.util.*;

class Main {
    // FastReader class to efficiently read input from InputStream
    public static class FastReader {

        private InputStream stream; // InputStream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store bytes read from the stream
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter to determine space characters

        // Constructor to initialize FastReader with a given InputStream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            // If no more characters are available, throw an exception
            if (numChars == -1)
                throw new InputMismatchException();

            // If current character index exceeds the number of characters read, refill the buffer
            if (curChar >= numChars) {
                curChar = 0; // Reset current character index

                try {
                    // Read bytes into the buffer and update numChars
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }

                // If no characters were read, return -1 indicating end of stream
                if (numChars <= 0)
                    return -1;
            }

            // Return the next character from the buffer
            return buf[curChar++];
        }

        // Method to read the next line of text from the input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";

            try {
                // Read a line of text
                str = br.readLine();
            } catch (IOException e) {
                e.printStackTrace();
            }

            return str;
        }

        // Method to read the next integer from the input
        public int nextInt() {
            int c = read();

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            int res = 0; // Resulting integer

            // Read digits and construct the integer
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException();

                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));

            return res * sgn; // Return the integer with its sign
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            int c = read();

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            long res = 0; // Resulting long integer

            // Read digits and construct the long integer
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException();

                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));

            return res * sgn; // Return the long integer with its sign
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read();

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            int sgn = 1; // Sign of the number

            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }

            double res = 0; // Resulting double

            // Read digits before the decimal point
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());

                if (c < '0' || c > '9')
                    throw new InputMismatchException();

                res *= 10;
                res += c - '0';
                c = read();
            }

            // If there is a decimal point, read digits after it
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9')
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }

            return res * sgn; // Return the double with its sign
        }

        // Method to read the next character from the input
        public char nextChar() {
            int c = read();

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            return (char) c; // Return the character
        }

        // Method to read the next word (sequence of non-space characters) from the input
        public String next() {
            int c = read();

            // Skip any space characters
            while (isSpaceChar(c))
                c = read();

            StringBuilder res = new StringBuilder();

            // Read characters until a space character is encountered
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString(); // Return the word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c);

            // Default space characters include space, newline, carriage return, tab, and end of stream
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading data
        OutputStream outputStream = System.out; // Output stream for writing data
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        int n, k, i, c = 0; // Declare variables
        n = in.nextInt(); // Read the number of elements
        k = in.nextInt(); // Read the threshold value
        int arr[] = new int[n]; // Array to store the elements

        // Loop to read elements into the array
        for (i = 0; i < n; i++) {
            arr[i] = in.nextInt(); // Read each element
            if (arr[i] >= k) { // Check if the element is greater than or equal to the threshold
                c++; // Increment the count if condition is met
            }
        }

        // Print the count of elements greater than or equal to the threshold
        System.out.println(c);
        w.close(); // Close the PrintWriter
    }
}

