import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
	public static void main (String[] args) throws IOException
	{
		// Create a BufferedReader to read input from the console
		BufferedReader input = new BufferedReader (new InputStreamReader (System.in));

		// Read the first line of input, which is the main string to be searched
		String str = input.readLine();

		// Read the second line of input, which is the substring we want to find
		String want = input.readLine();

		// Initialize a boolean flag to determine if the substring is found
		boolean judge = false;

		// Check if the substring length is 1
		if(want.length() == 1)
		{
			// Iterate over each character in the main string
			for(int num = 0; num < str.length(); num++)
			{
				// Check if the current character matches the single character substring
				if(str.charAt(num) == want.charAt(0))
				{
					// If a match is found, set the flag to true and exit the loop
					judge = true;
					break;
				}
			}
		}
		else
		{
			// Iterate over each character in the main string
			for(int start = 0; start < str.length(); start++)
			{
				// Check if the current character matches the first character of the substring
				if(str.charAt(start) == want.charAt(0))
				{
					// Iterate over the remaining characters of the substring
					for(int next = 1; next < want.length(); next++)
					{
						// Check if the next character in the main string matches the next character in the substring
						if(next + start < str.length())
						{
							if(str.charAt(next + start) != want.charAt(next))
								break; // Break if characters do not match
						}
						// Handle the case where the search wraps around the end of the main string
						else if(next + start >= str.length())
						{
							if(str.charAt(next + start - str.length()) != want.charAt(next))
								break; // Break if characters do not match
						}

						// If the end of the substring is reached and all characters matched
						if(next + 1 == want.length())
							judge = true; // Set the flag to true
					}
				}
			}
		}

		// Output "Yes" if the substring was found, otherwise "No"
		if(judge)
			System.out.println("Yes");
		else
			System.out.println("No");
	}
}

