import java.util.Scanner;

public class Main {

    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Infinite loop to continuously process input until a termination condition is met
        while (true) {
            // Read a line of input representing the sequence of cards
            String cards = sc.nextLine();

            // Check for termination condition: if input is "-", exit the loop
            if (cards.equals("-")) {
                break;
            }

            // Split the input string into an array of single-character strings
            String[] cds = cards.split("");

            // Get the length of the card sequence
            int cdlength = cards.length();

            // Create a secondary array to hold shuffled cards
            String[] cds2 = new String[cdlength];

            // Read the number of shuffles to perform
            int repeat = Integer.parseInt(sc.nextLine());

            // Loop through each shuffle operation
            for (int i = 0; i < repeat; i++) {
                // Read the shuffle position
                int shuffle = Integer.parseInt(sc.nextLine());

                // Determine which array to shuffle based on the current iteration
                if (i % 2 == 0) {
                    // Shuffle from cds to cds2
                    for (int j = 0, k = shuffle; j < cdlength; j++, k++) {
                        // Wrap around the index if it exceeds the array length
                        if (k == cdlength) {
                            k = 0;
                        }
                        // Assign the shuffled card to the new position in cds2
                        cds2[j] = cds[k];
                    }
                } else {
                    // Shuffle from cds2 back to cds
                    for (int j = 0, k = shuffle; j < cdlength; j++, k++) {
                        // Wrap around the index if it exceeds the array length
                        if (k == cdlength) {
                            k = 0;
                        }
                        // Assign the shuffled card to the new position in cds
                        cds[j] = cds2[k];
                    }
                }
            }

            // Use a StringBuilder to construct the final shuffled sequence
            StringBuilder after = new StringBuilder();

            // Determine which array holds the final shuffled sequence based on the number of shuffles
            if (repeat % 2 == 0) {
                // If even number of shuffles, the final sequence is in cds
                for (int i = 0; i < cdlength; i++) {
                    after.append(cds[i]);
                }
            } else {
                // If odd number of shuffles, the final sequence is in cds2
                for (int i = 0; i < cdlength; i++) {
                    after.append(cds2[i]);
                }
            }

            // Output the final shuffled sequence
            System.out.println(after.toString());
        }
    }
}

import java.io.*;
import java.util.*;
import java.lang.*;

public class Main {

    // FastReader class to efficiently read input from the input stream
    public static class FastReader {
        private InputStream stream; // Input stream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter to define space characters

        // Constructor to initialize the FastReader with an input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            if (numChars == -1) // If end of stream is reached, throw an exception
                throw new InputMismatchException();
            if (curChar >= numChars) { // If all characters in the buffer are processed
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read more characters into the buffer
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) // If no characters are read, return -1 indicating end of stream
                    return -1;
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to read the next line of input as a String
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the input
            } catch (IOException e) {
                e.printStackTrace();
            }
            return str;
        }

        // Method to read the next integer from the input
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c)) // Skip any space characters
                c = read();
            int sgn = 1;
            if (c == '-') { // Check for negative sign
                sgn = -1;
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9') // Ensure the character is a digit
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is encountered
            return res * sgn; // Return the integer with the correct sign
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9')
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Method to read the next character from the input
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            return (char) c;
        }

        // Method to read the next word (sequence of non-space characters) from the input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));
            return res.toString();
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c);
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Interface to define a custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading input
        OutputStream outputStream = System.out; // Output stream for writing output
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        // Array of days of the week
        String s[] = {"SUN", "MON", "TUE", "WED", "THU", "FRI", "SAT"};

        // Read the input string representing a day
        String str = in.next();

        // Loop to find the index of the input day in the array
        int i;
        for (i = 0; i < 7; i++) {
            if (str.equals(s[i])) {
                break; // Break the loop when the day is found
            }
        }

        // Print the number of days until the next Sunday
        w.println(7 - i);

        // Close the PrintWriter
        w.close();
    }
}

