class hayami implements Closeable {
    // InputStream to read input data
    private final InputStream in = System.in;

    // Buffer to store input data
    private final byte[] hayami = new byte[1024];

    // Pointers to track the current position in the buffer
    private int Hayami = 0;
    private int saori = 0;

    // Method to check if there is more data to read
    private boolean HayamiSaori() {
        if (Hayami < saori) {
            return true;
        } else {
            Hayami = 0;
            try {
                // Read data into the buffer
                saori = in.read(hayami);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no data was read
            if (saori <= 0) {
                return false;
            }
        }
        return true;
    }

    // Method to get the next byte from the buffer
    private int SaoriHayami() {
        if (HayamiSaori()) {
            return hayami[Hayami++];
        } else {
            return -1;
        }
    }

    // Method to check if a byte is a valid character (printable ASCII)
    private static boolean hayami_saori(int hayami) {
        return 33 <= hayami && hayami <= 126;
    }

    // Method to skip non-printable characters and check if there are more characters
    public boolean hayamisaori() {
        while (HayamiSaori() && !hayami_saori(hayami[Hayami])) Hayami++;
        return HayamiSaori();
    }

    // Method to read the next string from input
    public String nextHayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        StringBuilder hayamin = new StringBuilder();
        int saori = SaoriHayami();
        while (hayami_saori(saori)) {
            hayamin.appendCodePoint(saori);
            saori = SaoriHayami();
        }
        return hayamin.toString();
    }

    // Method to read the next long integer from input
    public long saorihayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        long hayami = 0;
        boolean misao = false;
        int saori = SaoriHayami();

        // Check for negative numbers
        if (saori == '-') {
            misao = true;
            saori = SaoriHayami();
        }

        // Validate that the input is a digit
        if (saori < '0' || '9' < saori) {
            throw new NumberFormatException();
        }

        // Convert the input characters to a long integer
        while (true) {
            if ('0' <= saori && saori <= '9') {
                hayami *= 10;
                hayami += saori - '0';
            } else if (saori == -1 || !hayami_saori(saori)) {
                return misao ? -hayami : hayami;
            } else {
                throw new NumberFormatException();
            }
            saori = SaoriHayami();
        }
    }

    // Method to read the next integer from input
    public int saori_hayami() {
        long hayami = saorihayami();
        // Check if the long value fits within the integer range
        if (hayami < Integer.MIN_VALUE || hayami > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) hayami;
    }

    // Method to read the next double from input
    public double Hayamin() {
        return Double.parseDouble(nextHayami());
    }

    // Close the input stream
    public void close() {
        try {
            in.close();
        } catch (IOException e) {
            // Handle exception silently
        }
    }
}

