    public static void main(String[] args) {

        // Create a Scanner object to read input from the console
        Scanner scan = new Scanner(System.in);

        // Read the integer X from input
        int X = scan.nextInt();

        // Read the integer N from input, which represents the size of the array
        int N = scan.nextInt();

        // Initialize an array M of size N to store the integers
        int M[] = new int[N];

        // Initialize variables K and Y to 0
        int K = 0;
        int Y = 0;

        // Loop to read N integers into the array M
        for (int i = 0; i < N; i++) {
            M[i] = scan.nextInt();

            // If the current element is equal to X, set K and Y to 1
            if (M[i] == X) {
                K = 1;
                Y = 1;
            }
        }

        // Initialize P with the value of X
        int P = X;

        // Initialize C to 1, which will be used as a flag
        int C = 1;

        // Sort the array M in ascending order
        Arrays.sort(M);

        // Loop to find the closest number to X in the array M
        for (int i = 0; i < N && K == 1 && C == 1; i++) {
            C = 0; // Reset C to 0
            K = 0; // Reset K to 0

            // Loop through the array M from the end to the beginning
            for (int j = N - 1; j >= 0 && K == 0; j--) {
                // Check if the current element is equal to X + i
                if (M[j] == X + i) {
                    C = 1; // Set C to 1
                    P = M[j]; // Update P to the current element
                }

                // Check if the current element is equal to X - i
                if (M[j] == X - i) {
                    K = 1; // Set K to 1
                    P = M[j]; // Update P to the current element
                }
            }
        }

        // Output the result based on the values of P, X, Y, K, and C
        if (P > X && Y == 1 && C == 0) {
            System.out.println(2 * X - P - 1);
        }
        if (P > X && Y == 1 && C == 1) {
            System.out.println(2 * X - P);
        }
        if (P < X && Y == 1 && K == 0) {
            System.out.println(P - 1);
        }
        if (P < X && Y == 1 && K == 1 && C == 0) {
            System.out.println(2 * X - P);
        }
        if (P == X && Y == 1) {
            System.out.println(P - 1);
        }
        if (Y == 0) {
            System.out.println(X);
        }
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read integers a, b, h, and m from the input
        int a = sc.nextInt(); // Length of the hour hand
        int b = sc.nextInt(); // Length of the minute hand
        int h = sc.nextInt(); // Current hour
        int m = sc.nextInt(); // Current minute

        // Calculate the angle of the hour hand from 12:00 in degrees
        // The hour hand moves 0.5 degrees per minute (30 degrees per hour)
        double argA = (double) (60 * h + m) / 2;

        // Calculate the angle of the minute hand from 12:00 in degrees
        // The minute hand moves 6 degrees per minute
        double argB = 6 * m;

        // Initialize coordinates for the hour hand (ax, ay) and minute hand (bx, by)
        double ax = 0;
        double ay = 0;
        double bx = 0;
        double by = 0;

        // Calculate the (x, y) coordinates of the hour hand based on its angle
        if (argA >= 0 && argA <= 90) {
            // First quadrant
            ax = a * Math.cos(Math.toRadians(90 - argA));
            ay = a * Math.sin(Math.toRadians(90 - argA));
        } else if (argA > 90 && argA <= 180) {
            // Second quadrant
            ax = a * Math.cos(Math.toRadians(argA - 90));
            ay = -a * Math.sin(Math.toRadians(argA - 90));
        } else if (argA > 180 && argA <= 270) {
            // Third quadrant
            ax = -a * Math.cos(Math.toRadians(270 - argA));
            ay = -a * Math.sin(Math.toRadians(270 - argA));
        } else if (argA > 270 && argA <= 360) {
            // Fourth quadrant
            ax = -a * Math.cos(Math.toRadians(argA - 270));
            ay = a * Math.sin(Math.toRadians(argA - 270));
        }

        // Calculate the (x, y) coordinates of the minute hand based on its angle
        if (argB >= 0 && argB <= 90) {
            // First quadrant
            bx = b * Math.cos(Math.toRadians(90 - argB));
            by = b * Math.sin(Math.toRadians(90 - argB));
        } else if (argB > 90 && argB <= 180) {
            // Second quadrant
            bx = b * Math.cos(Math.toRadians(argB - 90));
            by = -b * Math.sin(Math.toRadians(argB - 90));
        } else if (argB > 180 && argB <= 270) {
            // Third quadrant
            bx = -b * Math.cos(Math.toRadians(270 - argB));
            by = -b * Math.sin(Math.toRadians(270 - argB));
        } else if (argB > 270 && argB <= 360) {
            // Fourth quadrant
            bx = -b * Math.cos(Math.toRadians(argB - 270));
            by = b * Math.sin(Math.toRadians(argB - 270));
        }

        // Calculate the distance between the tips of the hour and minute hands
        // Using the distance formula: sqrt((x2 - x1)^2 + (y2 - y1)^2)
        double result = (double) Math.sqrt(Math.pow(bx - ax, 2) + Math.pow(by - ay, 2));

        // Print the result, which is the distance between the two hands
        System.out.println(result);
    }
}

import java.util.Scanner;

public class Main {

    // Define a static inner class 'node' to represent each node in a doubly linked list
    static class node {
        int val = -1; // Initialize the value of the node to -1
        node prev; // Reference to the previous node
        node next; // Reference to the next node
    }

    public static void main(String[] args) {

        Scanner scn = new Scanner(System.in); // Create a Scanner object to read input
        String str = scn.next(); // Read a string input from the user
        int[] arr = new int[str.length()]; // Create an integer array to store the numeric values of the string characters

        // Convert each character of the string to an integer and store it in the array
        for (int i = 0; i < str.length(); i++) {
            arr[i] = str.charAt(i) - '0'; // Convert character to integer by subtracting '0'
        }

        node start = new node(); // Initialize the start node of the doubly linked list
        node ptr = new node(); // Initialize a pointer node to traverse the list
        ptr = start; // Set the pointer to the start node

        // Traverse the array from the end to the beginning
        for (int i = str.length() - 1; i >= 0; i--) {
            if (start.val == -1) { // If the start node is uninitialized
                node n1 = new node(); // Create a new node
                n1.val = arr[i]; // Set the value of the new node
                n1.prev = null; // Set the previous node to null
                n1.next = null; // Set the next node to null
                start = n1; // Set the start node to the new node
                ptr = start; // Set the pointer to the start node
            } else if (arr[i] == 1) { // If the current array element is 1
                if (ptr.val == 1) { // If the current node value is 1
                    node n1 = new node(); // Create a new node
                    n1.val = arr[i]; // Set the value of the new node
                    n1.prev = ptr; // Set the previous node to the current pointer
                    n1.next = null; // Set the next node to null
                    ptr.next = n1; // Link the current node to the new node
                    ptr = n1; // Move the pointer to the new node
                } else {
                    // If the current node value is not 1, backtrack to the previous node
                    if (start != null && ptr != start) {
                        ptr = ptr.prev; // Move the pointer to the previous node
                        ptr.next = null; // Remove the link to the current node
                    } else if (ptr == start) {
                        start = new node(); // Reset the start node
                        ptr = start; // Reset the pointer to the start node
                    }
                }
            } else { // If the current array element is 0
                if (ptr.val == 0) { // If the current node value is 0
                    node n1 = new node(); // Create a new node
                    n1.val = arr[i]; // Set the value of the new node
                    n1.prev = ptr; // Set the previous node to the current pointer
                    n1.next = null; // Set the next node to null
                    ptr.next = n1; // Link the current node to the new node
                    ptr = n1; // Move the pointer to the new node
                } else {
                    // If the current node value is not 0, backtrack to the previous node
                    if (start != null && ptr != start) {
                        ptr = ptr.prev; // Move the pointer to the previous node
                        ptr.next = null; // Remove the link to the current node
                    } else if (ptr == start) {
                        start = new node(); // Reset the start node
                        ptr = start; // Reset the pointer to the start node
                    }
                }
            }
        }

        int cnt = 0; // Initialize a counter to count the number of nodes with valid values
        while (start != null) { // Traverse the linked list
            if (start.val != -1) // If the node has a valid value
                cnt++; // Increment the counter
            start = start.next; // Move to the next node
        }

        // Print the difference between the original string length and the count of valid nodes
        System.out.println(str.length() - cnt);
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read the number of string pairs to be compared
        int n = sc.nextInt();

        // Initialize arrays to store the pairs of strings
        String[] str1 = new String[n];
        String[] str2 = new String[n];

        // Initialize scores for Tarou and Hanako
        int tarou = 0;
        int hanako = 0;

        // Read n pairs of strings from input
        for (int i = 0; i < n; i++) {
            str1[i] = sc.next(); // Read first string of the pair
            str2[i] = sc.next(); // Read second string of the pair
        }

        // Compare each pair of strings
        for (int j = 0; j < n; j++) {
            // Convert strings to character arrays for comparison
            char[] ch1 = str1[j].toCharArray();
            char[] ch2 = str2[j].toCharArray();

            // Check if the length of the first string is less than or equal to the second
            if (str1[j].length() <= str2[j].length()) {
                // Create a character array to hold the characters of the shorter string
                char[] ch3 = new char[str2[j].length()];
                ch3 = str1[j].toCharArray();

                // Compare characters of both strings
                for (int k = 0; k < str1[j].length(); k++) {
                    // If strings are of equal length
                    if (str1[j].length() == str2[j].length()) {
                        // If last character is the same, it's a draw
                        if (k + 1 == str1[j].length() && ch3[k] == ch2[k]) {
                            tarou += 1;
                            hanako += 1;
                        }
                        // If characters are the same, continue to next character
                        else if (ch3[k] == ch2[k]) {
                            continue;
                        }
                        // If character from str1 is greater, Tarou wins
                        else if (ch3[k] > ch2[k]) {
                            tarou += 3;
                            break;
                        }
                        // If character from str2 is greater, Hanako wins
                        else if (ch3[k] < ch2[k]) {
                            hanako += 3;
                            break;
                        }
                    } else {
                        // If last character of shorter string is the same, Hanako wins
                        if (k + 1 == str1[j].length() && ch3[k] == ch2[k]) {
                            hanako += 3;
                        }
                        // If characters are the same, continue to next character
                        else if (ch3[k] == ch2[k]) {
                            continue;
                        }
                        // If character from str1 is greater, Tarou wins
                        else if (ch3[k] > ch2[k]) {
                            tarou += 3;
                            break;
                        }
                        // If character from str2 is greater, Hanako wins
                        else if (ch3[k] < ch2[k]) {
                            hanako += 3;
                            break;
                        }
                    }
                }
            }
            // If the first string is longer than the second
            else if (str1[j].length() > str2[j].length()) {
                // Create a character array to hold the characters of the shorter string
                char[] ch3 = new char[str1[j].length()];
                ch3 = str2[j].toCharArray();

                // Compare characters of both strings
                for (int k = 0; k < str2[j].length(); k++) {
                    // If last character of shorter string is the same, Tarou wins
                    if (k + 1 == str2[j].length() && ch3[k] == ch1[k]) {
                        tarou += 3;
                    }
                    // If characters are the same, continue to next character
                    else if (ch3[k] == ch1[k]) {
                        continue;
                    }
                    // If character from str2 is greater, Hanako wins
                    else if (ch3[k] > ch1[k]) {
                        hanako += 3;
                        break;
                    }
                    // If character from str1 is greater, Tarou wins
                    else if (ch3[k] < ch1[k]) {
                        tarou += 3;
                        break;
                    }
                }
            }
        }

        // Output the final scores of Tarou and Hanako
