import java.io.*;
import java.math.BigDecimal;
import java.util.*;

@SuppressWarnings("unused")
public class Main {
    FastScanner in; // Custom input reader
    PrintWriter out; // Output writer
    final static int MOD = (int)1e9+7; // A constant for modulus operations, not used in this code

    // Main logic of the program
    void solve(){
        int N = in.nextInt(); // Read the number of strings
        String[] S = new String[N]; // Array to store the strings
        for(int i = 0; i < N; i++) S[i] = in.nextStr(); // Read each string into the array

        // Array of possible outcomes
        String[] p = {"AC", "WA", "TLE", "RE"};
        int[] C = new int[p.length]; // Array to count occurrences of each outcome
        for(int i = 0; i < N; i++){
            for(int j = 0; j < p.length; j++){
                if(S[i].equals(p[j])) C[j]++; // Increment count if the string matches an outcome
            }
        }
        // Print the count of each outcome
        for(int i = 0; i < p.length; i++){
            out.println(p[i] + " x " + C[i]);
        }
    }

    public static void main(String[] args) {
        new Main().m(); // Create an instance of Main and call the method m()
    }

    private void m() {
        in = new FastScanner(System.in); // Initialize the input reader
        out = new PrintWriter(System.out); // Initialize the output writer

        solve(); // Call the solve method to execute the main logic
        out.flush(); // Flush the output stream
        in.close(); // Close the input stream
        out.close(); // Close the output stream
    }

    // Custom input reader class
    static class FastScanner {
        private Reader input; // Reader for input stream

        public FastScanner() {this(System.in);} // Default constructor using System.in
        public FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));} // Constructor with InputStream
        public void close() {
            try {
                this.input.close(); // Close the input stream
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
            }
        }

        // Method to read the next integer
        public int nextInt() {
            long nl = nextLong(); // Read as long first
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException(); // Check for overflow
            return (int) nl; // Return as integer
        }

        // Method to read the next long
        public long nextLong() {
            try {
                int sign = 1; // Sign of the number
                int b = input.read(); // Read the first byte
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                if (b == '-') {
                    sign = -1; // Set sign to negative
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                long ret = b - '0'; // Initialize the number
                while (true) {
                    b = input.read(); // Read next byte
                    if (b < '0' || '9' < b) return ret * sign; // Return if not a digit
                    ret *= 10; // Multiply current number by 10
                    ret += b - '0'; // Add the new digit
                }
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
                return -1; // Return -1 in case of error
            }
        }

        // Method to read the next double
        public double nextDouble() {
            try {
                double sign = 1; // Sign of the number
                int b = input.read(); // Read the first byte
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                if (b == '-') {
                    sign = -1; // Set sign to negative
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                double ret = b - '0'; // Initialize the number
                while (true) {
                    b = input.read(); // Read next byte
                    if (b < '0' || '9' < b) break; // Break if not a digit
                    ret *= 10; // Multiply current number by 10
                    ret += b - '0'; // Add the new digit
                }
                if (b != '.') return sign * ret; // Return if no decimal point
                double div = 1; // Divider for decimal places
                b = input.read(); // Read next byte
                while ('0' <= b && b <= '9') {
                    ret *= 10; // Multiply current number by 10
                    ret += b - '0'; // Add the new digit
                    div *= 10; // Increase the divider
                    b = input.read(); // Read next byte
                }
                return sign * ret / div; // Return the final double value
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
                return Double.NaN; // Return NaN in case of error
            }
        }

        // Method to read the next character
        public char nextChar() {
            try {
                int b = input.read(); // Read the first byte
                while (Character.isWhitespace(b)) {
                    b = input.read(); // Skip whitespace
                }
                return (char) b; // Return the character
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
                return 0; // Return null character in case of error
            }
        }

        // Method to read the next string
        public String nextStr() {
            try {
                StringBuilder sb = new StringBuilder(); // StringBuilder for the string
                int b = input.read(); // Read the first byte
                while (Character.isWhitespace(b)) {
                    b = input.read(); // Skip whitespace
                }
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b); // Append character to StringBuilder
                    b = input.read(); // Read next byte
                }
                return sb.toString(); // Return the string
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
                return ""; // Return empty string in case of error
            }
        }

        // Method to read the next line
        public String nextLine() {
            try {
                StringBuilder sb = new StringBuilder(); // StringBuilder for the line
                int b = input.read(); // Read the first byte
                while (b != -1 && b != '\n') {
                    sb.append((char) b); // Append character to StringBuilder
                    b = input.read(); // Read next byte
                }
                return sb.toString(); // Return the line
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an exception occurs
                return ""; // Return empty string in case of error
            }
        }

        // Method to read an array of integers
        public int[] nextIntArray(int n) {
            int[] res = new int[n]; // Array to store integers
            for (int i = 0; i < n; i++) {
                res[i] = nextInt(); // Read each integer
            }
            return res; // Return the array
        }

        // Method to read an array of integers and decrement each by 1
        public int[] nextIntArrayDec(int n) {
            int[] res = new int[n]; // Array to store integers
            for (int i = 0; i < n; i++) {
                res[i] = nextInt() - 1; // Read each integer and decrement by 1
            }
            return res; // Return the array
        }

        // Method to read an array of integers with 1-based indexing
        public int[] nextIntArray1Index(int n) {
            int[] res = new int[n + 1]; // Array with extra space for 1-based index
            for (int i = 0; i < n; i++) {
                res[i + 1] = nextInt(); // Read each integer into 1-based index
            }
            return res; // Return the array
        }

        // Method to read an array of longs
        public long[] nextLongArray(int n) {
            long[] res = new long[n]; // Array to store longs
            for (int i = 0; i < n; i++) {
                res[i] = nextLong(); // Read each long
            }
            return res; // Return the array
        }

        // Method to read an array of longs and decrement each by 1
        public long[] nextLongArrayDec(int n) {
            long[] res = new long[n]; // Array to store longs
            for (int i = 0; i < n; i++) {
                res[i] = nextLong() - 1; // Read each long and decrement by 1
            }
            return res; // Return the array
        }

        // Method to read an array of longs with 1-based indexing
        public long[] nextLongArray1Index(int n) {
            long[] res = new long[n + 1]; // Array with extra space for 1-based index
            for (int i = 0; i < n; i++) {
                res[i + 1] = nextLong(); // Read each long into 1-based index
            }
            return res; // Return the array
        }

        // Method to read an array of doubles
        public double[] nextDoubleArray(int n) {
            double[] res = new double[n]; // Array to store doubles
            for (int i = 0; i < n; i++) {
                res[i] = nextDouble(); // Read each double
            }
            return res; // Return the array
        }
    }
}

import java.util.*;
import java.io.*;

class Main {
    public static void main(String[] args) {
        // Create an instance of FastScanner to read input
        FastScanner sc = new FastScanner();

        // Read two integers from input
        int n = sc.nextInt();
        int m = sc.nextInt();

        // Check if both integers are less than 10
        if(n < 10 && m < 10) 
            // If true, print the product of n and m
            p(n * m);
        else 
            // If false, print -1
            p(-1);
    }

    // Generic method to print any type of element
    public static <T> void p(T element) {
        System.out.println(element);
    }

    // Method to find the minimum of three integers
    public static int min(int a, int b, int c) {
        // Find the minimum between a and b
        int min = Math.min(a, b);
        // Find the minimum between the current min and c
        min = Math.min(min, c);
        return min;
    }

    // Method to find the maximum of three integers
    public static int max(int a, int b, int c) {
        // Find the maximum between a and b
        int max = Math.max(a, b);
        // Find the maximum between the current max and c
        max = Math.max(max, c);
        return max;
    }
}

class FastScanner {
    // InputStream to read from standard input
    private final InputStream in = System.in;
    // Buffer to store input bytes
    private final byte[] buffer = new byte[1024];
    // Pointer to track the current position in the buffer
    private int ptr = 0;
    // Length of valid data in the buffer
    private int buflen = 0;

    // Check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                // Read data into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no data was read
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte())
            return buffer[ptr++];
        else
            return -1;
    }

    // Check if a character is printable
    private boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Check if there is another token to read
    public boolean hasNext() {
        // Skip non-printable characters
        while (hasNextByte() && !isPrintableChar(buffer[ptr]))
            ptr++;
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext())
            throw new NoSuchElementException();
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder until a non-printable character is found
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long
    public long nextLong() {
        if (!hasNext())
            throw new NoSuchElementException();
        long n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        // Convert characters to a long value
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an int
    public int nextInt() {
        long nl = nextLong();
        // Check if the long value fits in an int
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
            throw new NumberFormatException();
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next());
    }
}

