public class Main{

    public static void main(String[] args) {

        // Initialize a counter to store the number of occurrences of the target word
        int intAnwer = 0;

        try {
            // Create a BufferedReader to read input from the console
            BufferedReader insBR = new BufferedReader(new InputStreamReader(System.in));

            // Read the first line of input, which is the target word to search for
            String strLine = insBR.readLine();

            // Convert the target word to lowercase to ensure case-insensitive comparison
            strLine = strLine.toLowerCase();

            // Convert the target word into a character array for easier comparison
            char[] chaAryLine1 = strLine.toCharArray();

            // Continuously read lines of input until "END_OF_TEXT" is encountered
            while (true) {
                strLine = insBR.readLine();

                // Break the loop if the end marker "END_OF_TEXT" is reached
                if (strLine.equals("END_OF_TEXT")) {
                    break;
                }

                // Convert the current line to lowercase for case-insensitive comparison
                strLine = strLine.toLowerCase();

                // Convert the current line into a character array
                char[] chaAryLineAll = strLine.toCharArray();

                // Initialize a counter to track matching characters
                int intCount = 0;

                // Calculate the number of possible starting positions for the target word in the current line
                int intlength = chaAryLineAll.length - chaAryLine1.length + 1;

                // Iterate over each possible starting position in the current line
                for (int i = 0; i < intlength; i++) {

                    // Compare the first character of the target word with the current position in the line
                    char a = chaAryLine1[0];
                    char b = chaAryLineAll[i];

                    if (a == b) {
                        // If the first character matches, check the subsequent characters
                        for (int j = 1; j < chaAryLine1.length; j++) {
                            a = chaAryLine1[j];
                            b = chaAryLineAll[i + j];

                            if (a == b) {
                                intCount++;

                                // If all characters match, check word boundaries
                                if (intCount == chaAryLine1.length - 1) {

                                    // Check if the match is at the start of the line and followed by a space
                                    if(i == 0 && i + j + 1 != chaAryLineAll.length) {
                                        if(chaAryLineAll[i + j + 1] == ' ') {
                                            intAnwer++;
                                        }

                                    // Check if the match is at the end of the line and preceded by a space
                                    }else if(0 < i && i + j + 1 == chaAryLineAll.length) {
                                        if(chaAryLineAll[i -1] == ' ') {
                                            intAnwer++;
                                        }

                                    // Check if the match is surrounded by spaces
                                    }else if(0 < i && i + j + 1 < chaAryLineAll.length) {
                                        if(chaAryLineAll[i -1] == ' ') {
                                            if(chaAryLineAll[i + j + 1] == ' ') {
                                                intAnwer++;
                                            }
                                        }

                                    // Check if the match is the entire line
                                    }else if(i == 0 && i + j + 1 == chaAryLineAll.length) {
                                        intAnwer++;
                                    }

                                }
                            }
                        }
                    }

                    // Special case for single-character target words
                    if(chaAryLine1.length == 1) {
                        if(a == b) {

                            // Check if the match is at the start of the line and followed by a space
                            if(i == 0 && i + 1 != chaAryLineAll.length) {
                                if(chaAryLineAll[i + 1] == ' ') {
                                    intAnwer++;
                                }

                            // Check if the match is at the end of the line and preceded by a space
                            }else if(0 < i && i + 1 == chaAryLineAll.length) {
                                if(chaAryLineAll[i -1] == ' ') {
                                    intAnwer++;
                                }

                            // Check if the match is surrounded by spaces
                            }else if(0 < i && i + 1 < chaAryLineAll.length) {
                                if(chaAryLineAll[i -1] == ' ') {
                                    if(chaAryLineAll[i + 1] == ' ') {
                                        intAnwer++;
                                    }
                                }

                            // Check if the match is the entire line
                            }else if(i == 0 && i + 1 == chaAryLineAll.length) {
                                intAnwer++;
                            }
                        }

                    }

                    // Reset the character match counter for the next starting position
                    intCount = 0;
                }
            }

            // Output the total number of occurrences of the target word
            System.out.println(intAnwer);

        } catch (IOException e) {
