import java.io.*;
import java.util.*;
import java.lang.*;

public class Main{
    // FastReader class for fast input reading
    public static class FastReader {
        private InputStream stream; // Input stream for reading data
        private byte[] buf = new byte[1024]; // Buffer for storing input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data
        public int read() {
            if (numChars == -1)
                throw new InputMismatchException(); // Exception if no more data
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Exception on IO error
                }
                if (numChars <= 0)
                    return -1; // End of stream
            }
            return buf[curChar++]; // Return the next character
        }

        // Method to read the next line of input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from input
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace on error
            }
            return str;
        }

        // Method to read the next integer
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Exception if not a digit
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the integer with sign
        }

        // Method to read the next long integer
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Exception if not a digit
                res *= 10;
                res += c - '0'; // Convert character to long integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the long integer with sign
        }

        // Method to read the next double
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Exception if not a digit
                res *= 10;
                res += c - '0'; // Convert character to double
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Exception if not a digit
                    m /= 10;
                    res += (c - '0') * m; // Convert fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the double with sign
        }

        // Method to read the next character
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            return (char) c; // Return the character
        }

        // Method to read the next word
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c));
            return res.toString(); // Return the word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c); // Use custom filter if available
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Method to calculate the greatest common divisor (GCD) using Euclidean algorithm
    static long gcd(long a, long b) {
        if (a == 0)
            return b; // Base case: if a is 0, return b
        return gcd(b % a, a); // Recursive call
    }

    // Method to calculate the least common multiple (LCM)
    static long lcm(long a, long b) {
        return (a * b) / gcd(a, b); // LCM formula using GCD
    }

    // Method to find the maximum subarray sum using Kadane's algorithm
    static long func(long a[], long size, int s) {
        long max1 = a[s]; // Initialize max1 with the first element
        long maxc = a[s]; // Initialize maxc with the first element
        for (int i = s + 1; i < size; i++) {
            maxc = Math.max(a[i], maxc + a[i]); // Update maxc with the maximum of current element or sum
            max1 = Math.max(maxc, max1); // Update max1 with the maximum of maxc or max1
        }
        return max1; // Return the maximum subarray sum
    }

    // Generic Pair class implementing Comparable interface
    public static class Pair<U extends Comparable<U>, V extends Comparable<V>> implements Comparable<Pair<U, V>> {
        public U x; // First element of the pair
        public V y; // Second element of the pair

        // Constructor to initialize the pair
        public Pair(U x, V y) {
            this.x = x;
            this.y = y;
        }

        // Override hashCode method for hashing
        public int hashCode() {
            return (x == null ? 0 : x.hashCode() * 31) + (y == null ? 0 : y.hashCode());
        }

        // Override equals method for equality check
        public boolean equals(Object o) {
            if (this == o)
                return true; // Check if the same object
            if (o == null || getClass() != o.getClass())
                return false; // Check if the object is null or different class
            Pair<U, V> p = (Pair<U, V>) o;
            return (x == null ? p.x == null : x.equals(p.x)) && (y == null ? p.y == null : y.equals(p.y));
        }

        // Override compareTo method for comparison
        public int compareTo(Pair<U, V> b) {
            int cmpU = x.compareTo(b.x); // Compare first elements
            return cmpU != 0 ? cmpU : y.compareTo(b.y); // Compare second elements if first are equal
        }

        // Override toString method for string representation
        public String toString() {
            return String.format("(%s, %s)", x.toString(), y.toString());
        }
    }

    // Main method
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading data
        OutputStream outputStream = System.out; // Output stream for writing data
        FastReader sc = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        String s = sc.next(); // Read first string
        String t = sc.next(); // Read second string
        int count = 0; // Initialize count for differences

        // Loop through each character of the strings
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) != t.charAt(i)) {
                count++; // Increment count if characters are different
            }
        }
        w.print(count); // Print the count of differences
        w.close(); // Close the PrintWriter
    }
}

