public class Main{

	public static void main(String[] args) {

		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Read the first line of input which contains two integers n and m
		String input1 = sc.nextLine();
		String input2 = ""; // Initialize an empty string to store subsequent input lines
		String[] NM = input1.split(" "); // Split the input line into two parts based on space

		// Parse the first and second parts of the input as integers n and m
		int n = Integer.parseInt(NM[0]);
		int m = Integer.parseInt(NM[1]);

		// Initialize a boolean flag to check the validity of input values
		boolean judge = true;
		int value = 0; // Variable to store integer values parsed from input

		// Check if n and m are within the specified range
		if ((n >= 1 && n <= 100) && (m >= 1 && m <= 100)) {

			// Initialize a 2D array A with dimensions n x m
			int[][] A = new int[n][m];
			// Initialize arrays b and c to store m integers and n integers respectively
			int[] b = new int[m];
			int[] c = new int[n];

			// Temporary arrays to store string representations of input lines
			String[] AString = new String[m];
			String[] BString = new String[m];

			// Outer loop to read n lines of input for matrix A
			out: for (int i = 0; i < n; i++) {
				input2 = sc.nextLine(); // Read the next line of input
				AString = input2.split(" "); // Split the line into individual string numbers
				for (int j = 0; j < AString.length; j++) {
					value = Integer.parseInt(AString[j]); // Parse each string as an integer
					// Check if the value is within the valid range
					if (value < 0 || value > 1000) {
						judge = false; // Set judge to false if an invalid value is found
						break out; // Exit the loop if an invalid value is found
					}
					A[i][j] = value; // Assign the parsed value to the matrix A
				}
			}

			// If all values in matrix A are valid, proceed to read vector b
			if (judge == true) {

				// Loop to read m lines of input for vector b
				out: for (int i = 0; i < m; i++) {
					BString[i] = sc.nextLine(); // Read the next line of input
					value = Integer.parseInt(BString[i]); // Parse the string as an integer
					// Check if the value is within the valid range
					if (value < 0 || value > 1000) {
						judge = false; // Set judge to false if an invalid value is found
						break out; // Exit the loop if an invalid value is found
					}
					b[i] = value; // Assign the parsed value to the vector b
				}
			}

			// If all values in vector b are valid, proceed to calculate vector c
			if (judge == true) {
				// Loop through each row of matrix A
				for (int i = 0; i < n; i++) {
					// Loop through each column of matrix A
					for (int j = 0; j < m; j++) {
						// Calculate the dot product of row i of A and vector b
						c[i] += A[i][j] * b[j];
					}
				}

				// Output each element of vector c
				for (int k = 0; k < n; k++) {
					System.out.println(c[k]); // Print the result of the dot product for each row
				}
			}
		}
	}
