import java.util.Scanner;

public class Main {
  public static void main(String[] args) {
    // Create a Scanner object to read input from the standard input stream
    Scanner stdIn = new Scanner(System.in);
    try {
      // Read the first integer input which represents the count of +1 values
      int oneNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (oneNum < 0) return;

      // Read the second integer input which represents the count of 0 values
      int zeroNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (zeroNum < 0) return;

      // Read the third integer input which represents the count of -1 values
      int minusOneNum = stdIn.nextInt();
      // If the input is negative, terminate the program
      if (minusOneNum < 0) return;

      // Read the fourth integer input which represents the number of selections
      int selectNum = stdIn.nextInt();
      // Validate the selectNum input:
      // - It must be at least 1
      // - The total number of available numbers must be at least selectNum
      // - The total number of available numbers must not exceed 2 billion
      if (selectNum < 1 || (oneNum + zeroNum + minusOneNum) < selectNum || (oneNum + zeroNum + minusOneNum) > 2 * Math.pow(10, 9)) return;

      // Initialize maxValue to store the maximum sum possible
      int maxValue = 0;
      // Initialize restSelect to track the remaining selections
      int restSelect = selectNum;

      // Process the +1 values
      if (restSelect != 0) {
        // If the number of +1 values is less than or equal to the remaining selections
        if (oneNum <= restSelect) {
          // Add +1 for each available +1 value
          for (int oneCnt = 0; oneCnt < oneNum; oneCnt++) {
            maxValue++;
          }
          // Decrease the remaining selections by the number of +1 values used
          restSelect -= oneNum;
        } else {
          // If there are more +1 values than needed, use only the required amount
          for (int oneCnt = 0; oneCnt < restSelect; oneCnt++) {
            maxValue++;
          }
          // All selections are used up
          restSelect = 0;
        }
      }

      // Process the 0 values
      if (restSelect != 0) {
        // If the number of 0 values is less than or equal to the remaining selections
        if (zeroNum <= restSelect) {
          // Simply decrease the remaining selections by the number of 0 values used
          restSelect -= zeroNum;
        } else {
          // If there are more 0 values than needed, use only the required amount
          restSelect -= restSelect;
        }
      }

      // Process the -1 values
      if (restSelect != 0) {
        // If the number of -1 values is less than or equal to the remaining selections
        if (minusOneNum <= restSelect) {
          // Subtract 1 for each available -1 value
          for (int minusOneCnt = 0; minusOneCnt < minusOneNum; minusOneCnt++) {
            maxValue--;
          }
          // Decrease the remaining selections by the number of -1 values used
          restSelect -= minusOneNum;
        } else {
          // If there are more -1 values than needed, use only the required amount
          for (int minusOneCnt = 0; minusOneCnt < restSelect; minusOneCnt++) {
            maxValue--;
          }
          // All selections are used up
          restSelect -= restSelect;
        }
      }

      // Output the maximum value calculated
      System.out.println(maxValue);
    } catch (Exception e) {
      // Print the stack trace if an exception occurs
      e.printStackTrace();
    } finally {
      // Close the Scanner object to free up resources
      stdIn.close();
    }
  }
}

import java.io.IOException;
import java.io.InputStream;
import java.util.*;

public class Main {
    public static void main(String[] args){
        // Create an instance of FastScanner to read input
        FastScanner sc = new FastScanner();

        // Read an integer k from input
        int k = sc.nextInt();

        // Read a string s from input
        String s = sc.next();

        // Check if the length of the string s is less than or equal to k
        if(s.length() <= k) {
            // If true, print the entire string s
            System.out.println(s);
        } else {
            // If false, print the first k characters of s followed by "..."
            System.out.println(s.substring(0, k) + "...");
        }
    }

    // Custom scanner class for fast input reading
    static class FastScanner {
        // InputStream to read from standard input
        private final InputStream in = System.in;

        // Buffer to store bytes read from input
        private final byte[] buffer = new byte[1024];

        // Pointer to track the current position in the buffer
        private int ptr = 0;

        // Number of bytes currently in the buffer
        private int buflen = 0;

        // Check if there is a next byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    // Read bytes into the buffer
                    buflen = in.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                // Return false if no bytes were read
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() { 
            if (hasNextByte()) 
                return buffer[ptr++]; 
            else 
                return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) { 
            return 33 <= c && c <= 126;
        }

        // Check if there is a next token to read
        public boolean hasNext() { 
            while(hasNextByte() && !isPrintableChar(buffer[ptr])) 
                ptr++; 
            return hasNextByte();
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) 
                throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while(isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long
        public long nextLong() {
            if (!hasNext()) 
                throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while(true){
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if(b == -1 || !isPrintableChar(b)){
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an int
        public int nextInt() {
            long nl = nextLong();
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) 
                throw new NumberFormatException();
            return (int) nl;
        }

        // Read the next token as a double
        public double nextDouble() { 
            return Double.parseDouble(next());
        }
    }
}

