    // FastWriter class for efficient output handling
    static class FastWriter {
        private static final int IO_BUFFERS = 128 * 1024; // Buffer size
        private final StringBuilder out; // StringBuilder for accumulating output

        public FastWriter() {
            out = new StringBuilder(IO_BUFFERS);
        }

        // Append an object to the output
        public FastWriter p(Object object) {
            out.append(object);
            return this;
        }

        // Append formatted string to the output
        public FastWriter p(String format, Object... args) {
            out.append(String.format(format, args));
            return this;
        }

        // Append multiple objects to the output with spaces
        public FastWriter pp(Object... args) {
            for (Object ob : args) {
                out.append(ob).append(" ");
            }
            out.append("\n");
            return this;
        }

        // Append an object followed by a newline
        public FastWriter println(Object object) {
            out.append(object).append("\n");
            return this;
        }

        // Write the accumulated output to a file
        public void toFile(String fileName) throws IOException {
            BufferedWriter writer = new BufferedWriter(new FileWriter(fileName));
            writer.write(out.toString());
            writer.close();
        }

        // Print the accumulated output to the console
        public void close() throws IOException {
            System.out.print(out);
        }
    }

    // FastScanner class for efficient input handling
    static class FastScanner {
        private InputStream sin = System.in; // Input stream
        private final byte[] buffer = new byte[1024]; // Buffer for input
        private int ptr = 0; // Pointer in the buffer
        private int buflen = 0; // Length of valid data in buffer

        public FastScanner() {}

        // Constructor to read from a file
        public FastScanner(String filename) throws FileNotFoundException {
            File file = new File(filename);
            sin = new FileInputStream(file);
        }

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    buflen = sin.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Check if there is another token to read
        public boolean hasNext() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
            return hasNextByte();
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long
        public long longNext() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b) || b == ':') {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an int
        public int intNext() {
            long nl = longNext();
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Read the next token as a double
        public double doubleNext() {
            return Double.parseDouble(next());
        }

        // Read the next n tokens as a long array
        public long[] nextLongArray(final int n) {
            final long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = longNext();
            return a;
        }

        // Read the next n tokens as an int array
        public int[] nextIntArray(final int n) {
            final int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = intNext();
            return a;
        }

        // Initialize an adjacency list for a graph with n nodes
        public ArrayList<Integer>[] getAdj(int n) {
            ArrayList<Integer>[] adj = new ArrayList[n + 1];
            for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
            return adj;
        }

        // Create an adjacency list for a graph with n nodes and m edges
        public ArrayList<Integer>[] adjacencyList(int n, int m) throws IOException {
            adj = getAdj(n);
            for (int i = 0; i < m; i++) {
                int a = intNext(), b = intNext();
                adj[a].add(b);
                adj[b].add(a);
            }
            return adj;
        }
    }
}

import java.util.Scanner;

public class Main {

    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Continuously read input until there is no more input
        while (sc.hasNext()) {
            // Read the number of flavors (N) and the starting flavor (L)
            int N = sc.nextInt();
            int L = sc.nextInt();

            // Initialize an array to store the flavors
            int[] flavors = new int[N];
            // Initialize a variable to store the sum of selected flavors
            int sum = 0;

            // Populate the flavors array with values starting from L
            for (int i = 0; i < N; i++) {
                flavors[i] = L + i;
            }

            /* 
             * Check the conditions to determine which flavors to sum:
             * 1. If the first flavor is negative and the last flavor is zero or negative,
             *    sum all flavors except the last one.
             */
            if ((flavors[0] < 0 && flavors[N-1] == 0) || (flavors[0] < 0 && flavors[N-1] < 0) ){
                for (int i = 0; i < N - 1; i++)
                    sum += flavors[i];
            }
            /* 
             * 2. If the first flavor is zero and the last flavor is positive,
             *    or if both the first and last flavors are positive,
             *    sum all flavors except the first one.
             */
            else if ((flavors[0] == 0 && flavors[N-1] > 0) || (flavors[0] > 0 && flavors[N-1] > 0) ){
                for (int i = 1; i < N; i++) {
                    sum += flavors[i];
                }
            }
            /* 
             * 3. If the first flavor is negative and the last flavor is positive,
             *    sum all flavors except the one that is zero.
             */
            else if (flavors[0] < 0 && flavors[N-1] > 0){
                for (int i = 0; i < N; i++) {
                    if (flavors[i] == 0)
                        continue; // Skip the flavor that is zero
                    sum += flavors[i];
                }
            }

            // Output the calculated sum of selected flavors
            System.out.println(sum);
        }
    }
}

