public class Main {
    // Constant string for testing purposes
    private static final String TEST = "7 1 2 3 4 5 6 7";
    // Scanner object for reading input
    Scanner sc;

    // Number of elements in the sequence
    int N;
    // Array to store the sequence of numbers
    int[] p;

    // Default constructor initializing the scanner with standard input
    public Main() {
        sc = new Scanner(System.in);
    }

    // Constructor for testing with a predefined input string
    public Main(String input) {
        sc = new Scanner(input);
    }

    // Method to print output and flush the output stream
    void out(Object o) {
        System.out.println(o);
        System.out.flush();
    }

    // Main execution method
    public void exec() throws Exception {
        // Read the number of elements
        N = sc.nextInt();
        // Initialize the array with the given number of elements
        p = new int[N];
        // Populate the array with input values
        for (int i = 0; i < N; i++) {
            p[i] = sc.nextInt();
        }

        // Array to store indices where the sequence descends
        int[] descendIndex = new int[3];
        // Counter for the number of descending points
        int descendCnt = 0;

        // Loop through the array to find descending points
        for (int i = 0; i < N-1; i++) {
            if (p[i] > p[i+1]) { // Check if the current element is greater than the next
                descendIndex[descendCnt++] = i; // Store the index of the descending point
                if (descendCnt > 2) break; // Stop if more than 2 descending points are found
            }
        }

        int i, j;
        // Switch based on the number of descending points found
        switch (descendCnt) {

        case 0: // No descending points, sequence is already sorted
            out("YES");
            break;

        case 1: // One descending point, check if it can be fixed by swapping
            i = descendIndex[0];

            if (i != 0) { // Check if the element before the descending point is greater than the one after
                if (p[i-1] > p[i+1]) {
                    out("NO"); // Cannot fix by swapping
                    return;
                }
            }
            if (i < N-2) { // Check if the current element is greater than the one two positions ahead
                if (p[i] > p[i+2]) {
                    out("NO"); // Cannot fix by swapping
                    return;
                }
            }
            out("YES"); // Can fix by swapping
            return;

        case 2: // Two descending points, check if they can be fixed by swapping
            i = descendIndex[0];
            j = descendIndex[1];

            if (i != 0) { // Check if the element before the first descending point is greater than the one after the second
                if (p[i-1] > p[j+1]) {
                    out("NO"); // Cannot fix by swapping
                    return;
                }
            }
            if (p[j+1] > p[i+1]) { // Check if the element after the second descending point is greater than the one after the first
                out("NO"); // Cannot fix by swapping
                return;
            }
            if (j+1 < N-1) { // Check if the first descending element is greater than the element two positions after the second
                if (p[i] > p[j+2]) {
                    out("NO"); // Cannot fix by swapping
                    return;
                }
            }
            if (p[j] > p[i]) { // Check if the second descending element is greater than the first
                out("NO"); // Cannot fix by swapping
                return;
            }
            out("YES"); // Can fix by swapping
            return;

        default: // More than two descending points, cannot fix by a single swap
            out("NO");
            return;
        }
    }

    // Main method to run the program
    public static void main(String[] args) throws Exception {
        Main m = new Main();
        m.exec();
    }
}

