class FastScanner {
	// InputStream for reading input
	private final InputStream in = System.in;
	// Buffer for storing input bytes
	private final byte[] buffer = new byte[1024];
	// Pointer to the current position in the buffer
	private int ptr = 0;
	// Number of bytes currently in the buffer
	private int buflen = 0;

	// Check if there is another byte to read
	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true;
		} else {
			ptr = 0;
			try {
				// Read bytes into the buffer
				buflen = in.read(buffer);
			} catch (IOException e) {
				e.printStackTrace();
			}
			// Return false if no bytes were read
			if (buflen <= 0) {
				return false;
			}
		}
		return true;
	}

	// Read the next byte from the buffer
	private int readByte() {
		if (hasNextByte())
			return buffer[ptr++];
		else
			return -1;
	}

	// Check if a character is printable
	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126;
	}

	// Check if there is another token in the input
	public boolean hasNext() {
		// Skip non-printable characters
		while (hasNextByte() && !isPrintableChar(buffer[ptr]))
			ptr++;
		return hasNextByte();
	}

	// Read the next token as a String
	public String next() {
		if (!hasNext())
			throw new NoSuchElementException();
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		// Append characters to the StringBuilder until a non-printable character is found
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b);
			b = readByte();
		}
		return sb.toString();
	}

	// Read the next token as a long
	public long nextLong() {
		if (!hasNext())
			throw new NoSuchElementException();
		long n = 0;
		boolean minus = false;
		int b = readByte();
		// Check for negative sign
		if (b == '-') {
			minus = true;
			b = readByte();
		}
		// Ensure the first character is a digit
		if (b < '0' || '9' < b) {
			throw new NumberFormatException();
		}
		// Read digits and construct the number
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0';
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n;
			} else {
				throw new NumberFormatException();
			}
			b = readByte();
		}
	}

	// Read the next token as an int
	public int nextInt() {
		long nl = nextLong();
		// Check if the long value fits in an int
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
			throw new NumberFormatException();
		return (int) nl;
	}

	// Read the next token as a double
	public double nextDouble() {
		return Double.parseDouble(next());
	}

	// Read N integers into an array
	public int[] nextIntsN(int N) {
		int[] ints = new int[N];
		for (int i = 0; i < N; i++) {
			ints[i] = nextInt();
		}
		return ints;
	}

	// Read N long integers into an array
	public long[] nextLongsN(int N) {
		long[] longs = new long[N];
		for (int i = 0; i < N; i++) {
			longs[i] = nextLong();
		}
		return longs;
	}

	// Read N characters into an array
	public char[] nextCharsN(int N) {
		char[] chars = new char[N];
		String msg = next();
		for (int i = 0; i < N; i++) {
			chars[i] = msg.charAt(i);
		}
		return chars;
	}

	// Read a 2D array of characters with dimensions HxW
	public char[][] nextCharsHW(int H, int W) {
		char[][] chars = new char[H][W];
		for (int i = 0; i < H; i++) {
			String str = next();
			for (int j = 0; j < W; j++) {
				chars[i][j] = str.charAt(j);
			}
		}
		return chars;
	}

	// Read a 2D array of integers with dimensions NxM
	public int[][] nextIntsNM(int N, int M) {
		int[][] ints = new int[N][M];
		for (int i = 0; i < N; i++) {
			for (int j = 0; j < M; j++) {
				ints[i][j] = nextInt();
			}
		}
		return ints;
	}
}

