        int[] sum = new int[sp.length];

        // Initialize the first element of the sum array to 0
        sum[0] = 0;

        // Variable to keep track of the number of "AC" occurrences
        int count = 0;

        // Loop through the string to calculate the cumulative "AC" count
        for(int i = 1; i < N; i++) {
            // Check if the current and previous characters form "AC"
            if(sp[i-1].equals("A") && sp[i].equals("C")) {
                count++; // Increment the count
                sum[i-1] = count; // Update the sum array at the previous index
            }
            sum[i] = count; // Update the sum array at the current index
        }

        // Variables to store the current query's first and last indices
        int last = 0;
        int first = 0;

        // Variable to store the answer for each query
