                System.out.println(0);
            } else if(first == 0) { // Handle the case where the query starts from the beginning
                if(sum[last] == sum[last-1]) {
                    if(sum[first] == 0) {
                        System.out.println(sum[last]);
                    } else {
                        System.out.println(sum[last] - sum[first] + 1);
                    }
                } else {
