        // Create an instance of the Scan class to read input
        Scan sc = new Scan();

        // Read a string from input and convert it to a character array
        char[] carr = sc.scanString().toCharArray();

        // Initialize a stack to process the characters
        Stack<Character> st = new Stack<>();

        // Iterate over each character in the character array
        for(char c : carr){
            // If the character is not 'B', push it onto the stack
            if(c != 'B')
                st.push(c);
            else {
                // If the character is 'B' and the stack is not empty, pop the top character from the stack
                if(!st.isEmpty())
                    st.pop();
            }
        }

        // Use a StringBuilder to construct the final string from the stack
        StringBuilder sb= new StringBuilder();

        // Append each character from the stack to the StringBuilder
        for(char c : st)
            sb.append(c);

        // Print the resulting string
        System.out.println(sb);
    }
}

class Scan {
    // Buffer to store input bytes
    private byte[] buf = new byte[1024];
    // Current index in the buffer
    private int index;
    // Input stream to read from
    private InputStream in;
    // Total number of bytes read into the buffer
    private int total;

    // Constructor initializes the input stream to System.in
    public Scan() {
        in = System.in;
    }

    // Method to read the next byte from the input stream
    public int scan() throws IOException {
        // If total is negative, throw an exception indicating input mismatch
        if(total < 0)
            throw new InputMismatchException();

        // If the current index is greater than or equal to total, refill the buffer
        if(index >= total) {
            index = 0;
            total = in.read(buf);
            // If no bytes were read, return -1 indicating end of input
            if(total <= 0)
                return -1;
        }

        // Return the next byte from the buffer
        return buf[index++];
    }

    // Method to read an integer from the input
    public int scanInt() throws IOException {
        int integer = 0;
        int n = scan();

        // Skip any whitespace characters
        while(isWhiteSpace(n))
            n = scan();

        int neg = 1;
        // Check for negative sign
        if(n == '-') {
            neg = -1;
            n = scan();
        }

        // Read digits and construct the integer
        while(!isWhiteSpace(n)) {
            if(n >= '0' && n <= '9') {
                integer *= 10;
                integer += n - '0';
                n = scan();
            } else {
                throw new InputMismatchException();
            }
        }

        // Return the integer with the correct sign
        return neg * integer;
    }

    // Method to read a long integer from the input
    public long scanLong() throws IOException {
        long integer = 0;
        int n = scan();

        // Skip any whitespace characters
        while(isWhiteSpace(n))
            n = scan();

        int neg = 1;
        // Check for negative sign
        if(n == '-') {
            neg = -1;
            n = scan();
        }

        // Read digits and construct the long integer
        while(!isWhiteSpace(n)) {
            if(n >= '0' && n <= '9') {
                integer *= 10;
                integer += n - '0';
                n = scan();
            } else {
                throw new InputMismatchException();
            }
        }

        // Return the long integer with the correct sign
        return neg * integer;
    }

    // Method to read a double from the input
    public double scanDouble() throws IOException {
        double doub = 0;
        int n = scan();

        // Skip any whitespace characters
        while(isWhiteSpace(n))
            n = scan();

        int neg = 1;
        // Check for negative sign
        if(n == '-') {
            neg = -1;
            n = scan();
        }

        // Read digits before the decimal point
        while(!isWhiteSpace(n) && n != '.') {
            if(n >= '0' && n <= '9') {
                doub *= 10;
                doub += n - '0';
                n = scan();
            } else {
                throw new InputMismatchException();
            }
        }

        // Read digits after the decimal point
        if(n == '.') {
            n = scan();
            double temp = 1;
            while(!isWhiteSpace(n)) {
                if(n >= '0' && n <= '9') {
                    temp /= 10;
                    doub += (n - '0') * temp;
                    n = scan();
                } else {
                    throw new InputMismatchException();
                }
            }
        }

        // Return the double with the correct sign
        return doub * neg;
    }

    // Method to read a string from the input
    public String scanString() throws IOException {
        StringBuilder sb = new StringBuilder();
        int n = scan();

        // Skip any whitespace characters
        while(isWhiteSpace(n))
            n = scan();

        // Read characters until a whitespace is encountered
        while(!isWhiteSpace(n)) {
            sb.append((char)n);
            n = scan();
        }

        // Return the constructed string
        return sb.toString();
    }

    // Helper method to check if a character is a whitespace
    private boolean isWhiteSpace(int n) {
        if(n == ' ' || n == '\n' || n == '\r' || n == '\t' || n == -1)
            return true;
        return false;
    }
}

