            ans = Math.ceil((ans + ans * 0.05) / 1000) * 1000;
        }

        // Print the final result as an integer
        System.out.println((int)ans);
    }

    // Custom IO class extending PrintWriter for efficient input and output
    static class IO extends PrintWriter {
        private final InputStream in; // Input stream for reading data
        private final byte[] buffer = new byte[1024]; // Buffer for storing input data
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Constructor that initializes the IO with System.in as the input source
        IO() {
            this(System.in);
        }

        // Constructor that allows specifying a custom input source
        IO(InputStream source) {
            super(System.out); // Initialize PrintWriter with System.out
            this.in = source; // Set the input stream
        }

        // Check if there is another byte available in the buffer
        boolean hasNextByte() {
            if (ptr < buflen) return true; // If pointer is within buffer length, return true
            else {
                ptr = 0; // Reset pointer
                try {
                    buflen = in.read(buffer); // Read data into buffer
                } catch (IOException e) {
                    e.printStackTrace(); // Print stack trace if an exception occurs
                }
                if (buflen <= 0) return false; // Return false if no data was read
            }
            return true; // Return true if data is available
        }

        // Read the next byte from the buffer
        int readByte() {
            if (hasNextByte()) return buffer[ptr++]; // Return the next byte and increment pointer
            else return -1; // Return -1 if no byte is available
        }

        // Check if a character is printable
        boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126; // Return true if character is within printable ASCII range
        }

        // Skip non-printable characters in the buffer
        void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; // Increment pointer until a printable character is found
        }

        // Check if there is another token available
        boolean hasNext() {
            skipUnprintable(); // Skip non-printable characters
            return hasNextByte(); // Return true if there is another byte available
        }

        // Read the next long integer from input
        long nextLong() {
            if (!hasNext()) throw new NoSuchElementException(); // Throw exception if no more tokens
            long n = 0; // Initialize result
            boolean minus = false; // Flag for negative numbers
            int b = readByte(); // Read the first byte
            if (b == '-') {
                minus = true; // Set minus flag if negative
                b = readByte(); // Read the next byte
            }
            if (b < '0' || '9' < b) throw new NumberFormatException(); // Throw exception if not a digit
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10; // Multiply current result by 10
                    n += b - '0'; // Add the digit value
                } else if (b == -1 || !isPrintableChar(b)) return minus ? -n : n; // Return result if end of number
                else throw new NumberFormatException(); // Throw exception if invalid character
                b = readByte(); // Read the next byte
            }
        }

        // Read the next integer from input
        int nextInt() {
            long nl = nextLong(); // Read a long integer
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException(); // Check for overflow
            return (int) nl; // Return as integer
        }

        // Close the IO streams
        public void close() {
            super.close(); // Close PrintWriter
            try {
                in.close(); // Close input stream
            } catch (IOException ignored) {
                // Ignore exceptions during close
            }
        }
    }
}

