public class Main {
   public static void main(String[] args) {
      // Initialize input and output streams
      InputStream inputStream = System.in;
      OutputStream outputStream = System.out;

      // Create InputReader and OutputWriter objects for handling input and output
      InputReader in = new InputReader(inputStream);
      OutputWriter out = new OutputWriter(outputStream);

      // Create an instance of the solver class and solve the problem
      BResistorsInParallel solver = new BResistorsInParallel();
      solver.solve(1, in, out);

      // Close the output writer to release resources
      out.close();
   }

   static class BResistorsInParallel {
      public void solve(int testNumber, InputReader in, OutputWriter out) {
         // Read the number of resistors
         int n = in.nextInt();
         double a = 0;

         // Calculate the sum of the reciprocals of the resistances
         for (int x = 0; x < n; x++) {
            a += (1.0 / in.nextDouble());
         }

         // Output the reciprocal of the sum, which is the equivalent resistance
         out.println(1 / a);
      }
   }

   static class InputReader {
      private InputStream stream;
      private byte[] buf = new byte[1024]; // Buffer for reading input
      private int curChar; // Current character index in the buffer
      private int numChars; // Number of characters read into the buffer
      private InputReader.SpaceCharFilter filter; // Optional filter for space characters

      public InputReader(InputStream stream) {
         this.stream = stream;
      }

      public int read() {
         // If no more characters are available, throw an exception
         if (numChars == -1) {
            throw new InputMismatchException();
         }
         // If current character index exceeds the number of characters, read more
         if (curChar >= numChars) {
            curChar = 0;
            try {
               numChars = stream.read(buf);
            } catch (IOException e) {
               throw new InputMismatchException();
            }
            // If no characters were read, return -1 indicating end of stream
            if (numChars <= 0) {
               return -1;
            }
         }
         // Return the next character from the buffer
         return buf[curChar++];
      }

      public int nextInt() {
         int c = read();
         // Skip any whitespace characters
         while (isSpaceChar(c)) {
            c = read();
         }
         int sgn = 1;
         // Check for negative sign
         if (c == '-') {
            sgn = -1;
            c = read();
         }
         int res = 0;
         // Read the integer value
         do {
            if (c < '0' || c > '9') {
               throw new InputMismatchException();
            }
            res *= 10;
            res += c - '0';
            c = read();
         } while (!isSpaceChar(c));
         return res * sgn;
      }

      public boolean isSpaceChar(int c) {
         if (filter != null) {
            return filter.isSpaceChar(c);
         }
         return isWhitespace(c);
      }

      public static boolean isWhitespace(int c) {
         // Check if the character is a whitespace character
         return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
      }

      public double nextDouble() {
         int c = read();
         // Skip any whitespace characters
         while (isSpaceChar(c)) {
            c = read();
         }
         int sgn = 1;
         // Check for negative sign
         if (c == '-') {
            sgn = -1;
            c = read();
         }
         double res = 0;
         // Read the integer part of the double
         while (!isSpaceChar(c) && c != '.') {
            if (c == 'e' || c == 'E') {
               return res * Math.pow(10, nextInt());
            }
            if (c < '0' || c > '9') {
               throw new InputMismatchException();
            }
            res *= 10;
            res += c - '0';
            c = read();
         }
         // Read the fractional part of the double
         if (c == '.') {
            c = read();
            double m = 1;
            while (!isSpaceChar(c)) {
               if (c == 'e' || c == 'E') {
                  return res * Math.pow(10, nextInt());
               }
               if (c < '0' || c > '9') {
                  throw new InputMismatchException();
               }
               m /= 10;
               res += (c - '0') * m;
               c = read();
            }
         }
         return res * sgn;
      }

      public interface SpaceCharFilter {
         public boolean isSpaceChar(int ch);
      }
   }

   static class OutputWriter {
      private final PrintWriter writer;

      public OutputWriter(OutputStream outputStream) {
         // Initialize PrintWriter with a BufferedWriter for efficient output
         writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
      }

      public OutputWriter(Writer writer) {
         this.writer = new PrintWriter(writer);
      }

      public void print(Object... objects) {
         // Print each object separated by a space
         for (int i = 0; i < objects.length; i++) {
            if (i != 0) {
               writer.print(' ');
            }
            writer.print(objects[i]);
         }
      }

      public void println(Object... objects) {
         // Print objects followed by a newline
         print(objects);
         writer.println();
      }

      public void close() {
         // Close the writer to release resources
         writer.close();
      }
   }
}

import java.io.*;
