public class Main {

    public static void main(String[] args) throws IOException {
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Create InputReader and OutputWriter objects for handling input and output
        InputReader in = new InputReader(inputStream);
        InputReader.OutputWriter out = new InputReader.OutputWriter(outputStream);

        // Read three integers from input
        int a = in.nextInt();
        int b = in.nextInt();
        int c = in.nextInt();

        // Calculate the minimum sum of any two of the three integers
        int min = Math.min(Math.min(a+b, b+c), c+a);

        // Print the minimum sum
        out.println(min);

        // Flush the output stream to ensure all data is written out
        out.flush();
    }

    // Breadth-First Search (BFS) method to find the shortest path to a target 'Y' in a 2D grid
    private static int bfs(char[][] c, int i, int j, int length, boolean[][] visited) {
        // Queue to hold points to be explored
        LinkedList<Point> q = new LinkedList<>();
        q.add(new Point(i, j)); // Add starting point to the queue
        int distance = 0; // Initialize distance counter

        // Continue until there are no more points to explore
        while (!q.isEmpty()) {
            int size = q.size(); // Number of points to explore at the current distance
            for (int k = 0; k < size; k++) {
                Point current = q.pollFirst(); // Get the next point from the queue
                visited[current.getI()][current.getJ()] = true; // Mark the current point as visited

                // Explore the upward direction
                int up = current.getI() - 1;
                if (up >= 0) {
                    if (!visited[up][current.getJ()]) {
                        if (c[up][current.getJ()] == 'Y') return distance + 1; // Target found
                        else q.add(new Point(up, current.getJ())); // Add to queue for further exploration
                    }
                }

                // Explore the downward direction
                int down = current.getI() + 1;
                if (down < c.length) {
                    if (!visited[down][current.getJ()]) {
                        if (c[down][current.getJ()] == 'Y') return distance + 1; // Target found
                        else q.add(new Point(down, current.getJ())); // Add to queue for further exploration
                    }
                }

                // Explore the left direction
                int left = current.getJ() - 1;
                if (left >= 0) {
                    if (!visited[current.getI()][left]) {
                        if (c[current.getI()][left] == 'Y') return distance + 1; // Target found
                        else q.add(new Point(current.getI(), left)); // Add to queue for further exploration
                    }
                }

                // Explore the right direction
                int right = current.getJ() + 1;
                if (right < c[i].length) {
                    if (!visited[current.getI()][right]) {
                        if (c[current.getI()][right] == 'Y') return distance + 1; // Target found
                        else q.add(new Point(current.getI(), right)); // Add to queue for further exploration
                    }
                }
            }
            distance++; // Increment distance after exploring all points at the current distance
        }
        return Integer.MAX_VALUE; // Return a large value if target 'Y' is not found
    }
}

