        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read a string input from the user
        String S = sc.next();
        // Get the length of the input string
        int l = S.length();
        // Initialize a variable to keep track of the maximum length of a valid substring
        int max = 0;
        // Define a string containing the valid characters
        String X = "ACGT";
        // Extract individual characters from the string X for easy comparison
        char A = X.charAt(0);
        char C = X.charAt(1);
        char G = X.charAt(2);
        char T = X.charAt(3);

        // Iterate over all possible starting points of substrings
        for (int i = 0; i < l - 1; i++) {
            // Iterate over all possible ending points of substrings
            for (int j = i + 2; j <= l; j++) {
                // Extract the substring from the main string
                String sub = S.substring(i, j);
                // Get the length of the current substring
                int lsub = sub.length();
                // Check each character in the substring
                for (int k = 0; k < lsub; k++) {
                    // If the character is one of A, C, G, or T, continue checking
                    if (sub.charAt(k) == A || sub.charAt(k) == C || sub.charAt(k) == G || sub.charAt(k) == T) {
                        // Do nothing, just continue
                    } else {
                        // If any character is not A, C, G, or T, break out of the loop
                        break;
                    }
                    // If the loop completes without breaking, update the max length
                    if (k == lsub - 1) {
                        max = Math.max(max, lsub);
                    }
                }
            }
        }
        // If a valid substring longer than 1 was found, print its length
        if (max > 1) {
            System.out.println(max);
        }
        // If no valid substring longer than 1 was found
        else if (max == 0) {
            // Check if there is at least one valid character in the string
            for (int i = 0; i < l; i++) {
                if (S.charAt(i) == A || S.charAt(i) == C || S.charAt(i) == G || S.charAt(i) == T) {
                    // If found, set max to 1 and print it
                    max = 1;
                    System.out.println(max);
                    break;
                }
            }
        }
        // If no valid characters were found, print 0
        if (max == 0) {
            System.out.println(max);
        }
    }
}

