public class Main {
    public static void main (String[] args) throws java.lang.Exception {
        // Create an InputReader object to read input from standard input (System.in)
        InputReader in = new InputReader(System.in);
        // Create a PrintWriter object to write output to standard output (System.out)
        PrintWriter w = new PrintWriter(System.out);

        // Initialize the answer counter to 0
        int ans = 0;
        // Read two integers from input: a and b
        int a = in.nextInt(), b = in.nextInt();

        // Iterate over the range from a to b (inclusive)
        for (int i = a; i <= b; i++) {
            // Check if the current number i is a palindrome
            if (is_pal(i))
                // If it is a palindrome, increment the answer counter
                ans++;
        }

        // Print the total count of palindromic numbers in the range
        w.println(ans);

        // Close the PrintWriter to release resources
        w.close();
    }

    // Method to check if a given integer n is a palindrome
    static boolean is_pal(int n) {
        // Convert the integer to a string
        String x = Integer.toString(n);
        // Iterate over the first half of the string
        for (int i = 0; i < (x.length() / 2); i++) {
            // Compare characters from the start and end moving towards the center
            if (x.charAt(i) != x.charAt(x.length() - 1 - i))
                // If any characters do not match, return false
                return false;
        }
        // If all characters match, return true
        return true;
    }

    // Custom InputReader class to handle input operations
    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer

        // Constructor to initialize the InputReader with an InputStream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1)
                throw new UnknownError(); // Error if no more characters are available
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read data into the buffer
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new UnknownError(); // Error if reading fails
                }
                if (numChars <= 0)
                    return -1; // End of stream
            }
            return buf[curChar++]; // Return the next character
        }

        // Method to peek at the next byte of input without advancing the cursor
        public int peek() {
            if (numChars == -1)
                return -1; // End of stream
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    return -1; // Error if reading fails
                }
                if (numChars <= 0)
                    return -1; // End of stream
            }
            return buf[curChar]; // Return the next character
        }

        // Method to skip a specified number of characters
        public void skip(int x) {
            while (x-- > 0)
                read(); // Read and discard characters
        }

        // Method to read the next integer from input
        public int nextInt() {
            return Integer.parseInt(next()); // Parse the next token as an integer
        }

        // Method to read the next long integer from input
        public long nextLong() {
            return Long.parseLong(next()); // Parse the next token as a long integer
        }

        // Method to read the next string from input
        public String nextString() {
            return next(); // Return the next token as a string
        }

        // Method to read the next token from input
        public String next() {
            int c = read();
            // Skip any leading whitespace characters
            while (isSpaceChar(c))
                c = read();
            StringBuffer res = new StringBuffer();
            // Read characters until a space character is encountered
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString(); // Return the token as a string
        }

        // Method to read the next line of input
        public String nextLine() {
            StringBuffer buf = new StringBuffer();
            int c = read();
            // Read characters until a newline character is encountered
            while (c != '\n' && c != -1) {
                if (c != '\r') // Ignore carriage return characters
                    buf.appendCodePoint(c);
                c = read();
            }
            return buf.toString(); // Return the line as a string
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read();
            // Skip any leading whitespace characters
            while (isSpaceChar(c))
                c = read();
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Negative number
                c = read();
            }
            double res = 0;
            // Read the integer part of the number
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Error if not a digit
                res *= 10;
                res += c - '0';
                c = read();
            }
            // Read the fractional part of the number
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Error if not a digit
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn; // Return the parsed double value
        }

        // Method to read an array of integers from input
        public int[] nextIntArray(int n) {
            int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = nextInt(); // Read each integer into the array
            return a;
        }

        // Method to read an array of long integers from input
        public long[] nextLongArray(int n) {
            long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = nextLong(); // Read each long integer into the array
            return a;
        }

        // Method to check if there is more input available
        public boolean hasNext() {
            int value;
            // Skip any whitespace characters and check if there is more input
            while (isSpaceChar(value = peek()) && value != -1)
                read();
            return value != -1; // Return true if more input is available
        }

        // Method to check if a character is a whitespace character
        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }
    }
}

