import java.io.*;
import java.util.*;

public class Main {

    public static void main(String[] args) {

        // Create an instance of FastScanner to read input
        FastScanner fs = new FastScanner();

        // Read an integer from input which represents the radius
        int r = fs.nextInt();

        // Calculate and print the circumference of a circle with radius r
        // using the formula: circumference = 2 * π * r
        // Here, π is approximated as 3.141592
        System.out.println(r * 2 * 3.141592);
    }

    // FastScanner class for fast input reading
    static class FastScanner {
        // InputStream to read from standard input
        private final InputStream in = System.in;
        // Buffer to store bytes read from input
        private final byte[] buffer = new byte[1024];
        // Pointer to track the current position in the buffer
        private int ptr = 0;
        // Length of valid data in the buffer
        private int bufferLength = 0;

        // Check if there is another byte to read in the buffer
        private boolean hasNextByte() {
            if (ptr < bufferLength) {
                return true;
            } else {
                ptr = 0;
                try {
                    // Read more bytes into the buffer
                    bufferLength = in.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                return bufferLength > 0;
            }
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) {
                return buffer[ptr++];
            } else {
                return -1; // Return -1 if no more bytes are available
            }
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Check if there is another token to read
        boolean hasNext() {
            // Skip non-printable characters
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
                ptr++;
            }
            return hasNextByte();
        }

        // Read the next token as a String
        String next() {
            if (!hasNext()) {
                throw new NoSuchElementException();
            }
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            // Append characters to the StringBuilder until a non-printable character is encountered
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long integer
        long nextLong() {
            if (!hasNext()) {
                throw new NoSuchElementException();
            }
            long n = 0;
            boolean minus = false;
            int b = readByte();
            // Check for negative sign
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            // Ensure the first character is a digit
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            // Read digits and construct the number
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an integer
        public int nextInt() {
            long nl = nextLong();
            // Check if the long value fits within the integer range
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) {
                throw new NumberFormatException();
            }
            return (int) nl;
        }

        // Read the next token as a double
        public double nextDouble() {
            return Double.parseDouble(next());
        }
    }

    // Method to calculate the greatest common divisor (GCD) of two integers
    private static int gcd(int a, int b) {
        int x;
        int y;
        // Determine which number is larger
        if (a > b) {
            x = a;
            y = b;
        } else {
            x = b;
            y = a;
        }
        int tmp;
        // Use the Euclidean algorithm to find the GCD
        while ((tmp = x % y) != 0) {
            x = y;
            y = tmp;
        }
        return y; // Return the GCD
    }

}

