class Main {
  public static void main(String[] args) {
    // Create a Scanner object to read input from the standard input stream
    java.util.Scanner sc = new java.util.Scanner(System.in);

    // Read a string input from the user
    String S = sc.next();

    // Read a long integer input from the user
    long K = sc.nextLong();

    // Iterate over each character in the string S
    for (int i = 0; i < S.length(); i++) {
      // Switch statement to handle different characters in the string
      switch (S.charAt(i)) {
        // Case when the character is '1'
        case '1':
          // Decrement K by 1
          K -= 1;
          // If K is still greater than 0, continue to the next iteration
          if (K > 0) continue;
          // If K is not greater than 0, print '1' and exit the method
          println('1');
          return;

        // Default case for any character other than '1'
        default:
          // Print the current character and exit the method
          println(S.charAt(i));
          return;
      }
    }
  }

  /* 
   * Overloaded print methods for different data types.
   * Each method prints the input to the standard output and flushes the stream.
   */
  static public void print(byte what) { System.out.print(what); System.out.flush(); }
  static public void print(boolean what) { System.out.print(what); System.out.flush(); }
  static public void print(char what) { System.out.print(what); System.out.flush(); }
  static public void print(int what) { System.out.print(what); System.out.flush(); }
  static public void print(long what) { System.out.print(what); System.out.flush(); }
  static public void print(float what) { System.out.print(what); System.out.flush(); }
  static public void print(double what) { System.out.print(what); System.out.flush(); }
  static public void print(String what) { System.out.print(what); System.out.flush(); }

  // Overloaded print method for a variable number of Object arguments
  static public void print(Object... variables) { 
    StringBuilder sb = new StringBuilder(); 
    for (Object o : variables) { 
      if (sb.length() != 0) { 
        sb.append(" "); 
      } 
      if (o == null) { 
        sb.append("null"); 
      } else { 
        sb.append(o.toString()); 
      } 
    } 
    System.out.print(sb.toString()); 
  }

  /* 
   * Overloaded println methods for different data types.
   * Each method prints the input followed by a newline and flushes the stream.
   */
  static public void println() { System.out.println(); }
  static public void println(byte what) { System.out.println(what); System.out.flush(); }
  static public void println(boolean what) { System.out.println(what); System.out.flush(); }
