  static public void println(double what) { System.out.println(what); System.out.flush(); }
  static public void println(String what) { System.out.println(what); System.out.flush(); }

  // Overloaded println method for a variable number of Object arguments
  static public void println(Object... variables) { 
    print(variables); 
    println(); 
  }

  // Overloaded println method for a single Object argument
  static public void println(Object what) { 
    if (what == null) { 
      System.out.println("null"); 
    } else if (what.getClass().isArray()) { 
      printArray(what); 
    } else { 
      System.out.println(what.toString()); 
      System.out.flush(); 
    } 
  }

  // Method to print arrays of various types
  static public void printArray(Object what) { 
