			}
		}

		// Calculate the number of multiples of D in the range [A, B]
		if(A % D != 0) {
			if(A > D) {
				d = (B - (A / D + 1) * D) / D + 1;
			} else {
				if(D <= B) {
					d = (B - D) / D + 1;
				} else {
					d = 0;
				}
			}
		} else {
			if(A > D) {
				d = (B - A) / D + 1;
			} else {
				if(D <= B) {
					d = (B - D) / D + 1;
				} else {
					d = 0;
				}
			}
		}

		// Calculate the number of multiples of both C and D (i.e., multiples of LCM(C, D)) in the range [A, B]
		if(A % koub != 0) {
			if(A > koub) {
				cd = (B - (A / koub + 1) * koub) / koub + 1;
			} else {
				if(koub <= B) {
					cd = (B - koub) / koub + 1;
				} else {
					cd = 0;
				}
			}
		} else {
			if(A > koub) {
				cd = (B - A) / koub + 1;
			} else {
				if(koub <= B) {
					cd = (B - koub) / koub + 1;
				} else {
					cd = 0;
				}
			}
		}

		// Print the count of numbers in the range [A, B] that are not divisible by either C or D
		System.out.println(B - A + 1 - c - d + cd);
	}

	// Method to calculate the greatest common divisor (GCD) of two numbers using the Euclidean algorithm
	public static long gcd(long a, long b) {
		if(b == 0) {
			return a;
		}
		return gcd(b, a % b);
	}
}

