public class Main {
    public static void main(String[] args) {
        // Create input and output streams for reading from standard input and writing to standard output
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Initialize custom InputReader and OutputWriter for handling input and output
        InputReader in = new InputReader(inputStream);
        OutputWriter out = new OutputWriter(outputStream);

        // Create an instance of the problem solver class and solve the problem
        CAlchemist solver = new CAlchemist();
        solver.solve(1, in, out);

        // Close the output writer to release resources
        out.close();
    }

    static class CAlchemist {
        public void solve(int testNumber, InputReader in, OutputWriter out) {
            // Read the number of elements
            int n = in.readInt();

            // Initialize an array to store the elements
            double[] a = new double[n];

            // Read each element into the array
            for (int i = 0; i < n; i++) {
                a[i] = in.readDouble();
            }

            // Sort the array to facilitate the merging process
            Arrays.sort(a);

            // Initialize the sum with the average of the first two elements
            double sum = (a[0] + a[1]) / 2.0;

            // Iteratively merge the elements by averaging with the current sum
            for (int j = 2; j < n; j++) {
                sum = (sum + a[j]) / 2.0;
                a[j] = sum; // Update the current element with the new sum
            }

            // Output the final result
            out.printLine(sum);
        }
    }

    static class OutputWriter {
        private final PrintWriter writer;

        // Constructor to initialize the writer with an OutputStream
        public OutputWriter(OutputStream outputStream) {
            writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
        }

        // Constructor to initialize the writer with a Writer object
        public OutputWriter(Writer writer) {
            this.writer = new PrintWriter(writer);
        }

        // Method to print multiple objects separated by spaces
        public void print(Object... objects) {
            for (int i = 0; i < objects.length; i++) {
                if (i != 0) {
                    writer.print(' ');
                }
                writer.print(objects[i]);
            }
        }

        // Method to print multiple objects followed by a newline
        public void printLine(Object... objects) {
            print(objects);
            writer.println();
        }

        // Method to close the writer and release resources
        public void close() {
            writer.close();
        }
    }

    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer for reading input
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private InputReader.SpaceCharFilter filter;

        // Constructor to initialize the InputReader with an InputStream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next character from the input
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    return -1;
                }
            }
            return buf[curChar++];
        }

        // Method to read an integer from the input
        public int readInt() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c);
            }
            return isWhitespace(c);
        }

        // Static method to check if a character is whitespace
        public static boolean isWhitespace(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Method to read a double value from the input
        public double readDouble() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    return res * Math.pow(10, readInt());
                }
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, readInt());
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Interface for defining custom space character filters
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }
}

