        if ('-' == S.charAt(A)) {
            // Loop through the first A characters of the string
            for (int i = 0; A > i; i++) {
                // Check if the current character is a digit (0-9)
                if (ans[i] == '0' || ans[i] == '1' || ans[i] == '2' || ans[i] == '3' || ans[i] == '4' || ans[i] == '5' || ans[i] == '6' || ans[i] == '7' || ans[i] == '8' || ans[i] == '9') {
                    // If it is a digit, continue to the next character
                } else {
                    // If it is not a digit, set A1 to 1 and break the loop
                    A1 = 1;
                    break;
                }
            }
            // Loop through the next B characters after the hyphen
            for (int j = 0; B > j; j++) {
                // Check if the current character is a digit (0-9)
                if (ans[A + 1 + j] == '0' || ans[j + A + 1] == '1' || ans[j + A + 1] == '2' || ans[j + A + 1] == '3' || ans[j + A + 1] == '4' || ans[j + A + 1] == '5' || ans[j + A + 1] == '6' || ans[j + A + 1] == '7' || ans[j + A + 1] == '8' || ans[j + A + 1] == '9') {
