public class Main {
    public static void main(String[] args) {
        // Create an instance of FastScanner to read input
        FastScanner fsc = new FastScanner();

        // Read the next input as a string and convert it to a character array
        char[] s = fsc.next().toCharArray();

        // Initialize two pointers: f for the front and b for the back
        int f = 0, b = s.length - 1;

        // Move the front pointer forward until it finds the character 'A'
        while (s[f] != 'A') {
            f++;
        }

        // Move the back pointer backward until it finds the character 'Z'
        while (s[b] != 'Z') {
            b--;
        }

        // Calculate and print the length of the substring from 'A' to 'Z', inclusive
        System.out.println(b - f + 1);
