class FastScanner {
    // InputStream to read from standard input
    private final InputStream in = System.in;

    // Buffer to store bytes read from the input stream
    private final byte[] buffer = new byte[1024];

    // Pointer to the current position in the buffer
    private int ptr = 0;

    // Number of bytes currently in the buffer
    private int buflen = 0;

    // Check if there is another byte available in the buffer
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                // Read more bytes into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no more bytes are available
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte()) return buffer[ptr++];
        else return -1;
    }

    // Check if a character is printable (ASCII range 33 to 126)
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Check if there is a next token available
    public boolean hasNext() {
        while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) throw new NoSuchElementException();
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder until a non-printable character is found
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long integer
    public long nextLong() {
        if (!hasNext()) throw new NoSuchElementException();
        long n = 0;
        boolean minus = false;
        int b = readByte();

        // Check for a negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }

        // Ensure the next character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }

        // Convert the sequence of digits into a long integer
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an integer
    public int nextInt() {
        long nl = nextLong();
        // Ensure the long value fits within the integer range
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next());
    }
}

import java.util.*;
import java.io.*;

// Suppress warnings for unused imports or variables
@SuppressWarnings("unused")
public class Main {
    // Fast input scanner
    FastScanner in;
    // Output writer
    PrintWriter out;
    // Modulo constant
    int MOD = (int)1e9+7;

    // Method to calculate the ceiling of a/b
    long ceil(long a, long b) {
        return (a + b - 1) / b;
    }

    // Method to calculate the greatest common divisor (GCD) using Euclidean algorithm
    long gcd(long a, long b) {
        return b == 0 ? a : gcd(b, a % b);
    }

    // Method to calculate the least common multiple (LCM)
    long lcm(long a, long b) {
        return a / gcd(a, b) * b;
    }

    // Main problem-solving method
    void solve() {
        // Read the number of elements
        int N = in.nextInt();
        // Read the array of integers
        int[] X = in.nextIntArray(N);
        // Initialize minimum sum of squares to a large value
        long min = Long.MAX_VALUE;

        // Iterate over possible values of x from 1 to 100
        for(int x = 1; x <= 100; x++) {
            long sum = 0;
            // Calculate the sum of squared differences for each element in X
            for(int i = 0; i < N; i++) {
                sum += (X[i] - x) * (X[i] - x);
            }
            // Update the minimum sum if the current sum is smaller
            min = Math.min(min, sum);
        }
        // Output the minimum sum of squares
        out.println(min);
    }

    // Main method to start the program
    public static void main(String[] args) {
        new Main().m();
    }

    // Method to initialize input and output streams and call the solve method
    private void m() {
        in = new FastScanner(System.in);
        out = new PrintWriter(System.out);

        // Solve the problem
        solve();
        // Flush the output stream
        out.flush();
        // Close input and output streams
        in.close();
        out.close();
    }

    // Custom fast scanner class for efficient input handling
    static class FastScanner {
        private Reader input;

        // Constructor with default input stream
        public FastScanner() {
            this(System.in);
        }

        // Constructor with specified input stream
        public FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Close the input stream
        public void close() {
            try {
                this.input.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // Read the next integer from input
        public int nextInt() {
            return (int) nextLong();
        }

        // Read the next long integer from input
        public long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                long ret = b - '0';
                // Read the number
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Read the next double from input
        public double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                double ret = b - '0';
                // Read the integer part
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }
                // Read the fractional part
