import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {

    public static void main(String[] a) {

        // Declare a string variable to hold each line of input
        String str;

        // Create a BufferedReader object to read input from the console
        BufferedReader bf = new BufferedReader(new InputStreamReader(System.in));

        try {
            // Continuously read lines from the input until a null value is encountered
            while (null != (str = bf.readLine())) {
                // Convert the input string to a character array
                char[] cArr = str.toCharArray();

                // Get the length of the character array
                int len = cArr.length;

                // Reverse the character array in place
                // Iterate only through the first half of the array
                for (int i = 0; i < len / 2; i++) {
                    // Swap the characters at positions i and len-i-1
                    char tmp = cArr[i];
                    cArr[i] = cArr[len - i - 1];
                    cArr[len - i - 1] = tmp;
                }

                // Print the reversed character array
                for (char c : cArr) {
                    System.out.print(c);
                }

                // Print a newline character after each reversed string
                System.out.println("");
            }
        } catch (IOException e) {
            // Print the stack trace if an IOException occurs
            e.printStackTrace();
        } finally {
            // Ensure the BufferedReader is closed to release system resources
            try {
                bf.close();
            } catch (IOException e) {
                // Handle potential IOException during the closing of BufferedReader
            }
        }
    }

}

