class Main {

	public static void main (String [] a){

		// Number of mountains to process
		int numMountain = 10;
		// Minimum and maximum constraints for mountain height
		int minConst = 0;
		int maxConst = 10000;
		// Array to store the heights of the mountains
		int[] mountainList = new int[numMountain];
		// Variables to store the top three highest mountains
		int topOne = 0;
		int topTwo = 0;
		int topThree = 0;

		// BufferedReader to read input from the console
		BufferedReader stdin = new BufferedReader(new InputStreamReader(System.in));
		String line;
		int i = 0;

		try {
			// Read input until the number of mountains is reached or input is null/empty
			while (i < numMountain && (line = stdin.readLine()) != null && 
					line.length()!= 0 ) {

					try {
						// Parse the input line to an integer representing mountain height
						int tempHeight = Integer.parseInt(line);
						// Check if the height is within the valid range
						if (tempHeight < minConst || tempHeight > maxConst) {
							// If not, ignore this input
						} else {
							// Store the valid height in the mountain list
							mountainList[i] = tempHeight;
							i++;
						}
					} catch (NumberFormatException e){
						// Ignore invalid input that cannot be parsed to an integer
					}

			}

			// Determine the top three highest mountains
			for (int j=0; j<numMountain; j++){
				if (mountainList[j] >= topOne){
					// Shift down the top two and top three if a new highest is found
					topThree = topTwo;
					topTwo = topOne;
					topOne = mountainList[j];
				} else if (mountainList[j] >= topTwo){
					// Shift down the top three if a new second highest is found
					topThree = topTwo;
					topTwo = mountainList[j];
				} else if (mountainList[j] >= topThree){
					// Update the third highest if a new third highest is found
					topThree = mountainList[j];
				}
			}

			// Output the top three highest mountain heights
			System.out.println(topOne +"\n"+ topTwo +"\n"+ topThree);
		} catch (IOException e) {
			// Handle potential IOExceptions from reading input
		}
	}
