        // Initialize a variable to represent the first occurrence count
        long first = 1;
        // Create a HashMap to store the frequency string and its occurrence count
        Map<String, Long> map = new HashMap<>();

        // Loop through each frequency string
        for(int i = 0; i < N; i++){
            // If the frequency string is already in the map, increment its count
            if(map.containsKey(str2[i])){
                map.put(str2[i], map.get(str2[i])+first);
            } else {
                // Otherwise, add the frequency string to the map with an initial count
                map.put(str2[i], first);
            }
        }

        // Calculate the number of valid combinations using the values in the map
        for(long val: map.values()){
            count += comb2(val);
