		long b = a / 15;
		// Calculate the remainder when 'a' is divided by 15
		long c = a % 15;

		/* 
		 * Calculate the contribution of complete groups of 15 to the answer.
		 * Each complete group of 15 contributes a specific value calculated by the formula:
		 * ((b * (b + 1)) * 60 - 60 * b)
		 * This formula is derived from a pattern or sequence specific to the problem.
		 */
		ans += ((b * (b + 1)) * 60 - 60 * b);

		// Calculate the base value for the current group of 15
		long x =  b * 15;

		// Add contributions based on the remainder 'c'
		if(c == 0) {
			// If remainder is 0, no additional contribution is needed
			ans += 0;
		} else if(c == 1) {
			// If remainder is 1, add the base value plus 1
			ans += x + 1;
		} else if(c == 2 || c == 3) {
			// If remainder is 2 or 3, add contributions for 1 and 2
			ans += x + 1 + x + 2;
		} else if(c == 4 || c == 5 || c == 6) {
			// If remainder is 4, 5, or 6, add contributions for 1, 2, and 4
			ans += x + 1 + x + 2 + x + 4;
