	// Constant MOD value, often used in competitive programming for modulo operations
	final int MOD = (int)1e9+7;

	// Main solving function
	void solve() throws Exception {
		// Read the number of points N and the dimension D
		int N = in.nextInt(), D = in.nextInt();
		// Initialize a 2D array to store the coordinates of N points in D dimensions
		int[][] X = new int[N][D];
		// Read the coordinates for each point
		for(int i = 0; i < N; i++){
			for(int j = 0; j < D; j++){
				X[i][j] = in.nextInt();
			}
		}

		// Counter for the number of pairs with integer distance
		int cnt = 0;
		// Iterate over all pairs of points
		for(int i = 0; i < N-1; i++){
			for(int j = i+1; j < N; j++){
				// Calculate the squared distance between points i and j
				long d2 = calc(X[i], X[j]);
				// Check if the distance is an integer by comparing the square root
				if(Math.sqrt(d2) == (long)Math.sqrt(d2)) cnt++;
			}
		}
		// Output the count of such pairs
		out.println(cnt);
	}

	// Function to calculate the squared Euclidean distance between two points
	long calc(int[] X1, int[] X2) {
		long res = 0;
		// Sum the squares of differences for each dimension
		for(int i = 0; i < X1.length; i++) res += (X1[i] - X2[i]) * (X1[i] - X2[i]);
		return res;
	}

