        private InputStream stream; // Input stream to read from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException(); // Throw exception if end of input is reached
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Throw exception on I/O error
                }
                if (numChars <= 0) {
                    return -1; // Return -1 if no more data is available
                }
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to read an integer from input
        public int Int() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read(); // Skip space characters
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException(); // Throw exception if not a digit
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed integer
        }

        // Method to read a string from input
        public String String() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read(); // Skip space characters
            }
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c));
            return res.toString(); // Return the parsed string
        }

