                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, Int()); // Handle scientific notation
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException(); // Throw exception if not a digit
                    }
                    m /= 10;
                    res += (c - '0') * m; // Convert character to fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the parsed double
        }

        // Method to read a long integer from input
        public long Long() {
            int c = read();
            while (isSpaceChar(c)) {
                c = read(); // Skip space characters
            }
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException(); // Throw exception if not a digit
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed long integer
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c); // Use custom filter if available
            }
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
        }

        // Method to read the next token as a string
        public String next() {
            return String(); // Delegate to String() method
        }

        // Interface for custom space character filtering
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Custom OutputWriter class to handle output operations
    private static class OutputWriter {
        private final PrintWriter writer; // PrintWriter for efficient output

        // Constructor to initialize the OutputWriter with an output stream
        public OutputWriter(OutputStream outputStream) {
            writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
        }

        // Constructor to initialize the OutputWriter with a writer
        public OutputWriter(Writer writer) {
            this.writer = new PrintWriter(writer);
        }

        // Method to print objects to the output
        public void print(Object... objects) {
            for (int i = 0; i < objects.length; i++) {
                if (i != 0) {
                    writer.print(' '); // Print space between objects
                }
                writer.print(objects[i]); // Print the object
            }
            writer.flush(); // Flush the writer
        }

        // Method to print objects followed by a newline
        public void println(Object... objects) {
            print(objects); // Print the objects
            writer.println(); // Print a newline
            writer.flush(); // Flush the writer
        }

        // Method to close the writer
        public void close() {
            writer.close(); // Close the writer
        }

        // Method to flush the writer
        public void flush() {
            writer.flush(); // Flush the writer
        }
    }
}

import java.util.*;
