class Main {
  // Custom scanner class for input handling
  static class Scnr {
    private final InputStream ins; // Input stream for reading data
    private final byte[] buffer = new byte[1024]; // Buffer to store input data
    private int ptr = 0; // Pointer to track current position in buffer
    private int buflen = 0; // Length of valid data in buffer

    // Default constructor using System.in as input stream
    Scnr() {
      this(System.in);
    }

    // Constructor with custom input stream
    Scnr(InputStream in) {
      ins = in;
    }

    // Check if there is another byte to read in the buffer
    private boolean hasNextByte() {
      if (ptr < buflen) {
        return true;
      } else {
        ptr = 0;
        try {
          buflen = ins.read(buffer); // Read data into buffer
        } catch (IOException e) {
          e.printStackTrace();
        }
        if (buflen <= 0) {
          return false; // No more data to read
        }
      }
      return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
      if (hasNextByte()) {
        return buffer[ptr++];
      } else {
        return -1; // End of stream
      }
    }

    // Check if a character is printable
    private static boolean isPrintableChar(int c) {
      return 33 <= c && c <= 126;
    }

    // Check if there is another token in the input
    public boolean hasNext() {
      while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
        ptr++;
      }
      return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
      if (!hasNext()) {
        throw new NoSuchElementException();
      }
      StringBuilder sb = new StringBuilder();
      int b = readByte();
      while (isPrintableChar(b)) {
        sb.appendCodePoint(b);
        b = readByte();
      }
      return sb.toString();
    }

    // Read the next token as a StringBuilder
    public StringBuilder nextBuilder() {
      if (!hasNext()) {
        throw new NoSuchElementException();
      }
      StringBuilder sb = new StringBuilder();
      int b = readByte();
      while (isPrintableChar(b)) {
        sb.appendCodePoint(b);
        b = readByte();
      }
      return sb;
    }

    // Read the next token as a double
    public double nextDouble() {
      return Double.parseDouble(next());
    }

    // Read the next token as a long
    public long nextLong() {
      if (!hasNext()) {
        throw new NoSuchElementException();
      }
      long n = 0;
      boolean minus = false;
      int b = readByte();
      if (b == '-') {
        minus = true;
        b = readByte();
      }
      if (b < '0' || '9' < b) {
        throw new NumberFormatException();
      }
      while (true) {
        if ('0' <= b && b <= '9') {
          n *= 10;
          n += b - '0';
        } else if (b == -1 || !isPrintableChar(b)) {
          return minus ? -n : n;
        } else {
          throw new NumberFormatException();
        }
        b = readByte();
      }
    }

    // Read the next token as an int
    public int nextInt() {
      long nl = nextLong();
      if (nl < Integer.MIN_VALUE || Integer.MAX_VALUE < nl) {
        throw new NumberFormatException();
      }
      return (int) nl;
    }

    // Read the next n integers into an array
    public int[] nextAInt(int n) {
      int[] a = new int[n];
      nextAInt(a, n);
      return a;
    }

    // Fill the provided array with the next n integers
    public void nextAInt(int[] a, int n) {
      for (int i = 0; i < n; i++) {
        a[i] = nextInt();
      }
    }

    // Read the next n longs into an array
    public long[] nextALong(int n) {
      long[] a = new long[n];
      nextALong(a, n);
      return a;
    }

    // Fill the provided array with the next n longs
    public void nextALong(long[] a, int n) {
      for (int i = 0; i < n; i++) {
        a[i] = nextLong();
      }
    }

    // Read the next n doubles into an array
    public double[] nextADouble(int n) {
      double[] a = new double[n];
      for (int i = 0; i < n; i++) {
        a[i] = nextDouble();
      }
      return a;
    }

    // Fill the provided array with the next n doubles
    public void nextADouble(double[] a, int n) {
      for (int i = 0; i < n; i++) {
        a[i] = nextDouble();
      }
    }
  }

  static Scnr sc = new Scnr(); // Instance of custom scanner
  static PrintWriter out = new PrintWriter(System.out); // PrintWriter for output

  public static void main(String args[]) {
