import java.io.IOException;
import java.io.InputStream;
import java.util.Arrays;
import java.util.NoSuchElementException;

public class Main {

	public static void main(String[] args) {

		// Create an instance of FastScanner to read input
		FastScanner sc = new FastScanner();

		// Read the number of strings
		int N = sc.nextInt();

		// Initialize an array to store the strings
		String[] W = new String[N];

		// Read each string and store it in the array
		for (int i = 0; i < N; i++)
			W[i] = sc.next();

		// Flag to determine if the conditions are violated
		boolean flag = false;

		// Check if the last character of a string matches the first character of the next string
		for (int i = 0; i < N - 1; i++) {
			if (W[i].charAt(W[i].length() - 1) != W[i + 1].charAt(0))
				flag = true; // Set flag if condition is violated
		}

		// Sort the array of strings
		Arrays.sort(W);

		// Check for duplicate strings in the sorted array
		for (int i = 0; i < N - 1; i++) {
			if (W[i].equals(W[i + 1]))
				flag = true; // Set flag if duplicate is found
		}

		// Output "No" if any condition is violated, otherwise "Yes"
		if (flag)
			System.out.println("No");
		else
			System.out.println("Yes");

	}

	// Method to calculate the greatest common divisor (GCD) of two numbers
	public static long gcd(long a, long b) {
		if (a < b)
			return gcd(b, a); // Ensure a >= b
		long c = 0;
		c = a % b;
		if (c == 0)
			return b; // Base case: if remainder is 0, return b
		return gcd(b, c); // Recursive call
	}

	// Method to calculate the least common multiple (LCM) of two numbers
	public static long lcm(long m, long n) {
		return m * n / gcd(m, n); // LCM formula using GCD
	}

	// Method to check if a number is prime
	public static boolean isPrime(int n) {
		if (n < 2)
			return false; // Numbers less than 2 are not prime
		if (n == 2)
			return true; // 2 is the only even prime number
		if (n % 2 == 0)
			return false; // Even numbers greater than 2 are not prime

		// Check divisibility from 3 to sqrt(n)
		for (int i = 3; i * i <= n; i += 2) {
			if (n % i == 0)
				return false; // Not prime if divisible by any i
		}
		return true; // Prime if no divisors found
	}
}


class FastScanner {
	private final InputStream in = System.in; // Input stream for reading data
	private final byte[] buffer = new byte[1024]; // Buffer for storing input data
	private int ptr = 0; // Pointer to current position in buffer
	private int buflen = 0; // Length of valid data in buffer

	// Check if there is another byte to read
	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true; // More bytes available in buffer
		} else {
			ptr = 0; // Reset pointer
			try {
				buflen = in.read(buffer); // Read more data into buffer
			} catch (IOException e) {
				e.printStackTrace(); // Print stack trace on error
			}
			if (buflen <= 0) {
				return false; // No more data available
			}
		}
		return true;
	}

	// Read the next byte from the buffer
	private int readByte() {
		if (hasNextByte())
			return buffer[ptr++]; // Return next byte and increment pointer
		else
			return -1; // Return -1 if no more bytes
	}

	// Check if a character is printable
	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126; // Printable ASCII range
	}

	// Check if there is another token to read
	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr]))
			ptr++; // Skip non-printable characters
		return hasNextByte(); // Return true if more tokens are available
	}

	// Read the next token as a String
	public String next() {
		if (!hasNext())
			throw new NoSuchElementException(); // Throw exception if no more tokens
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b); // Append character to StringBuilder
			b = readByte(); // Read next byte
		}
		return sb.toString(); // Return the constructed string
	}

	// Read the next token as a long
	public long nextLong() {
		if (!hasNext())
			throw new NoSuchElementException(); // Throw exception if no more tokens
		long n = 0;
		boolean minus = false;
		int b = readByte();
		if (b == '-') {
			minus = true; // Handle negative numbers
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException(); // Throw exception if not a number
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0'; // Construct the number
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n; // Return the number with correct sign
			} else {
				throw new NumberFormatException(); // Throw exception if invalid character
			}
			b = readByte(); // Read next byte
		}
	}

	// Read the next token as an int
	public int nextInt() {
		long nl = nextLong(); // Read as long first
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
			throw new NumberFormatException(); // Throw exception if out of int range
		return (int) nl; // Cast to int and return
	}

	// Read the next token as a double
	public double nextDouble() {
		return Double.parseDouble(next()); // Parse the next token as a double
	}
}

import java.util.Scanner;
import java.util.ArrayList;

class Main {
  public static void main(String[] args) {
    // Create a Scanner object to read input from the console
    Scanner sc = new Scanner(System.in);

    // Read the number of elements to be inputted
    int n = sc.nextInt();

    // Initialize an ArrayList to store the integers
    ArrayList<Integer> li = new ArrayList<Integer>();

    // Loop to read 'n' integers from the input and add them to the list
    for (int i = 0; i < n; i++) {
      int a = sc.nextInt();
      li.add(a);
    }

    // Initialize 'bigger' with the first element of the list
    int bigger = li.get(0);

    // Loop through the list to find the maximum value
    for (int i = 1; i < n; i++) {
      // Update 'bigger' with the maximum of current 'bigger' and the current list element
      int a = Math.max(bigger, li.get(i));
      bigger = a;
    }

    // Variables to count occurrences of the maximum value and to store its last index
    int maxNumber = 0;
    int m = 0;

    // Loop to count how many times the maximum value appears in the list
    for (int i = 0; i < n; i++) {
      if (li.get(i) == bigger) {
        maxNumber++;
        m = i; // Update 'm' to the index of the current maximum value
      }
    }

    // If the maximum value appears more than once
    if (maxNumber > 1) {
      // Print the maximum value 'n' times
      for (int i = 0; i < n; i++) {
        System.out.println(bigger);
      }
    } 
    // Special case: if the maximum is at the first index and there are only two elements
    else if (m == 0 && n == 2) {
      System.out.println(li.get(1)); // Print the second element
      System.out.println(bigger); // Print the maximum value
    } 
    // If the maximum is at the first index and there are more than two elements
    else if (m == 0) {
      // Find the second largest value (semiMax) starting from the second element
      int semiMax = li.get(1);
      for (int i = 2; i < n; i++) {
        int a = Math.max(semiMax, li.get(i));
        semiMax = a;
      }
      // Print the second largest value once
      System.out.println(semiMax);
      // Print the maximum value for the rest of the elements
      for (int i = 1; i < n; i++) {
        System.out.println(bigger);
      }
    } 
    // If the maximum is not at the first index
    else {
      // Find the second largest value (semiMax) excluding the maximum value's index
      int semiMax = li.get(0);
      for (int i = 1; i < n; i++) {
        if (i == m) {
          continue; // Skip the index of the maximum value
        } else {
          int a = Math.max(semiMax, li.get(i));
          semiMax = a;
        }
      }
      // Print the second largest value at the index of the maximum value
      // Print the maximum value for all other indices
      for (int i = 0; i < n; i++) {
        if (i == m) {
          System.out.println(semiMax);
        } else {
          System.out.println(bigger);
        }
      }
    }
  }
}

