        int x = in.Int();
        // Initialize the answer variable to store the result
        int ans = 0;

        // Check if x is greater than or equal to 500
        if (x >= 500) {
            // Calculate how many 500s fit into x
            int temp1 = x / 500;
            // Calculate the equivalent value in terms of 1000s
            int temp = (x / 500) * 1000;

            // Subtract the value of 500s from x
            x -= 500 * temp1;
            // Add the calculated value to the answer
            ans += temp;
        }
        // Check if the remaining x is greater than or equal to 5
        if (x >= 5) {
            // Calculate how many 5s fit into x
            int temp = (x / 5) * 5;
            // Subtract the value of 5s from x
            x -= temp;
            // Add the calculated value to the answer
            ans += temp;
        }
        // Output the final answer
        out.println(ans);
    }

    // Custom InputReader class to handle input operations
    private static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the InputReader with an InputStream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read data into the buffer
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    return -1;
                }
            }
            return buf[curChar++];
        }

        // Method to read an integer from input
        public int Int() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            // Read digits and form the integer
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to read a string from input
        public String String() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            StringBuilder res = new StringBuilder();
            // Read characters until a space character is encountered
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));
            return res.toString();
        }

        // Method to read a double from input
        public double Double() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            // Read digits before the decimal point
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    return res * Math.pow(10, Int());
                }
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            }
            // Read digits after the decimal point
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, Int());
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Method to read a long integer from input
        public long Long() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            long res = 0;
            // Read digits and form the long integer
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c);
            }
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Method to read the next token as a string
        public String next() {
            return String();
        }

        // Interface for defining custom space character filters
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Custom OutputWriter class to handle output operations
    private static class OutputWriter {
        private final PrintWriter writer;

        // Constructor to initialize the OutputWriter with an OutputStream
        public OutputWriter(OutputStream outputStream) {
            writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
        }

        // Constructor to initialize the OutputWriter with a Writer
        public OutputWriter(Writer writer) {
            this.writer = new PrintWriter(writer);
        }

        // Method to print objects to the output
        public void print(Object... objects) {
            for (int i = 0; i < objects.length; i++) {
                if (i != 0) {
                    writer.print(' ');
                }
                writer.print(objects[i]);
            }
            writer.flush();
        }

        // Method to print objects followed by a newline
        public void println(Object... objects) {
            print(objects);
            writer.println();
            writer.flush();
        }

        // Method to close the writer
        public void close() {
            writer.close();
        }

        // Method to flush the writer
        public void flush() {
            writer.flush();
        }
    }
}

