public class Main {
    public static void main (String[] args) throws java.lang.Exception {
        // Create an InputReader object to read input from the standard input stream
        InputReader in = new InputReader(System.in);
        // Create a PrintWriter object for output
        PrintWriter w = new PrintWriter(System.out);

        // Read an array of 3 integers from input
        int[] a = in.nextIntArray(3);

        // Initialize a variable to store the minimum sum of absolute differences
        int min = 100000;

        // Iterate over each element in the array
        for (int i = 0; i < 3; i++) {
            // Temporary variable to store the sum of absolute differences for the current element
            int temp = 0;

            // Compare the current element with every other element in the array
            for (int j = 0; j < 3; j++) {
                // Skip the comparison if it's the same element
                if (i == j)
                    continue;
                // Add the absolute difference between the current pair of elements to temp
                temp += Math.abs(a[j] - a[i]);
            }
            // Update the minimum sum of absolute differences if the current temp is smaller
            min = Math.min(min, temp);
        }

        // Print the minimum sum of absolute differences
        w.print(min);
        // Close the PrintWriter
        w.close();
    }

    // Custom InputReader class to handle input operations
    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer for reading input
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next character from the input stream
        public int read() {
            if (numChars == -1)
                throw new UnknownError(); // Throw an error if no more characters can be read
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read into the buffer
                } catch (IOException e) {
                    throw new UnknownError(); // Throw an error if reading fails
                }
                if (numChars <= 0)
                    return -1; // Return -1 if end of stream is reached
            }
            return buf[curChar++]; // Return the next character
        }

        // Method to peek at the next character without advancing the buffer
        public int peek() {
            if (numChars == -1)
                return -1;
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    return -1;
                }
                if (numChars <= 0)
                    return -1;
            }
            return buf[curChar];
        }

        // Method to skip a specified number of characters
        public void skip(int x) {
            while (x-- > 0)
                read();
        }

        // Method to read the next integer from the input
        public int nextInt() {
            return Integer.parseInt(next());
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            return Long.parseLong(next());
        }

        // Method to read the next string from the input
        public String nextString() {
            return next();
        }

        // Method to read the next token (word) from the input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            StringBuffer res = new StringBuffer();
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString();
        }

        // Method to read the next line from the input
        public String nextLine() {
            StringBuffer buf = new StringBuffer();
            int c = read();
            while (c != '\n' && c != -1) {
                if (c != '\r')
                    buf.appendCodePoint(c);
                c = read();
            }
            return buf.toString();
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9')
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Method to read an array of integers from the input
        public int[] nextIntArray(int n) {
            int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = nextInt();
            return a;
        }

        // Method to read an array of long integers from the input
        public long[] nextLongArray(int n) {
            long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = nextLong();
            return a;
        }

        // Method to check if there is another token available in the input
        public boolean hasNext() {
            int value;
            while (isSpaceChar(value = peek()) && value != -1)
                read();
            return value != -1;
        }

        // Method to check if a character is a whitespace character
        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }
    }
}

import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) {
        // Read the number of elements N and the maximum distance X from input
        int N = sc.nextInt();
        int X = sc.nextInt();

        // Initialize an array L to store the distances
        int[] L = new int[N];

        // Populate the array L with distances from input
        for(int i = 0; i < N; i++) {
            L[i] = sc.nextInt();
        }

        // Initialize the current distance D and the answer counter ans
        int D = 0;
        int ans = 1; // Start with 1 because the initial position is counted

        // Iterate over the distances
        int i = 0;
        while(i < N) {
            // Add the current distance to D
            D += L[i];

            // If the current distance exceeds X, break the loop
            if (D > X) break;

            // Increment the answer counter as the current position is within the limit
            ans++;

            // Move to the next distance
            i++;
        }

        // Output the result
        writer.println(ans);
        writer.flush();
    }

    // FastScanner for efficient input reading
    static final FastScanner sc = new FastScanner(System.in);
    static PrintWriter writer = new PrintWriter(System.out);

    static class FastScanner {
        Reader input;

        // Constructor that initializes the input stream
        FastScanner() {
            this(System.in);
        }

        // Constructor that accepts a custom input stream
        FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to read the next integer from input
        int nextInt() {
            return (int) nextLong();
        }

        // Method to read the next long integer from input
        long nextLong() {
            try {
                int sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Determine the sign of the number
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                // Read the numeric value
                long ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Method to read the next double from input
        double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Determine the sign of the number
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                // Read the integer part of the number
                double ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }

                // If there's no decimal part, return the integer part
                if (b != '.') return sign * ret;

                // Read the decimal part of the number
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }

                // Return the complete number
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

        // Method to read the next non-whitespace character from input
        char nextChar() {
            try {
                int b = input.read();

                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }

                // Return the character
                return (char) b;
            } catch (IOException e) {
                e.printStackTrace();
                return 0;
            }
        }

        // Method to read the next string from input
        String nextStr() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();

                // Skip initial whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }

                // Read characters until a whitespace or end of input is encountered
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }

                // Return the string
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }
    }

}

