class AtCoder {

    // Final variables to store the initial health (H), number of spells (N), and damage values (A)
    final int H;
    final int N;
    final int[] A;

    // Constructor to initialize the AtCoder problem with input values
    AtCoder(FastScanner sc) {
        // Read the initial health value
        H = sc.nextInt();
        // Read the number of spells
        N = sc.nextInt();
        // Initialize the array to store damage values of each spell
        A = new int[N];
        // Populate the damage array with input values
        for (int i = 0; i < A.length; i++) {
            A[i] = sc.nextInt();
        }
    }

    // Method to solve the problem and print the result
    void solve(PrintWriter out) {
        // Initialize current health with the initial health value
        int HP = H;
        // Iterate over each spell's damage
        for (int i = 0; i < A.length; i++) {
            // Subtract the spell's damage from current health
            HP -= A[i];
            // Check if the current health is still positive
            if (HP > 0) {
                continue; // Continue to the next spell if health is positive
            } else {
                // If health is zero or negative, print "Yes" and exit the loop
                out.println("Yes");
                break;
            }
        }

        // If loop completes and health is still positive, print "No"
        if (HP > 0) {
            out.println("No");
        }
    }
}


class FastScanner {

    // InputStream to read input data
    private final InputStream in = System.in;
    // Buffer to store input data
    private final byte[] buffer = new byte[1024];
    // Pointer to track the current position in the buffer
    private int ptr = 0;
    // Length of valid data in the buffer
    private int buflen = 0;

    // Method to check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true; // There is more data in the buffer
        } else {
            ptr = 0;
            try {
                // Read more data into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no more data is available
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Method to read the next byte from the buffer
    private int readByte() {
        if (hasNextByte()) {
            return buffer[ptr++]; // Return the next byte and increment the pointer
        } else {
            return -1; // Return -1 if no more bytes are available
        }
    }

    // Method to check if a character is printable
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Method to check if there is another token to read
    public boolean hasNext() {
        // Skip non-printable characters
        while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
            ptr++;
        }
        return hasNextByte(); // Return true if there is another token
    }

    // Method to read the next token as a String
    public String next() {
        if (!hasNext()) {
            throw new NoSuchElementException(); // Throw exception if no more tokens
        }
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder until a non-printable character is found
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString(); // Return the constructed string
    }

    // Method to read the next token as a long
    public long nextLong() {
        if (!hasNext()) {
            throw new NoSuchElementException(); // Throw exception if no more tokens
        }
        long n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Validate the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        // Construct the long value from digits
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n; // Return the constructed long value
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Method to read the next token as an int
    public int nextInt() {
        long nl = nextLong(); // Read the next token as a long
        // Check if the long value is within the range of an int
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) {
            throw new NumberFormatException();
        }
        return (int) nl; // Return the value as an int
    }

    // Method to read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next()); // Parse the next token as a double
    }
}

import java.util.Scanner;
import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class Main {
    public static void main(String[] args) throws MyException {

        // Create a Scanner object to read input from the console
        Scanner scan = new Scanner(System.in);

        // Read two strings S and T from input
        String S = scan.next();
        String T = scan.next();

        // Validate the length of S and T; they must be between 1 and 10 characters
        if(S.length() < 1 || S.length() > 10) throw new MyException("");
        if(T.length() < 1 || T.length() > 10) throw new MyException("");

        // Validate that S and T contain only lowercase letters
        if (!Pattern.matches("^[a-z]+$", S)) throw new MyException("");
        if (!Pattern.matches("^[a-z]+$", T)) throw new MyException("");

        // Ensure that S and T are not the same
        if(S.equals(T)) throw new MyException("");

        // Read two more strings As and Bs from input
        String As = scan.next();
        String Bs = scan.next();

        // Validate that As and Bs are valid integers (including negative numbers)
        if(!Pattern.compile("^-?[0-9]+$").matcher(As).find()) throw new MyException("");
        if(!Pattern.compile("^-?[0-9]+$").matcher(Bs).find()) throw new MyException("");

        // Parse As and Bs into integers A and B
        int A = Integer.parseInt(As);
        int B = Integer.parseInt(Bs);

        // Validate that A and B are between 1 and 10
        if(A < 1 || A > 10) throw new MyException("");
        if(B < 1 || B > 10) throw new MyException("");

        // Read another string U from input
        String U = scan.next();

        // Validate that U is either S or T
        if(!U.equals(S) && !U.equals(T)) throw new MyException("");

        // If U is S, decrement A and print the result with B
        if(U.equals(S)) System.out.println((A - 1) + " " + B);

        // If U is T, decrement B and print the result with A
        if(U.equals(T)) System.out.println(A + " " + (B - 1));

        // Close the scanner to free up resources
        scan.close();
    }
}

// Custom exception class extending Exception
class MyException extends Exception {
    // Constructor that takes a message and passes it to the superclass
    public MyException(String msg) {
        super(msg);
    }
}

