class FastScanner {

    // InputStream for reading input, default is standard input
    private final InputStream in = System.in;
    // Buffer to store bytes read from input
    private final byte[] buffer = new byte[1024];
    // Pointer to the current position in the buffer
    private int ptr = 0;
    // Number of bytes currently in the buffer
    private int buflen = 0;

    // Check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true; // There are unread bytes in the buffer
        } else {
            ptr = 0; // Reset pointer
            try {
                // Read more bytes into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace if an error occurs
            }
            if (buflen <= 0) {
                return false; // No more bytes to read
            }
        }
        return true; // Bytes are available to read
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte()) {
            return buffer[ptr++]; // Return the next byte and increment the pointer
        } else {
            return -1; // Indicate end of input
        }
    }

    // Check if a character is printable
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126; // Printable ASCII range
    }

    // Check if there is another token to read
    public boolean hasNext() {
        // Skip non-printable characters
        while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
            ptr++;
        }
        return hasNextByte(); // Return true if there is a next token
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) {
            throw new NoSuchElementException(); // No more tokens
        }
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder until a non-printable character is encountered
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString(); // Return the constructed string
    }

    // Read the next token as a long
    public long nextLong() {
        if (!hasNext()) {
            throw new NoSuchElementException(); // No more tokens
        }
        long n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException(); // Invalid number format
        }
        // Read digits and construct the number
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0'; // Convert character to digit
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n; // Return the number, negated if necessary
            } else {
                throw new NumberFormatException(); // Invalid number format
            }
            b = readByte();
        }
    }

    // Read the next token as an int
    public int nextInt() {
        long nl = nextLong(); // Read as long first
        // Check if the long value fits within the int range
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) {
            throw new NumberFormatException(); // Value out of int range
        }
        return (int) nl; // Cast to int and return
    }

    // Read the next token as a double
    public double nextDouble() {
        return Double.parseDouble(next()); // Parse the next token as a double
    }
}

