public class Main {
    public static void main(String[] args) {
        FS reader = new FS(); // Create an instance of the FS class to read input

        int a = reader.nextInt(); // Read the first integer from input
        int b = reader.nextInt(); // Read the second integer from input

        // Check if both integers are odd
        if (a % 2 == 1 && b % 2 == 1) {
            System.out.println("Odd"); // Print "Odd" if both are odd
        } else {
            System.out.println("Even"); // Print "Even" otherwise
        }
    }

    // Custom input reader class
    static class FS {
        private final InputStream in = System.in; // Input stream for reading data
        private final byte[] buffer = new byte[1024]; // Buffer to store input data
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true; // There is more data in the buffer
            } else {
                ptr = 0; // Reset pointer
                try {
                    buflen = in.read(buffer); // Read more data into the buffer
                } catch (IOException e) {
                    e.printStackTrace(); // Print stack trace if an error occurs
                }
                if (buflen <= 0) {
                    return false; // No more data to read
                }
            }
            return true; // Data is available
        }

        // Read the next byte from the buffer
        private int readByte() {
            return hasNextByte() ? buffer[ptr++] : -1; // Return the next byte or -1 if no data
        }

        // Check if a character is printable
        private boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126; // Printable ASCII range
        }

        // Skip non-printable characters
        private void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
                ptr++; // Move pointer to the next printable character
            }
        }

        // Check if there is another token to read
        public boolean hasNext() {
            skipUnprintable(); // Skip any unprintable characters
            return hasNextByte(); // Check if there is more data
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) throw new NoSuchElementException(); // Throw exception if no more tokens
            StringBuilder sb = new StringBuilder(); // Use StringBuilder to construct the token
            int b = readByte(); // Read the first byte of the token
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b); // Append character to the StringBuilder
                b = readByte(); // Read the next byte
            }
            return sb.toString(); // Return the constructed token
        }

        // Read the next token as an integer
        public int nextInt() {
            return (int) nextLong(); // Convert the next long to an int
        }

        // Read the next token as a long
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException(); // Throw exception if no more tokens
            long n = 0; // Initialize the number
            boolean minus = false; // Flag for negative numbers
            int b = readByte(); // Read the first byte

            // Check for negative sign
            if (b == '-') {
                minus = true; // Set the minus flag
                b = readByte(); // Read the next byte
            }

            // Ensure the first character is a digit
            if (b < '0' || '9' < b) {
                throw new NumberFormatException(); // Throw exception if not a digit
            }

            // Read the number
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10; // Shift digits left
                    n += b - '0'; // Add the new digit
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n; // Return the number, negated if necessary
                } else {
                    throw new NumberFormatException(); // Throw exception if invalid character
                }
                b = readByte(); // Read the next byte
            }
        }
    }
}

import java.io.BufferedReader;
