import java.io.InputStreamReader;

public class Main {

    public static void main(String[] a){

        // Initialize variables to store the number of columns and bars
        int NumberOfColumn = 0;
        int NumberOfBar = 0;

        // Declare a 2D array to store bar connections and an array to store the final answer
        int[][] arr;
        int[] ans;

        // BufferedReader to read input from the console
        BufferedReader bf = new BufferedReader(new InputStreamReader(System.in));

        String tmpString;
        try {
            // Read the number of columns from input
            if(null != (tmpString = bf.readLine())){
                NumberOfColumn = Integer.parseInt(tmpString);
            }

            // Read the number of bars from input
            if(null != (tmpString = bf.readLine())){
                NumberOfBar = Integer.parseInt(tmpString);
            }

            // Initialize the array to store bar connections
            arr = new int[NumberOfBar][2];

            // Read each bar connection and store it in the array
            for(int i = 0; i < NumberOfBar; i++){
                if(null != (tmpString = bf.readLine())){
                    String[]  tmp = tmpString.split(",");
                    arr[i][0] = Integer.parseInt(tmp[0]);
                    arr[i][1] = Integer.parseInt(tmp[1]);
                }
            }

            // Initialize the answer array with column numbers
            ans = new int[NumberOfColumn];
            for(int i = 0; i < NumberOfColumn; i++){
                ans[i] = i + 1;

                // Check each bar to see if it affects the current column
                for(int j = 0; j < NumberOfBar; j++){
                    if(arr[j][0] == ans[i]){
                        // If the current column matches the first element of a bar, swap it with the second
                        ans[i] = arr[j][1];
                    } else if(arr[j][1] == ans[i]){
                        // If the current column matches the second element of a bar, swap it with the first
                        ans[i] = arr[j][0];
                    }
                }
            }

            // Output the final positions of each column
            for(int i = 0; i < NumberOfColumn; i++){
                for(int j = 0; j < NumberOfColumn; j++ ){
                    if(ans[j] == i + 1){
                        // Print the original position of the column that ends up in position i+1
                        System.out.println(j + 1);
                        break;
                    }
                }
            }

        } catch (Exception e) {
            // Print error message in case of any exception
            System.err.println("error");
        } finally {
            try {
                // Close the BufferedReader to release system resources
                bf.close();
            } catch (IOException e) {
                // Handle potential IOException during BufferedReader closing
            }
        }

    }

}

