public class Main {
    // Static variables to store the values of K and S
    static int K;
    static int S;

    public static void main(String[] args) {
        // Read the values of K and S from input
        K = sc.nextInt();
        S = sc.nextInt();

        // Calculate the result using function g and print it
        writer.println(g(S, K));

        // Flush the writer to ensure all data is written out
        writer.flush();
    }

    // Function f calculates the number of ways to choose two numbers
    // such that their sum is equal to 'sum' and each number is between 0 and k
    private static int f(int sum, int k) {
        // If the sum is negative, return 0 as it's not possible
        if (sum < 0) return 0;

        int ans = 0; // Initialize the answer counter

        // Iterate over all possible values for the first number
        for (int i = 0; i <= k; i++) {
            // Check if the second number is within the valid range
            if (sum - i <= k && sum - i >= 0) ans++;
        }

        return ans; // Return the total count of valid pairs
    }

    // Function g calculates the number of ways to choose three numbers
    // such that their sum is equal to 'sum' and each number is between 0 and k
    private static int g(int sum, int k) {
        int ans = 0; // Initialize the answer counter

        // Iterate over all possible values for the first number
        for (int i = 0; i <= k; i++) {
            // Add the number of valid pairs for the remaining sum
            ans += f(sum - i, k);
        }

        return ans; // Return the total count of valid triplets
    }

    // FastScanner instance for efficient input reading
    static final FastScanner sc = new FastScanner(System.in);
    // PrintWriter instance for efficient output writing
    static PrintWriter writer = new PrintWriter(System.out);

    // FastScanner class for fast input operations
    static class FastScanner {
        Reader input;

        // Constructor that initializes the input stream
        FastScanner() {
            this(System.in);
        }

        // Constructor that accepts a custom input stream
        FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to read the next integer from input
        int nextInt() {
            return (int) nextLong();
        }

        // Method to read the next long integer from input
        long nextLong() {
            try {
                int sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                long ret = b - '0'; // Initialize the result

                // Read the number
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1; // Return -1 in case of an error
            }
        }

        // Method to read the next double from input
        double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();

                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }

                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }

                double ret = b - '0'; // Initialize the result

                // Read the integer part
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }

                // If there's no decimal part, return the result
                if (b != '.') return sign * ret;

                double div = 1;
                b = input.read();

                // Read the decimal part
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }

                return sign * ret / div; // Return the final result
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN; // Return NaN in case of an error
            }
        }

        // Method to read the next non-whitespace character from input
        char nextChar() {
            try {
                int b = input.read();

                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }

                return (char) b; // Return the character
            } catch (IOException e) {
                e.printStackTrace();
                return 0; // Return null character in case of an error
            }
        }

        // Method to read the next string from input
        String nextStr() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();

                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }

                // Read the string
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }

                return sb.toString(); // Return the string
            } catch (IOException e) {
                e.printStackTrace();
                return ""; // Return empty string in case of an error
            }
        }
    }
}

