  // MOD class for modular arithmetic operations
  static class MOD {
    private static final int MOD = (int) 1e9 + 7; // Modulus value

    // Method to perform modular addition
    static long plus(long x, long y) {
      x %= MOD;
      y %= MOD;
      return (x + y) % MOD;
    }

    // Method to perform modular subtraction
    static long sub(long x, long y) {
      x %= MOD;
      y %= MOD;
      return (x - y + MOD) % MOD;
    }

    // Method to perform modular multiplication
    static long multi(long x, long y) {
      x %= MOD;
      y %= MOD;
      return x * y % MOD;
    }

    // Method to perform modular division using modular inverse
    static long div(long x, long y) {
      x %= MOD;
      y %= MOD;
      return x * pow(y, MOD - 2) % MOD; // Uses Fermat's Little Theorem
    }

    // Method to perform modular exponentiation
    static long pow(final long a, final long p) {
      if (p == 0)
        return 1; // Base case: a^0 = 1
      if (p % 2 == 0) {
        final long halfP = p / 2;
        final long root = pow(a, halfP);
        return root * root % MOD; // If p is even
      } else
        return a * pow(a, p - 1) % MOD; // If p is odd
    }
  }

