public class Main {
    // Static variables to hold the input strings S and T
    static String S;
    static String T;

    public static void main(String[] args) {
        // Read input strings S and T using the FastScanner
        S = sc.nextStr();
        T = sc.nextStr();

        // Check if T is a rotation of S using the solve method
        if(solve()) {
            writer.println("Yes"); // If true, print "Yes"
        } else {
            writer.println("No"); // If false, print "No"
        }

        // Flush the writer to ensure all output is written
        writer.flush();
    }

    // Method to determine if T is a rotation of S
    static boolean solve() {
        // Iterate over each possible rotation starting point in S
        for (int i = 0; i < S.length(); i++) {
            // Check if the current rotation matches T
            boolean b = match(i);
            if(b) return true; // If a match is found, return true
        }
        return false; // If no match is found, return false
    }

    // Method to check if T matches a rotation of S starting at index i
    static boolean match(int i) {
        int len = S.length(); // Length of the string S
        // Iterate over each character in T
        for (int j = 0; j < len; j++) {
            // Calculate the rotated index in S
            int k = (i+j)%len;
            // If characters do not match, return false
            if (S.charAt(k) != T.charAt(j)) return false;
        }
        return true; // If all characters match, return true
    }

    // FastScanner instance for efficient input reading
    static final FastScanner sc = new FastScanner(System.in);
    // PrintWriter instance for efficient output writing
    static PrintWriter writer = new PrintWriter(System.out);

    // Custom FastScanner class for fast input operations
    static class FastScanner {
        Reader input; // Reader to handle input stream

        // Constructor with default input stream
        FastScanner() {
            this(System.in);
        }

        // Constructor with specified input stream
        FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to read the next integer from input
        int nextInt() {
            return (int) nextLong(); // Reuse nextLong method for integer reading
        }

        // Method to read the next long integer from input
        long nextLong() {
            try {
                int sign = 1; // Variable to store the sign of the number
                int b = input.read(); // Read the first byte
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Check for negative sign
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                long ret = b - '0'; // Initialize the number with the first digit
                // Read the remaining digits
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign; // Return the number if non-digit is encountered
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1; // Return -1 in case of an exception
            }
        }

        // Method to read the next double from input
        double nextDouble() {
            try {
                double sign = 1; // Variable to store the sign of the number
                int b = input.read(); // Read the first byte
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Check for negative sign
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                double ret = b - '0'; // Initialize the number with the first digit
                // Read the remaining digits
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break; // Break if non-digit is encountered
                    ret *= 10;
                    ret += b - '0';
                }
                if (b != '.') return sign * ret; // Return the number if no decimal point is found
                double div = 1;
                b = input.read();
                // Read the fractional part
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div; // Return the final double value
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN; // Return NaN in case of an exception
            }
        }

        // Method to read the next non-whitespace character from input
        char nextChar() {
            try {
                int b = input.read(); // Read the first byte
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                return (char) b; // Return the character
            } catch (IOException e) {
                e.printStackTrace();
                return 0; // Return null character in case of an exception
            }
        }

        // Method to read the next string from input
        String nextStr() {
            try {
                StringBuilder sb = new StringBuilder(); // StringBuilder to accumulate characters
                int b = input.read(); // Read the first byte
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                // Read characters until whitespace or end of stream
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString(); // Return the accumulated string
            } catch (IOException e) {
                e.printStackTrace();
                return ""; // Return empty string in case of an exception
            }
        }
    }

}

