public class Main {
    public static void main(String args[]) {
        Scanner sc = new Scanner(System.in); // Creating a Scanner object to read input from the user

        // Reading four integers from the user
        int a = sc.nextInt();
        int b = sc.nextInt();
        int c = sc.nextInt();
        int d = sc.nextInt();

        /* 
         * The following conditional statements are used to determine the overlap
         * between two intervals [a, b] and [c, d]. The program calculates the length
         * of the overlapping segment if there is any overlap.
         */

        // Check if the interval [a, b] overlaps with [c, d] and c is within [a, b]
        if (a <= c && b <= d && c <= b) {
            System.out.println(b - c); // Output the length of the overlap
        }
        // Check if the interval [c, d] overlaps with [a, b] and a is within [c, d]
        else if (c <= a && d <= b && a <= d) {
            System.out.println(d - a); // Output the length of the overlap
        }
        // Check if [a, b] completely contains [c, d]
        else if (a <= c && a <= d && b >= c && b >= d) {
            System.out.println(d - c); // Output the length of the interval [c, d]
        }
        // Check if [c, d] completely contains [a, b]
        else if (c <= a && c <= b && d >= a && d >= b) {
            System.out.println(b - a); // Output the length of the interval [a, b]
        }
        // If none of the above conditions are met, there is no overlap
        else {
            System.out.println(0); // Output 0 indicating no overlap
        }
    }
