class hayami implements Closeable {
    // Input stream and buffer for reading input
    private final InputStream in = System.in;
    private final byte[] hayami = new byte[1024];
    private int Hayami = 0; // Current position in the buffer
    private int saori = 0;  // Number of bytes read into the buffer

    // Check if there are more bytes to read in the buffer
    private boolean HayamiSaori() {
        if (Hayami < saori) {
            return true;
        } else {
            Hayami = 0;
            try {
                // Read more bytes into the buffer
                saori = in.read(hayami);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no more bytes are available
            if (saori <= 0) {
                return false;
            }
        }
        return true;
    }

    // Get the next byte from the buffer
    private int SaoriHayami() { 
        if (HayamiSaori()) {
            return hayami[Hayami++];
        } else {
            return -1;
        }
    }

    // Check if a byte is a printable ASCII character
    private static boolean hayami_saori(int hayami) { 
        return 33 <= hayami && hayami <= 126;
    }

    // Skip non-printable characters and check if there are more printable characters
    public boolean hayamisaori() { 
        while (HayamiSaori() && !hayami_saori(hayami[Hayami])) Hayami++; 
        return HayamiSaori();
    }

    // Read the next word from input as a String
    public String nextHayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        StringBuilder hayamin = new StringBuilder();
        int saori = SaoriHayami();
        while (hayami_saori(saori)) {
            hayamin.appendCodePoint(saori);
            saori = SaoriHayami();
        }
        return hayamin.toString();
    }

    // Read the next number from input as a long
    public long saorihayami() {
        if (!hayamisaori()) throw new NoSuchElementException();
        long hayami = 0;
        boolean misao = false;
        int saori = SaoriHayami();

        // Check for negative sign
        if (saori == '-') {
            misao = true;
            saori = SaoriHayami();
        }

        // Ensure the first character is a digit
        if (saori < '0' || '9' < saori) {
            throw new NumberFormatException();
        }

        // Read digits and construct the number
        while (true) {
            if ('0' <= saori && saori <= '9') {
                hayami *= 10;
                hayami += saori - '0';
            } else if (saori == -1 || !hayami_saori(saori)) {
                return misao ? -hayami : hayami;
            } else {
                throw new NumberFormatException();
            }
            saori = SaoriHayami();
        }
    }

    // Read the next number from input as an int
    public int saori_hayami() {
        long hayami = saorihayami();
        // Check if the number fits in an int
        if (hayami < Integer.MIN_VALUE || hayami > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) hayami;
    }

    // Read the next number from input as a double
    public double Hayamin() { 
        return Double.parseDouble(nextHayami());
    }

    // Close the input stream
    public void close() {
        try {
            in.close();
        } catch (IOException e) {
            // Handle exception silently
        }
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read an integer input from the user
        int a = sc.nextInt();

        // Initialize a variable to store the result
        long result = 0;

        // Iterate over all possible values of i from 1 to a
        for (int i = 1; i <= a; i++) {
            // Iterate over all possible values of j from i to a
            for (int j = i; j <= a; j++) {
                // Iterate over all possible values of k from j to a
                for (int k = j; k <= a; k++) {
                    // Initialize a boolean flag to determine if a common divisor is found
                    boolean judge = true;

                    // Check for the greatest common divisor (GCD) of i, j, and k
                    for (int l = i; l > 0 && judge; l--) {
                        // If l is a common divisor of i, j, and k
                        if (i % l == 0 && j % l == 0 && k % l == 0) {
                            // Set judge to false to stop further checks
                            judge = false;

                            // Check if i, j, and k are all equal
                            if (i == j && j == k) {
                                // Add the common divisor to the result
                                result += l;
                            } 
                            // Check if i, j, and k are all different
                            else if (i != j && j != k && i != k) {
                                // Add six times the common divisor to the result
                                result += (l * 6);
                            } 
                            // Otherwise, two of i, j, and k are equal
                            else {
                                // Add three times the common divisor to the result
                                result += (l * 3);
                            }
                        }
                    }
                }
            }
        }

        // Output the final result
        System.out.println(result);
    }
}

