import java.util.Scanner;

public class Main {

    public static void main(String[] args) {

        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read two integers N and M from input
        int N = sc.nextInt(); // N represents the upper bound of a range
        int M = sc.nextInt(); // M represents the number of intervals to process

        // Initialize variables
        int t = 0; // t will store the length of the intersection of intervals
        int L = 0, R = N; // L and R represent the current intersection range [L, R]

        // If there is only one interval to process
        if (M == 1) {
            // Read the interval [c, d]
            int c = sc.nextInt();
            int d = sc.nextInt();
            // Calculate the length of the interval
            t = d - c + 1;
        } else {
            // Process multiple intervals
            for (int i = 0; i < M; i++) {
                // Read the interval [a, b]
                int a = sc.nextInt();
                int b = sc.nextInt();

                // Check if the current interval [a, b] is within the current range [L, R]
                if (L <= a && b <= R) {
                    // Update L and R to the current interval
                    L = a;
                    R = b;
                    // Calculate the length of the intersection
                    t = R - L + 1;
                } 
                // Check if the current range [L, R] is within the interval [a, b]
                else if (a <= L && R <= b) {
                    // The intersection remains the same
                    t = R - L + 1;
                } 
                // Check if the left part of the interval [a, b] overlaps with [L, R]
                else if ((L <= a && a <= R) && R < b) {
                    // Update L to a
                    L = a;
                    // Calculate the length of the intersection
                    t = R - L + 1;
                } 
                // Check if the right part of the interval [a, b] overlaps with [L, R]
                else if ((L <= b && b <= R) && a < L) {
                    // Update R to b
                    R = b;
                } 
                // Check if the interval [a, b] is completely outside [L, R]
                else if (b < L || R < a) {
                    // No intersection, set t to 0 and break the loop
                    t = 0;
                    break;
                } 
                // If none of the above conditions are met, update L and R to the current interval
                else {
                    L = a;
                    R = b;
                }
            }
        }

        // Output the length of the intersection
        System.out.println(t);
    }

}

