class FastScanner {
    // InputStream to read from standard input
    private final InputStream in = System.in;
    // Buffer to store bytes read from the input
    private final byte[] buffer = new byte[1024];
    // Pointer to the current position in the buffer
    private int ptr = 0;
    // Number of bytes currently in the buffer
    private int buflen = 0;

    // Check if there is another byte available in the buffer
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                // Read more bytes into the buffer
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            // Return false if no more bytes are available
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() {
        if (hasNextByte()) {
            return buffer[ptr++];
        } else {
            return -1; // Return -1 if no byte is available
        }
    }

    // Check if a character is printable (ASCII range 33 to 126)
    private static boolean isPrintableChar(int c) {
        return 33 <= c && c <= 126;
    }

    // Skip non-printable characters in the buffer
    private void skipUnprintable() {
        while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
            ptr++;
        }
    }

    // Check if there is another token available
    public boolean hasNext() {
        skipUnprintable();
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        // Append characters to the StringBuilder until a non-printable character is found
        while (isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as an integer
    public int nextInt() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        int n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for a negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        // Parse the integer value
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as a long
    public long nextLong() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        long n = 0;
        boolean minus = false;
        int b = readByte();
        // Check for a negative sign
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        // Ensure the first character is a digit
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        // Parse the long value
        while (true) {
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if (b == -1 || !isPrintableChar(b)) {
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }
}

