import java.io.BufferedReader;
import java.io.InputStreamReader;

public class Main {

    public static void main(String[] args) throws Exception {

        // Using try-with-resources to ensure BufferedReader is closed automatically
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in))) {
            String line; // Variable to store each line of input
            int n = 0, j = 0; // n is the number of integers to read, j is the index for storing integers
            int[] store = null; // Array to store the integers read from input
            boolean first = true, min_flag = true; // Flags to control logic flow
            while ((line = br.readLine()) != null) { // Read input until EOF
                if (first) {
                    // First line of input is the number of integers
                    n = Integer.parseInt(line);
                    store = new int[n]; // Initialize the array with size n
                    first = false; // Set flag to false after reading the first line
                } else {
                    // Store the integer in the array
                    store[j] = Integer.parseInt(line);
                    j++; // Increment index
                    if (j == n) {
                        // Break loop if all integers are read
                        break;
                    }
                }               
            }

            int s = 0; // Variable to store the current value being processed
            int result = store[1] - store[0]; // Initialize result with the difference of the first two elements
            int min = store[0], max = min; // Initialize min and max with the first element

            for (int i = 1; i < n; i++) {
                if (min_flag) {
                    // Update s with the current store value if min_flag is true
                    s = store[i];
                }

                min_flag = true; // Reset min_flag to true for the next iteration

                if (s <= min && i != n - 1) {
                    // Update min if s is less than or equal to current min and not the last element
                    min = s;
                    if (i == n - 2) {
                        // Special case for the second last element
                        max = store[i + 1];
                        if (max - min > result) {
                            // Print the larger of max-min or result
                            System.out.println(max - min);
                        } else {
                            System.out.println(result);
                        }
                        return; // Exit the program after printing the result
                    } else {
                        // Update s and max for the next element
                        s = store[i + 1];
                        max = s;
                        if (result < max - min) {
                            // Update result if the new difference is larger
                            result = max - min;
                        } else {
                            // Set min_flag to false if no update to result
                            min_flag = false;
                        }
                    }
                } else if (s >= max) {
                    // Update max if s is greater than or equal to current max
                    max = s;
                    if (max - min > result) {
                        // Update result if the new difference is larger
                        result = max - min;
                    }
                }
            }

            // Print the final result
            System.out.println(result);
        }
    }
}

