import java.io.IOException;
import java.io.InputStream;
import java.util.*;

public class Main {
    public static void main(String[] args){
        // Create an instance of FastScanner to read input
        FastScanner sc = new FastScanner();

        // Read the number of elements in the array
        int N = sc.nextInt();

        // Initialize an array of size N
        int[] array = new int[N];

        // Variable to count the number of swaps made during sorting
        int sw = 0;

        // Read N integers from input and store them in the array
        for(int i=0; i<N; i++) array[i] = sc.nextInt();

        // Perform selection sort on the array
        for(int i=0; i<N; i++){
            // Assume the minimum element is at the current position
            int minj = i;

            // Find the index of the minimum element in the unsorted part of the array
            for(int j=i; j<N; j++){
                if(array[j] < array[minj]) minj = j;
            }

            // If the current element is not the minimum, swap it with the minimum element
            if(array[i] != array[minj]) sw++;

            // Swap the elements at index i and minj
            int v = array[i];
            array[i] = array[minj];
            array[minj] = v;
        }

        // Print the sorted array
        System.out.println(parseArray(array));

        // Print the number of swaps made
        System.out.println(sw);
    }

    // Method to convert an array of integers to a space-separated string
    static String parseArray(int[] array){
        StringBuilder builder = new StringBuilder();

        // Append each element of the array to the StringBuilder
        for(int i=0; i<array.length; i++){
            if(i > 0) builder.append(" "); // Add space between elements
            builder.append(array[i]);
        }

        // Return the resulting string
        return builder.toString();
    }

    // Custom scanner class for fast input reading
    static class FastScanner {
        private final InputStream in = System.in; // Input stream for reading data
        private final byte[] buffer = new byte[1024]; // Buffer to store input data
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    buflen = in.read(buffer); // Read data into the buffer
                } catch (IOException e) {
                    e.printStackTrace();
                }
                if (buflen <= 0) {
                    return false; // No more data to read
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() { 
            if (hasNextByte()) return buffer[ptr++]; 
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) { 
            return 33 <= c && c <= 126;
        }

        // Check if there is another token to read
        public boolean hasNext() { 
            while(hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; 
            return hasNextByte();
        }

        // Read the next token as a string
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while(isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long integer
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while(true){
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if(b == -1 || !isPrintableChar(b)){
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an integer
        public int nextInt() {
            long nl = nextLong();
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Read the next token as a double
        public double nextDouble() { 
            return Double.parseDouble(next());
        }
    }
}

import java.text.ParseException;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {

    public static void main(String[] arges) throws ParseException {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read a line of input from the user
        String line = sc.nextLine();

        // Split the input line into two parts based on space and parse them as integers
        String[] kz = line.split(" ");
        int v1 = Integer.parseInt(kz[0]);
        int v2 = Integer.parseInt(kz[1]);

        // Initialize lists to store divisors of v1, v3, and common divisors (kouyaku)
        List<Integer> vlist = new ArrayList<Integer>();
        List<Integer> v3list = new ArrayList<Integer>();
        List<Integer> kouyaku = new ArrayList<Integer>();

        // Check if v1 is less than v2
        if (v1 < v2) {
            // Calculate the remainder of v2 divided by v1
            int v3 = v2 % v1;

            // Check if v1 is greater than or equal to v3
            if (v1 >= v3) {
                // Find divisors of v3 and v1
                for (int i = 1; i <= v3; i++) {
                    if (v3 % i == 0) {
                        v3list.add(i);
                    }
                    if (v1 % i == 0) {
                        vlist.add(i);
                    }
                }
            } else {
                // Find divisors of v3 and v1 when v1 is less than v3
                for (int i = 1; i <= v1; i++) {
                    if (v3 % i == 0) {
                        v3list.add(i);
                    }
                    if (v1 % i == 0) {
                        vlist.add(i);
                    }
                }
            }
        } else if (v1 > v2) { // Check if v1 is greater than v2
            // Calculate the remainder of v1 divided by v2
            int v3 = v1 % v2;

            // Check if v3 is greater than or equal to v2
            if (v3 >= v2) {
                // Find divisors of v2 and v3
                for (int i = 1; i <= v2; i++) {
                    if (v2 % i == 0) {
                        vlist.add(i);
                    }
                    if (v3 % i == 0) {
                        v3list.add(i);
                    }
                }
            } else {
                // Find divisors of v3 and v2 when v3 is less than v2
                for (int i = 1; i <= v3; i++) {
                    if (v3 % i == 0) {
                        v3list.add(i);
                    }
                    if (v2 % i == 0) {
                        vlist.add(i);
                    }
                }
            }
        } else { // If v1 is equal to v2
            // Add v1 (or v2) to the list of common divisors
            kouyaku.add(v1);
        }

        // Find common divisors between vlist and v3list
        for (int integer : vlist) {
            for (int in : v3list) {
                if (integer == in) {
                    // Add common divisor to kouyaku list
                    kouyaku.add(in);
                    break;
                } else if (integer < in) {
                    // Break the loop if the current integer is less than in
                    break;
                }
            }
        }

        // Print the maximum common divisor found
        System.out.println(java.util.Collections.max(kouyaku));
    }
}

import java.io.BufferedReader;
