import java.util.*;
import java.lang.*;
import java.io.*;
import java.math.BigDecimal;

public class Main {
    public static void main (String[] args) throws java.lang.Exception {
        // Create an InputReader object to read input from the standard input stream
        InputReader in = new InputReader(System.in);
        // Create a PrintWriter object to write output to the standard output stream
        PrintWriter w = new PrintWriter(System.out);

        // Read two integers from input: n and d
        int n = in.nextInt(), d = in.nextInt();

        // Calculate 100^n and store it in temp
        int temp = (int)Math.pow(100, n);
        // Initialize ans to 0, which will store the final result
        int ans = 0;

        // Loop d times
        while (d-- > 0) {
            // Add temp to ans
            ans += temp;
            // If the number of trailing "00"s in ans is greater than n, add temp again
            if (howMany(ans) > n)
                ans += temp;
        }

        // Print the final result
        w.println(ans);
        // Close the PrintWriter
        w.close();
    }

    // Method to count how many times 100 divides n completely
    static int howMany(int n) {
        int r = 0; // Initialize counter for the number of times 100 divides n
        // While n is divisible by 100, divide n by 100 and increment the counter
        while (n % 100 == 0) {
            n /= 100;
            r++;
        }
        // Return the count of how many times 100 divides n
        return r;
    }

    // Custom InputReader class to handle input operations
    static class InputReader {
        private InputStream stream; // Input stream to read from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1)
                throw new UnknownError(); // Throw error if end of stream is reached
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new UnknownError(); // Throw error on IOException
                }
                if (numChars <= 0)
                    return -1; // Return -1 if no characters were read
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to peek at the next byte of input without advancing the cursor
        public int peek() {
            if (numChars == -1)
                return -1; // Return -1 if end of stream is reached
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    return -1; // Return -1 on IOException
                }
                if (numChars <= 0)
                    return -1; // Return -1 if no characters were read
            }
            return buf[curChar]; // Return the next character from the buffer
        }

        // Method to skip x characters in the input
        public void skip(int x) {
            while (x-- > 0)
                read(); // Read and discard x characters
        }

        // Method to read the next integer from input
        public int nextInt() {
            return Integer.parseInt(next()); // Parse the next token as an integer
        }

        // Method to read the next long from input
        public long nextLong() {
            return Long.parseLong(next()); // Parse the next token as a long
        }

        // Method to read the next string from input
        public String nextString() {
            return next(); // Return the next token as a string
        }

        // Method to read the next token from input
        public String next() {
            int c = read(); // Read the next character
            while (isSpaceChar(c))
                c = read(); // Skip whitespace characters
            StringBuffer res = new StringBuffer(); // Buffer to store the token
            do {
                res.appendCodePoint(c); // Append character to the buffer
                c = read(); // Read the next character
            } while (!isSpaceChar(c)); // Continue until a space character is found

            return res.toString(); // Return the token as a string
        }

        // Method to read the next line from input
        public String nextLine() {
            StringBuffer buf = new StringBuffer(); // Buffer to store the line
            int c = read(); // Read the next character
            while (c != '\n' && c != -1) { // Continue until newline or end of stream
                if (c != '\r')
                    buf.appendCodePoint(c); // Append character to the buffer
                c = read(); // Read the next character
            }
            return buf.toString(); // Return the line as a string
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read(); // Read the next character
            while (isSpaceChar(c))
                c = read(); // Skip whitespace characters
            int sgn = 1; // Sign of the number
            if (c == '-') {
                sgn = -1; // Set sign to negative if '-' is found
                c = read(); // Read the next character
            }
            double res = 0; // Resulting double value
            while (!isSpaceChar(c) && c != '.') { // Continue until space or '.'
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception if not a digit
                res *= 10;
                res += c - '0'; // Convert character to digit and add to result
                c = read(); // Read the next character
            }
            if (c == '.') {
                c = read(); // Read the next character after '.'
                double m = 1; // Multiplier for decimal places
                while (!isSpaceChar(c)) { // Continue until space
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Throw exception if not a digit
                    m /= 10;
                    res += (c - '0') * m; // Convert character to digit and add to result
                    c = read(); // Read the next character
                }
            }
            return res * sgn; // Return the resulting double value with sign
        }

        // Method to read an array of integers from input
        public int[] nextIntArray(int n) {
            int[] a = new int[n]; // Array to store integers
            for (int i = 0; i < n; i++)
                a[i] = nextInt(); // Read each integer into the array
            return a; // Return the array
        }

        // Method to read an array of longs from input
        public long[] nextLongArray(int n) {
            long[] a = new long[n]; // Array to store longs
            for (int i = 0; i < n; i++)
                a[i] = nextLong(); // Read each long into the array
            return a; // Return the array
        }

        // Method to check if there is another token in the input
        public boolean hasNext() {
            int value;
            while (isSpaceChar(value = peek()) && value != -1)
                read(); // Skip whitespace characters
            return value != -1; // Return true if there is another token
        }

        // Method to check if a character is a space character
        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }
    }
}

