    // Custom FastScanner class for fast input reading
    static class FastScanner {
        // Reader object for input
        private Reader input;

        // Constructor with default input stream
        public FastScanner() {this(System.in);}
        // Constructor with specified input stream
        public FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));}

        // Method to close the input stream
        public void close() {
            try {
                this.input.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // Method to read the next integer from input
        public int nextInt() {
            long nl = nextLong();
            // Check if the long value is within the integer range
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Method to read the next long integer from input
        public long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters except '-' and '+'
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Determine the sign of the number
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                // Read the numeric value
                long ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Method to read the next double from input
        public double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();
                // Skip non-numeric characters except '-' and '+'
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Determine the sign of the number
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                // Read the integer part of the number
                double ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }
                // If there is no decimal part, return the result
                if (b != '.') return sign * ret;
                // Read the decimal part of the number
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

