                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                // Read characters until whitespace or end of input
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }

        // Method to read the next line from input
        public String nextLine() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();
