import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.NoSuchElementException;

public class Main {
    // Create a static instance of FastScanner for input
    static FastScanner sc = new FastScanner();
    // Create a static instance of PrintWriter for output
    static PrintWriter out = new PrintWriter(System.out);
    // Declare static variables for input values
    static int n;
    static String s;

    public static void main(String[] args) {
        // Read an integer from input and assign it to n
        n = sc.nextInt();
        // Read another integer from input and assign it to a
        int a = sc.nextInt();

        // Calculate the product of n and a, and print it
        out.println(n * a);
        // Flush the output stream to ensure all data is written out
        out.flush();
    }

    // Inner class to handle fast input operations
    static class FastScanner {
        // InputStream to read from standard input
        private final InputStream in = System.in;
        // Buffer to store bytes read from input
        private final byte[] buffer = new byte[1024];
        // Pointer to the current position in the buffer
        private int ptr = 0;
        // Number of bytes currently in the buffer
        private int buflen = 0;

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    // Read bytes into the buffer
                    buflen = in.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                // Return false if no bytes were read
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Skip non-printable characters in the buffer
        private void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
        }

        // Check if there is another token to read
        public boolean hasNext() {
            skipUnprintable();
            return hasNextByte();
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            // Check for negative sign
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            // Ensure the first character is a digit
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            // Read digits and construct the number
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an int
        public int nextInt() {
            return (int) nextLong();
        }

        // Read the next token as a double
        public double nextDouble() {
            return Double.parseDouble(next());
        }

        // Read an array of integers
        public int[] nextIntArray(int N, boolean oneBased) {
            if (oneBased) {
                int[] array = new int[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            } else {
                int[] array = new int[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            }
        }

        // Read an array of longs
        public long[] nextLongArray(int N, boolean oneBased) {
            if (oneBased) {
                long[] array = new long[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            } else {
                long[] array = new long[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            }
        }
    }
}

