public class Main {

    /**
     * This method determines the "last card" based on two input strings.
     * Each character in the strings represents a card type: 'S', 'E', or 'T'.
     * If the characters at the same position in both strings are the same, 
     * the result at that position is the same character.
     * If they are different, the result is the third character that is not present.
     * 
     * @param a First input string representing a sequence of cards.
     * @param b Second input string representing a sequence of cards.
     * @return A string representing the "last card" sequence.
     */
    static String lastcard(String a, String b) {
        int k = a.length(); // Length of the input strings
        String ret = ""; // Resultant string to store the "last card" sequence
        for (int i = 0; i < k; i++) {
            if (a.charAt(i) == b.charAt(i)) {
                ret += a.charAt(i); // If characters are the same, append it to the result
            } else {
                // Determine the third character that is not present
                if (a.charAt(i) == 'S' && b.charAt(i) == 'E' || a.charAt(i) == 'E' && b.charAt(i) == 'S') {
                    ret += 'T';
                }
                else if (a.charAt(i) == 'S' && b.charAt(i) == 'T' || a.charAt(i) == 'T' && b.charAt(i) == 'S') {
                    ret += 'E';
                }
                else if (a.charAt(i) == 'E' && b.charAt(i) == 'T' || a.charAt(i) == 'T' && b.charAt(i) == 'E') {
                    ret += 'S';
                }
            }
        }
        return ret; // Return the resultant "last card" sequence
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in); // Scanner for reading input

        // Read the number of problems and submissions
        int probs = sc.nextInt();
        int subs = sc.nextInt();

        // Array to track if a problem is solved correctly
        boolean[] ac = new boolean[probs + 1];

        // Array to track the number of wrong attempts for each problem
        int[] pentrack = new int[probs + 1];

        int correct = 0; // Counter for correctly solved problems
        int penalty = 0; // Counter for penalty points

        // Process each submission
        for (int i = 0; i < subs; i++) {
            int id = sc.nextInt(); // Problem ID
            String s = sc.next(); // Submission result (WA or AC)

            // If the submission is wrong and the problem is not yet solved
            if (s.equals("WA") && ac[id] == false) {
                ++pentrack[id]; // Increment the penalty count for the problem
            } 
            // If the submission is correct and the problem is not yet solved
            else if (s.equals("AC") && ac[id] == false) {
                ac[id] = true; // Mark the problem as solved
                ++correct; // Increment the correct counter
            }
        }

        // Calculate the total penalty for correctly solved problems
        for (int i = 0; i < pentrack.length; ++i) {
            if (ac[i]) {
                penalty += pentrack[i]; // Add the penalty for each solved problem
            }
        }

        // Output the number of correct solutions and the total penalty
        System.out.println(correct + " " + penalty);
    }

    /**
     * Checks if a number is even.
     * 
     * @param n The number to check.
     * @return True if the number is even, false otherwise.
     */
    static boolean isEven(int n) {
        return n % 2 == 0;
    }

    /**
     * Checks if a number is odd.
     * 
     * @param n The number to check.
     * @return True if the number is odd, false otherwise.
     */
    static boolean isOdd(int n) {
        return n % 2 == 1;
    }

    /**
     * Checks if a number is prime.
     * 
     * @param n The number to check.
     * @return True if the number is prime, false otherwise.
     */
    static boolean isPrime(int n) {
        if (n == 0 || n == 1) {
            return false; // 0 and 1 are not prime numbers
        } else {
            // Check divisibility from 2 to the square root of n
            for (int i = 2; i * i <= n; i++) {
                if (n % i == 0) {
                    return false; // If divisible, n is not prime
                }
            }
            return true; // If not divisible by any number, n is prime
        }
    }
}

class Pair {
    public int x; // First element of the pair
    public int y; // Second element of the pair

    /**
     * Constructor to initialize the pair with two integers.
     * 
     * @param x First integer.
     * @param y Second integer.
     */
    public Pair(int x, int y) {
        this.x = x;
        this.y = y;
    }

    /**
     * Overrides the equals method to compare two Pair objects.
     * 
     * @param o The object to compare with.
     * @return True if the objects are equal, false otherwise.
     */
    @Override
    public boolean equals(Object o) {
        if (o == this) {
            return true; // If the same object, they are equal
        } else if (!(o instanceof Pair)) {
            return false; // If not a Pair instance, they are not equal
        } else {
            Pair p = (Pair)o;
            return this.x == p.x && this.y == p.y; // Compare the elements of the pair
        }
    }

    /**
     * Overrides the hashCode method to generate a hash code for the Pair object.
     * 
     * @return The hash code of the Pair object.
     */
    @Override
    public int hashCode() {
        return Arrays.hashCode(new int[]{this.x, this.y}); // Generate hash code based on the elements
    }

    /**
     * Overrides the toString method to provide a string representation of the Pair object.
     * 
     * @return A string representation of the Pair object.
     */
    @Override
    public String toString() {
        return "(" + this.x + ", " + this.y + ")"; // Format the pair as a string
    }
}

