public class Main {

	public static void main(String[] args) {
		// Create a Scanner object to read input from the console
		Scanner s = new Scanner(System.in);

		// Boolean flag to determine if a number is prime
		boolean is_prime = true;

		// Array of known prime numbers less than 10
		Integer[] prime_10 = {2, 3, 5, 7};

		// Initialize an ArrayList with prime numbers less than 10
		ArrayList<Integer> prime_100 = new ArrayList<Integer>(Arrays.asList(prime_10));

		// Loop through numbers from 10 to 99 to find prime numbers
		for(int i = 10; i < 100; i++){
			is_prime = true; // Assume the number is prime

			// Check divisibility by known primes less than 10
			for(int j = 0; j < prime_10.length; j++){
				if(i %  prime_10[j] == 0){
					is_prime = false; // Not prime if divisible by any known prime
					break; // Exit loop early if not prime
				}
			}

			// If the number is prime, add it to the list
			if(is_prime){
				prime_100.add(i);
			}
		}

		// Initialize an ArrayList to store prime numbers less than 10,000
		ArrayList<Integer> prime_10000 = new ArrayList<Integer>();

		// Loop through numbers from 2 to 9,999 to find prime numbers
		for(int i = 2; i < 10000; i++){
			is_prime = true; // Assume the number is prime

			// Check divisibility by known primes less than 100
			for(int j = 0; j < prime_100.size(); j++){
				Integer prime = prime_100.get(j);
				if(i != prime && i % prime == 0){
					is_prime = false; // Not prime if divisible by any known prime
					break; // Exit loop early if not prime
				}
			}

			// If the number is prime, add it to the list
			if(is_prime){
				prime_10000.add(i);
			}
		}

		// Initialize an ArrayList to store the result of prime numbers from input
		ArrayList<Integer> result = new ArrayList<Integer>();

		// Read numbers from input until there are no more
		while(s.hasNext()){
			Integer number = Integer.parseInt(s.next()); // Parse the input as an integer
			is_prime = true; // Assume the number is prime

			// Skip numbers already in the result list
			if(result.contains(number)){
				continue;
			}

			// Check divisibility by known primes less than 10,000
			for(int j = 0; j < prime_10000.size(); j++){
				Integer prime = prime_10000.get(j);
				if(!number.equals(prime) && number % prime == 0){
					is_prime = false; // Not prime if divisible by any known prime
					break; // Exit loop early if not prime
				}
			}

			// If the number is prime, add it to the result list
			if(is_prime){
				result.add(number);
			}
		}

		// Print the size of the result list, which is the count of unique prime numbers from input
		System.out.println(result.size());

		// Close the scanner to free up resources
		s.close();
	}
}

import java.io.BufferedInputStream;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main{

	public static void main(String[] args) {
		// Create a Scanner object to read input from the standard input stream
		Scanner scan = new Scanner(new BufferedInputStream(System.in));

		// Initialize a list to store the results of operations
		List<String> output = new ArrayList<String>();

		// Continuously read input until a termination condition is met
		while (scan.hasNext()) {
			// Read the next line of input
			String input = scan.nextLine();

			// Split the input line into parts based on spaces
			String[] in = input.split(" ");

			// Parse the first part as an integer (operand a)
			int a = Integer.parseInt(in[0]);

			// The second part is the operator
			String op = in[1];

			// Parse the third part as an integer (operand b)
			int b = Integer.parseInt(in[2]);

			// Check if the operator is "?" which indicates termination
			if ("?".equals(op)) {
				break; // Exit the loop if termination condition is met
			} else {
				// Ensure both operands are within the valid range [0, 20000]
				if (a >= 0 && a <= 20000 && b >= 0 && b <= 20000) {
					// Perform addition if the operator is "+"
					if ("+".equals(op)) {
						int result = a + b; // Calculate the sum
						output.add(String.valueOf(result)); // Add result to output list
					} 
					// Perform subtraction if the operator is "-"
					else if ("-".equals(op)) {
						int result = a - b; // Calculate the difference
						output.add(String.valueOf(result)); // Add result to output list
					} 
					// Perform multiplication if the operator is "*"
					else if ("*".equals(op)) {
						int result = a * b; // Calculate the product
						output.add(String.valueOf(result)); // Add result to output list
					} 
					// Perform division if the operator is "/"
					else if ("/".equals(op)) {
						// Ensure the divisor is not zero to avoid division by zero error
						if (b != 0) {
							int result = a / b; // Calculate the quotient
							output.add(String.valueOf(result)); // Add result to output list
						}
					}
				}
			}
		}

		// Iterate over the list of results and print each one
		for (String out : output) {
			System.out.println(out); // Output the result
		}
	}

}

import java.util.Scanner;

class Main {
  public static void main(String[] args) {
    // Create a Scanner object to read input from the console
    Scanner sc = new Scanner(System.in);

    // Initialize variables to store input values
    int N = 0; // Total number of positions
    int M = 0; // Number of special positions
    int X = 0; // Starting position

    // Read a valid value for N (1 <= N <= 100)
    while (N < 1 || N > 100) {
      N = sc.nextInt();
    }

    // Read a valid value for M (1 <= M <= 100)
    while (M < 1 || M > 100) {
      M = sc.nextInt();
    }

    // Read a valid value for X (1 <= X <= N - 1)
    while (X < 1 || X > N - 1) {
      X = sc.nextInt();
    }

    // Array to store the special positions
    int[] A = new int[M];
    int s; // Temporary variable to store input for special positions

    // Read M special positions, ensuring each is valid and not equal to X
    for (int i = 0; i <= M - 1; i++) {
      s = 0;

      // Ensure the special position is valid (1 <= s <= N - 1) and not equal to X
      while (s < 1 || s > N - 1 || s == X) {
        s = sc.nextInt();
      }
      A[i] = s; // Store the valid special position in the array
    }

    // Initialize variables for counting special positions in both directions
    int X2 = X; // Temporary variable for traversing positions
    int c1 = 0; // Counter for special positions from X to N-1

    // Count special positions from X to N-1
    while (X2 <= N - 1) {
      for (int ii = 0; ii <= M - 1; ii++) {
        if (A[ii] == X2) {
          c1++; // Increment counter if a special position matches
        }
      }
      X2++; // Move to the next position
    }

    // Reset X2 to X for counting in the opposite direction
    X2 = X;
    int c2 = 0; // Counter for special positions from X to 0

    // Count special positions from X to 0
    while (X2 >= 0) {
      for (int iii = 0; iii <= M - 1; iii++) {
        if (A[iii] == X2) {
          c2++; // Increment counter if a special position matches
        }
      }
      X2--; // Move to the previous position
    }

    // Output the smaller count of special positions between the two directions
    if (c1 < c2) {
      System.out.println(c1);
    } else {
      System.out.println(c2);
    }
  }
}

