        int[][] has_cards = new int[4][13];

        // Populate the cards array with card numbers for each suit
        for(int m = 0; m < 4; m++){
            for(int i = 0; i < 13; i++){
                cards[m][i] = i + 1; // Card numbers range from 1 to 13
            }
