import java.io.IOException;
import java.io.InputStream;
import java.util.*;

public class Main {
	public static void main(String[] args) {
		// Create an instance of FastScanner to read input
		FastScanner sc = new FastScanner();

		// Read the number of elements in the array
		int n = sc.nextInt();

		// Initialize an array to store the elements
		int[] a = new int[n];

		// Read each element into the array
		for (int i = 0; i < n; i++) {
			a[i] = sc.nextInt();
		}

		// Flag to check if any swaps were made in the last pass
		boolean flag = true;

		// Counter to keep track of the number of swaps made
		int count = 0;

		// Perform a bubble sort on the array
		while (flag) {
			// Assume no swaps will be made
			flag = false;

			// Traverse the array from the end to the beginning
			for (int i = n - 1; i > 0; i--) {
				// If the current element is less than the previous element, swap them
				if (a[i] < a[i - 1]) {
					// Swap the elements
					int tmp = a[i];
					a[i] = a[i - 1];
					a[i - 1] = tmp;

					// Set flag to true to indicate a swap was made
					flag = true;

					// Increment the swap counter
					count++;
				}
			}
		}

		// Print the sorted array
		for (int i = 0; i < n; i++) {
			System.out.print(a[i]);
			if (i < n - 1) {
				System.out.print(" ");
			} else {
				System.out.println();
			}
		}

		// Print the total number of swaps made
		System.out.println(count);
	}
}

class FastScanner {
	// InputStream to read from standard input
	private final InputStream in = System.in;

	// Buffer to store bytes read from the input
	private final byte[] buffer = new byte[1024];

	// Pointer to the current position in the buffer
	private int ptr = 0;

	// Number of bytes currently in the buffer
	private int buflen = 0;

	// Check if there is another byte to read
	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true;
		} else {
			ptr = 0;
			try {
				// Read bytes into the buffer
				buflen = in.read(buffer);
			} catch (IOException e) {
				e.printStackTrace();
			}
			// Return false if no bytes were read
			if (buflen <= 0) {
				return false;
			}
		}
		return true;
	}

	// Read the next byte from the buffer
	private int readByte() {
		if (hasNextByte()) {
			return buffer[ptr++];
		} else {
			return -1;
		}
	}

	// Check if a character is printable
	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126;
	}

	// Check if there is another token to read
	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr])) {
			ptr++;
		}
		return hasNextByte();
	}

	// Read the next token as a String
	public String next() {
		if (!hasNext()) {
			throw new NoSuchElementException();
		}
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b);
			b = readByte();
		}
		return sb.toString();
	}

	// Read the next token as a long
	public long nextLong() {
		if (!hasNext()) {
			throw new NoSuchElementException();
		}
		long n = 0;
		boolean minus = false;
		int b = readByte();
		if (b == '-') {
			minus = true;
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException();
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0';
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n;
			} else {
				throw new NumberFormatException();
			}
			b = readByte();
		}
	}

	// Read the next token as an int
	public int nextInt() {
		long nl = nextLong();
		if (nl < Integer.MIN_VALUE || Integer.MAX_VALUE < nl) {
			throw new NumberFormatException();
		}
		return (int) nl;
	}

	// Read the next token as a double
	public double nextDouble() {
		return Double.parseDouble(next());
	}
}

