        for (int i = 0; i < N; i++) {
            // Read the size of the i-th array
            K[i] = sc.nextInt();
            // Read the elements of the i-th array
            for (int j = 0; j < K[i]; j++) {
                A[i][j] = sc.nextInt();
            }
        }

        // Check if there is more than one array
        if (N > 1) {
            // Iterate over each element in the first array
            for (int i = 0; i < M; i++) {
                // Loop through each of the remaining arrays
                loop: for (int j = 1; j < N; j++) {
                    // Check if the current element of the first array is present in the j-th array
                    for (int k = 0; k < K[j]; k++) {
                        if (A[0][i] == A[j][k]) {
                            // If found, increment x and break out of the loop
                            x += 1;
                            break;
                        } else if (A[0][i] != A[j][M - 1] && k == M - 1) {
                            // If not found in the last position of the j-th array, reset x and break the outer loop
                            x = 0;
                            break loop;
                        }
                    }
                }
                // If the element is found in all arrays, increment the answer
                if (x == N) {
                    ans += 1;
                }
                // Reset x for the next element
                x = 1;
            }
        }

        // If there is only one array, the answer is simply the number of elements in that array
        if (N == 1) {
            ans = K[0];
        }

        // Print the final count of common elements
        System.out.println(ans);
    }
}

