        }

        // Assign the extracted digits to variables a, b, c, and e
        int a = d[3]; // Most significant digit
        int b = d[2];
        int c = d[1];
        int e = d[0]; // Least significant digit

        // Initialize variables for switch case logic
        int k = 1; // Starting case number
        int j = 0; // Variable to store the result of operations

        // Use a switch statement to check different combinations of operations
        switch(k){
            // Case 1: Check if the sum of all digits equals 7
            case 1:
                j = a + b + c + e;
                if(j == 7){
                    System.out.println(a + "+" + b + "+" + c + "+" + e + "=7");
                    break;
                }
            // Case 2: Check if subtracting b from a and adding c and e equals 7
            case 2:
                j = a - b + c + e;
                if(j == 7){
                    System.out.println(a + "-" + b + "+" + c + "+" + e + "=7");
                    break;
                }
            // Case 3: Check if subtracting b and e from a and adding c equals 7
            case 3:
                j = a - b + c - e;
                if(j == 7){
                    System.out.println(a + "-" + b + "+" + c + "-" + e + "=7");
                    break;
                }
            // Case 4: Check if subtracting b and c from a and adding e equals 7
            case 4:
                j = a - b - c + e;
                if(j == 7){
                    System.out.println(a + "-" + b + "-" + c + "+" + e + "=7");
                    break;
                }
            // Case 5: Check if subtracting b, c, and e from a equals 7
            case 5:
                j = a - b - c - e;
                if(j == 7){
                    System.out.println(a + "-" + b + "-" + c + "-" + e + "=7");
                    break;
                }
            // Case 6: Check if adding b and e to a and subtracting c equals 7
            case 6:
                j = a + b - c + e;
                if(j == 7){
                    System.out.println(a + "+" + b + "-" + c + "+" + e + "=7");
                    break;
                }
            // Case 7: Check if adding b and c to a and subtracting e equals 7
            case 7:
                j = a + b + c - e;
                if(j == 7){
                    System.out.println(a + "+" + b + "+" + c + "-" + e + "=7");
                    break;
                }
            // Case 8: Check if adding b to a and subtracting c and e equals 7
            case 8:
                j = a + b - c - e;
                if(j == 7){
                    System.out.println(a + "+" + b + "-" + c + "-" + e + "=7");
                    break;
                }
            // Default case: If no combination results in 7, print an error message
            default:
                System.out.println("間違い"); // "間違い" means "mistake" in Japanese
                break;
        }
    }
}

