    public static void main(String[] args) throws IOException {
        // Initialize the FastScanner for input
        in = new FastScanner();

        // Read three integers from input: n, a, and b
        int n = in.intNext(), a = in.intNext(), b = in.intNext();

        // Calculate the largest multiple of n that is less than or equal to a
        int div = (a / n) * n;

        // If this multiple is less than a, increment it by n to get the next multiple
        if (div < a) div += n;

        // Check if this multiple is within the range [a, b]
        // Print "OK" if it is, otherwise print "NG"
        out.println((div <= b) ? "OK" : "NG");

        // Close the FastWriter to flush the output
        out.close();
    }

    // Static instance of FastWriter for output
    private static final FastWriter out = new FastWriter();
    // Static instance of FastScanner for input
    private static FastScanner in;
    // Adjacency list for graph representation (not used in main logic)
    static ArrayList<Integer>[] adj;
    // A constant value used for modular arithmetic (not used in main logic)
    private static long e97 = (long)1e9 + 7;

    // FastWriter class for efficient output operations
    static class FastWriter {
        private static final int IO_BUFFERS = 128 * 1024; // Buffer size for output
        private final StringBuilder out; // StringBuilder to accumulate output

        // Constructor initializes the StringBuilder with a buffer size
        public FastWriter() {
            out = new StringBuilder(IO_BUFFERS);
        }

        // Append an object to the output
        public FastWriter p(Object object) {
            out.append(object);
            return this;
        }

        // Append a formatted string to the output
        public FastWriter p(String format, Object... args) {
            out.append(String.format(format, args));
            return this;
        }

        // Append multiple objects to the output, separated by spaces
        public FastWriter pp(Object... args) {
            for (Object ob : args) {
                out.append(ob).append(" ");
            }
            out.append("\n");
            return this;
        }

        // Append an object followed by a newline to the output
        public FastWriter println(Object object) {
            out.append(object).append("\n");
            return this;
        }

        // Write the accumulated output to a file
        public void toFile(String fileName) throws IOException {
            BufferedWriter writer = new BufferedWriter(new FileWriter(fileName));
            writer.write(out.toString());
            writer.close();
        }

        // Print the accumulated output to the console
        public void close() throws IOException {
            System.out.print(out);
        }
    }

    // FastScanner class for efficient input operations
    static class FastScanner {
        private InputStream sin = System.in; // Input stream for reading data
        private final byte[] buffer = new byte[1024]; // Buffer for input
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Default constructor using standard input
        public FastScanner(){}

        // Constructor to read from a file
        public FastScanner(String filename) throws FileNotFoundException {
            File file = new File(filename);
            sin = new FileInputStream(file);
        }

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    buflen = sin.read(buffer);
                } catch (IOException e) {
                    e.printStackTrace();
                }
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() { 
            if (hasNextByte()) return buffer[ptr++]; 
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) { 
            return 33 <= c && c <= 126;
        }

        // Check if there is another token to read
        public boolean hasNext() { 
            while(hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; 
            return hasNextByte();
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while(isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long
        public long longNext() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while(true){
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if(b == -1 || !isPrintableChar(b) || b == ':'){
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an int
        public int intNext() {
            long nl = longNext();
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Read the next token as a double
        public double doubleNext() { 
            return Double.parseDouble(next());
        }

        // Read an array of longs
        public long[] nextLongArray(final int n){
            final long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = longNext();
            return a;
        }

        // Read an array of ints
        public int[] nextIntArray(final int n){
            final int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = intNext();
            return a;
        }

        // Initialize an adjacency list for a graph with n nodes
        public ArrayList<Integer>[] getAdj(int n) {
            ArrayList<Integer>[] adj = new ArrayList[n + 1];
            for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
            return adj;
        }

        // Create an adjacency list for a graph with n nodes and m edges
        public ArrayList<Integer>[] adjacencyList(int n, int m) throws IOException {
            adj = getAdj(n);
            for (int i = 0; i < m; i++) {
                int a = intNext(), b = intNext();
                adj[a].add(b);
                adj[b].add(a);
            }
            return adj;
        }
    }
}

