import java.util.NoSuchElementException;

public class Main {
    // Static instance of FastScanner for input operations
    static FastScanner sc = new FastScanner();
    // Static instance of PrintWriter for output operations
    static PrintWriter out = new PrintWriter(System.out);
    // Variable to store the number of elements
    static int n;
    // Variable to store a string input (not used in this code)
    static String s;

    // Constant to define the upper limit for multiplication
    static final long lim = 1_000_000_000_000_000_000L;

    public static void main(String[] args) {
        // Read the number of elements
        n = sc.nextInt();

        // Read an array of long integers
        long a[] = sc.nextLongArray(n, false);

        // Sort the array in ascending order
        Arrays.sort(a);

        // If the smallest element is zero, the product is zero
        if (a[0] == 0)
            out.println(0);
        else {
            // Initialize the product with the first element
            long A = a[0];
            // Flag to check if the product exceeds the limit
            boolean ok = true;
            // Iterate through the array to calculate the product
            for (int i = 1; i < n; i++) {
                long cur = a[i];

                // Check if the current product will exceed the limit
                if (cur <= lim / A) {
                    A *= cur; // Update the product
                } else {
                    ok = false; // Set flag to false if limit is exceeded
                    break;
                }
            }

            // Output the result based on the flag
            if (ok)
                out.println(A);
            else
                out.println(-1);
        }
        // Flush the output stream
        out.flush();
    }

    // FastScanner class for efficient input operations
    static class FastScanner {
        private final InputStream in = System.in; // Input stream
        private final byte[] buffer = new byte[1024]; // Buffer for input
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Check if there is a next byte in the input
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    buflen = in.read(buffer); // Read data into buffer
                } catch (IOException e) {
                    e.printStackTrace();
                }
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the input
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Skip non-printable characters in the input
        private void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
        }

        // Check if there is a next token in the input
        public boolean hasNext() {
            skipUnprintable();
            return hasNextByte();
        }

        // Read the next token as a string
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long integer
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an integer
        public int nextInt() {
            return (int) nextLong();
        }

        // Read the next token as a double
        public double nextDouble() {
            return Double.parseDouble(next());
        }

        // Read an array of integers
        public int[] nextIntArray(int N, boolean oneBased) {
            if (oneBased) {
                int[] array = new int[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            } else {
                int[] array = new int[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            }
        }

        // Read an array of long integers
        public long[] nextLongArray(int N, boolean oneBased) {
            if (oneBased) {
                long[] array = new long[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            } else {
                long[] array = new long[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            }
        }
    }
