import java.io.*;
import java.util.InputMismatchException;

public class Main {
    public static void main(String[] xps){
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Create an InputReader instance for reading input
        InputReader in = new InputReader(inputStream);

        // Create a PrintWriter instance for writing output
        PrintWriter out = new PrintWriter(outputStream);

        // StringBuilder for efficient string manipulation
        StringBuilder sb = new StringBuilder();

        // Read a string from input
        String s = in.String();

        // Check if the input string is "ABC"
        if (s.equals("ABC"))
            // If true, print "ARC"
            out.println("ARC");
        else
            // Otherwise, print "ABC"
            out.println("ABC");

        // Close the output stream
        out.close();
    }

    // Custom InputReader class for handling input operations
    private static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer for reading input
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) {
                // If no more characters are available, throw an exception
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                // If current character index exceeds buffer, refill the buffer
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    // Handle IOException by throwing InputMismatchException
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    // If no characters were read, return -1
                    return -1;
                }
            }
            // Return the next character from the buffer
            return buf[curChar++];
        }

        // Method to read an integer from input
        public int Int() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                // If negative sign is found, set sign to -1
                sgn = -1;
                c = read();
            }
            int res = 0; // Resulting integer
            do {
                if (c < '0' || c > '9') {
                    // If non-digit character is found, throw exception
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until space character is found
            return res * sgn; // Return the signed integer
        }

        // Method to read a string from input
        public String String() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            StringBuilder res = new StringBuilder();
            do {
                // Append each character to the StringBuilder
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c)); // Continue until space character is found
            return res.toString(); // Return the resulting string
        }

        // Method to read a double from input
        public double Double() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                // If negative sign is found, set sign to -1
                sgn = -1;
                c = read();
            }
            double res = 0; // Resulting double
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    // Handle scientific notation
                    return res * Math.pow(10, Int());
                }
                if (c < '0' || c > '9') {
                    // If non-digit character is found, throw exception
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            }
            if (c == '.') {
                // Handle decimal part
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        // Handle scientific notation
                        return res * Math.pow(10, Int());
                    }
                    if (c < '0' || c > '9') {
                        // If non-digit character is found, throw exception
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m; // Add decimal part
                    c = read();
                }
            }
            return res * sgn; // Return the signed double
        }

        // Method to read a long integer from input
        public long Long() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1; // Sign of the number
            if (c == '-') {
                // If negative sign is found, set sign to -1
                sgn = -1;
                c = read();
            }
            long res = 0; // Resulting long integer
            do {
                if (c < '0' || c > '9') {
                    // If non-digit character is found, throw exception
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until space character is found
            return res * sgn; // Return the signed long integer
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                // Use custom filter if available
                return filter.isSpaceChar(c);
            }
            // Default space characters
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Method to read the next token as a string
        public String next() {
            return String();
        }

        // Interface for custom space character filtering
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }
}

