class PrimeIterator implements Iterable<Integer>, PrimitiveIterator.OfInt {
    // BitSet to store prime numbers; true means the index is a prime
    BitSet bitset;
    // Current value in the iteration
    private int currentvalue;
    // Upper limit for prime numbers
    private int limit;

    // Constructor to initialize the PrimeIterator with a given limit
    public PrimeIterator(int limit) {
        currentvalue = 0;
        // Initialize the BitSet with size limit + 1
        bitset = new BitSet(limit + 1);
        this.limit = limit;
        // Construct the BitSet with prime numbers
        construct();
    }

    // Method to construct the BitSet using a prime number sieve algorithm
    private final void construct() {
        // Calculate the square root of the limit for optimization
        int sqLim = (int) Math.sqrt(limit + 0.5);
        {
            int n;
            // Loop through specific patterns to mark non-prime numbers
            for (int z = 1; z <= 5; z += 4) {
                for (int y = z; y <= sqLim; y += 6) {
                    int ysq = y * y;
                    for (int x = 1; x <= sqLim && (n = 4 * x * x + ysq) <= limit; ++x)
                        bitset.flip(n); // Flip the bit to mark non-prime
                    for (int x = y + 1; x <= sqLim && (n = 3 * x * x - ysq) <= limit; x += 2)
                        bitset.flip(n); // Flip the bit to mark non-prime
                }
            }
            for (int z = 2; z <= 4; z += 2) {
                for (int y = z; y <= sqLim; y += 6) {
                    int ysq = y * y;
                    for (int x = 1; x <= sqLim && (n = 3 * x * x + ysq) <= limit; x += 2)
                        bitset.flip(n); // Flip the bit to mark non-prime
                    for (int x = y + 1; x <= sqLim && (n = 3 * x * x - ysq) <= limit; x += 2)
                        bitset.flip(n); // Flip the bit to mark non-prime
                }
            }
            for (int y = 3; y <= sqLim; y += 6) {
                int ysq = y * y;
                for (int z = 1; z <= 2; ++z)
                    for (int x = z; x <= sqLim && (n = 4 * x * x + ysq) <= limit; x += 3)
                        bitset.flip(n); // Flip the bit to mark non-prime
            }
        }
        {
            // Clear multiples of each prime number found
            for (int n = 5; n <= sqLim && n != -1; n = bitset.nextSetBit(n + 1)) {
                int nsq = n * n;
                for (int k = nsq; k <= limit; k += nsq)
                    bitset.clear(k); // Clear the bit to mark non-prime
            }
        }
        // Set the bits for the first two prime numbers
        bitset.set(2);
        bitset.set(3);
    }

    @Override
    public boolean hasNext() {
        // Check if there is a next prime number in the BitSet
        int r = getNextValue();
        return 0 <= r && r <= limit;
    }

    // Get the next prime number from the BitSet
    private int getNextValue() {
        return bitset.nextSetBit(currentvalue + 1);
    }

    @Override
    public int nextInt() {
        // Get the next prime number and update the current value
        int r = getNextValue();
        if (r < 0 || limit < r) throw new NoSuchElementException();
        return currentvalue = r;
    }

    @Override
    public OfInt iterator() {
        // Return this object as an iterator
        return this;
    }

    // Return a clone of the BitSet containing prime numbers
    public BitSet getClonedBitSet() {
        return (BitSet) bitset.clone();
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

class Main {
	public static void main(String[] args) {
		// Create an InputStreamReader to read bytes from the standard input stream (System.in)
		InputStreamReader isr = new InputStreamReader(System.in);
		// Wrap the InputStreamReader with a BufferedReader for efficient reading of text data
		BufferedReader br = new BufferedReader(isr);
		try {
			// Initialize a list to store the results for each input case
			List<Integer> ret = new ArrayList<Integer>();
			int n, x; // Declare variables to store the input values
			do {
				// Read a line of input and split it into an array of strings
				String[] inputList = br.readLine().split(" ");
				// Parse the first and second elements of the array as integers
				n = Integer.parseInt(inputList[0]);
				x = Integer.parseInt(inputList[1]);

				// Check for the termination condition where both n and x are zero
				if (n == 0 && x == 0) {
					break; // Exit the loop if the termination condition is met
				} else {
					// If x is less than 6, it's impossible to have three distinct numbers that sum to x
					if (x < 6) {
						ret.add(0); // Add 0 to the results list
					} else {
						// Initialize a list to store unique combinations of three numbers
						List<int[]> hoge = new ArrayList<int[]>();
						int a, b, c; // Declare variables for the three numbers

						// Iterate over all possible values for a, b, and c
						for (a = 1; a <= n; a++) {
							for (b = 1; b <= n; b++) {
								for (c = 1; c <= n; c++) {
									// Check if a, b, and c are distinct and their sum equals x
									if (!(a == b || b == c || a == c) && a + b + c == x) {
										boolean flg = true; // Flag to check if the combination is unique

										// Check if the combination already exists in the list
										for (int[] list : hoge) {
											if ((list[0] == a || list[0] == b || list[0] == c)
													&& (list[1] == a || list[1] == b || list[1] == c)
													&& (list[2] == a || list[2] == b || list[2] == c)) {
												flg = false; // Set flag to false if combination is not unique
												break; // Exit the loop as the combination is already present
											}
										}

										// If the combination is unique, add it to the list
										if (flg) {
											int[] tmp = new int[3]; // Create an array to store the combination
											tmp[0] = a;
											tmp[1] = b;
											tmp[2] = c;
											hoge.add(tmp); // Add the combination to the list
											break; // Exit the innermost loop after adding the combination
										}
									}
								}
							}
						}
						// Add the size of the list (number of unique combinations) to the results
						ret.add(hoge.size());
					}
				}
			} while (true); // Continue the loop indefinitely until a break statement is encountered

			// Print each result stored in the list
			for (int num : ret) {
				System.out.println(num);
			}
		} catch (IOException e) {
			// Print the stack trace if an IOException occurs
			e.printStackTrace();
		}
	}
}

