import java.io.*;
import java.util.*;

public class Main {
    // FastReader class for fast input operations
    public static class FastReader {
        private InputStream stream; // Input stream to read from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) // If end of stream is reached
                throw new InputMismatchException();
            if (curChar >= numChars) { // If all characters in buffer are processed
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read more characters into the buffer
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) // If no more characters are available
                    return -1;
            }
            return buf[curChar++]; // Return the next character
        }

        // Method to read the next line of input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the input
            } catch (IOException e) {
                e.printStackTrace();
            }
            return str;
        }

        // Method to read the next integer from input
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c)) // Skip space characters
                c = read();
            int sgn = 1; // Sign of the number
            if (c == '-') { // If the number is negative
                sgn = -1;
                c = read();
            }
            int res = 0; // Resulting integer
            do {
                if (c < '0' || c > '9') // If the character is not a digit
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is found
            return res * sgn; // Return the integer with its sign
        }

        // Method to read the next long integer from input
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c)) // Skip space characters
                c = read();
            int sgn = 1; // Sign of the number
            if (c == '-') { // If the number is negative
                sgn = -1;
                c = read();
            }
            long res = 0; // Resulting long integer
            do {
                if (c < '0' || c > '9') // If the character is not a digit
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0'; // Convert character to long integer
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is found
            return res * sgn; // Return the long integer with its sign
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c)) // Skip space characters
                c = read();
            int sgn = 1; // Sign of the number
            if (c == '-') { // If the number is negative
                sgn = -1;
                c = read();
            }
            double res = 0; // Resulting double
            while (!isSpaceChar(c) && c != '.') { // Process integer part
                if (c == 'e' || c == 'E') // Handle scientific notation
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9') // If the character is not a digit
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0'; // Convert character to double
                c = read();
            }
            if (c == '.') { // Process fractional part
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') // Handle scientific notation
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9') // If the character is not a digit
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m; // Convert character to double
                    c = read();
                }
            }
            return res * sgn; // Return the double with its sign
        }

        // Method to read the next character from input
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c)) // Skip space characters
                c = read();
            return (char) c; // Return the character
        }

        // Method to read the next word from input
        public String next() {
            int c = read();
            while (isSpaceChar(c)) // Skip space characters
                c = read();
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is found
            return res.toString(); // Return the word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c);
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading input
        OutputStream outputStream = System.out; // Output stream for writing output
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter for output

        long n, i, b = 0; // Variables for input and calculations
        long min; // Variable to store the minimum value

        n = in.nextLong(); // Read the input number
        min = n - 1; // Initialize min with n-1

        // Loop to find the minimum value of i + b - 2 where n = i * b
        for (i = 1; i <= (int) Math.pow(n, 0.5); i++) {
            b = n / i; // Calculate b as n divided by i
            if (n == b * i) { // Check if i * b equals n
                if (min > i + b - 2) { // Update min if a smaller value is found
                    min = i + b - 2;
                }
            }
        }

        w.println(min); // Print the minimum value
        w.close(); // Close the PrintWriter
    }
}

import java.util.Scanner;

public class Main {

    public static void main(String[] args) {

        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read a line of input from the user
        String input = sc.nextLine();

        // Initialize an empty string to store the output
        String output = "";

        // Split the input string into an array of words based on spaces
        String[] mozi = input.split(" ");

        // Strings containing uppercase and lowercase alphabets
        String UpperAlpha = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        String LowerAlpha = "abcdefghijklmnopqrstuvwxyz";

        // Variable to keep track of the total length of all words
        int mozi_length = 0;

        // Variables to store the index of characters in the alphabet strings
        int index1 = -1;
        int index2 = -1;

        // Iterate over each word in the input
        for (int i = 0; i < mozi.length; i++) {
            // Add the length of the current word to the total length
            mozi_length += mozi[i].length();

            // Add a space before each word in the output except the first one
            if (i != 0) {
                output += " ";
            }

            // Iterate over each character in the current word
            for (int j = 0; j < mozi[i].length(); j++) {
                // Find the index of the character in the uppercase alphabet
                index1 = UpperAlpha.indexOf(mozi[i].charAt(j));

                // Find the index of the character in the lowercase alphabet
                index2 = LowerAlpha.indexOf(mozi[i].charAt(j));

                // If the character is not found in either alphabet, add it as is
                if (index1 == -1 && index2 == -1) {
                    output += "" + mozi[i].charAt(j);
                } 
                // If the character is uppercase, convert it to lowercase
                else if (index1 != -1) {
                    output += "" + LowerAlpha.charAt(index1);
                } 
                // If the character is lowercase, convert it to uppercase
                else if (index2 != -1) {
                    output += "" + UpperAlpha.charAt(index2);
                }
            }
        }

        // If the total length of all words is less than 1200, print the output
        if (mozi_length < 1200) {
            System.out.println(output);
        }
    }
}

