import java.io.*;
import java.lang.reflect.Array;
import java.util.*;

@SuppressWarnings("unused")
public class Main {
    // FastScanner instance for reading input
    private FastScanner in = new FastScanner(System.in);
    // PrintWriter instance for writing output
    private PrintWriter out = new PrintWriter(System.out);
    // Constant for modulo operations, typically used in competitive programming
    final int MOD = (int)1e9+7;

    // Method to calculate the ceiling of a division between two long integers
    long ceil(long a, long b) {
        return (a + b - 1) / b;
    }

    // Main logic of the program
    void solve() throws Exception {
        // Read the number of elements
        int N = in.nextInt();
        // Initialize sum variables
        long sum1 = 0, sum2 = 0;
        // Array to store the elements
        int[] d = new int[N];
        // Loop to read elements and calculate sums
        for(int i = 0; i < N; i++) {
            d[i] = in.nextInt(); // Read each element
            sum1 += d[i]; // Sum of elements
            sum2 += d[i] * d[i]; // Sum of squares of elements
        }
        // Calculate and print the result based on the formula (sum1^2 - sum2) / 2
        out.println((sum1 * sum1 - sum2) / 2);
    }

    public static void main(String[] args) throws Exception {
        // Create an instance of Main and call the method m
        new Main().m();
    }

    // Method to call solve and flush the output
    private void m() throws Exception {
        solve(); // Solve the problem
        out.flush(); // Flush the output stream
    }

    // Custom FastScanner class for fast input reading
    static class FastScanner {
        Reader input;

        // Constructor with default input stream
        FastScanner() {
            this(System.in);
        }

        // Constructor with specified input stream
        FastScanner(InputStream stream) {
            this.input = new BufferedReader(new InputStreamReader(stream));
        }

        // Method to read the next integer
        int nextInt() {
            return (int) nextLong();
        }

        // Method to read the next long integer
        long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                long ret = b - '0';
                // Read the number
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Method to read the next double
        double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                double ret = b - '0';
                // Read the integer part
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }
                // Read the fractional part
                if (b != '.') return sign * ret;
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

        // Method to read the next non-whitespace character
        char nextChar() {
            try {
                int b = input.read();
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                return (char) b;
            } catch (IOException e) {
                e.printStackTrace();
                return 0;
            }
        }

        // Method to read the next string
        String nextStr() {
            try {
                StringBuilder sb = new StringBuilder();
                int b = input.read();
                // Skip initial whitespace
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                // Read the string
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }

        // Method to read an array of integers
        public int[] nextIntArray(int n) {
            int[] res = new int[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextInt();
            }
            return res;
        }

        // Method to read an array of integers and decrement each by 1
        public int[] nextIntArrayDec(int n) {
            int[] res = new int[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextInt() - 1;
            }
            return res;
        }

        // Method to read an array of integers with 1-based indexing
        public int[] nextIntArray1Index(int n) {
            int[] res = new int[n + 1];
            for (int i = 0; i < n; i++) {
                res[i + 1] = nextInt();
            }
            return res;
        }

        // Method to read an array of long integers
        public long[] nextLongArray(int n) {
            long[] res = new long[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextLong();
            }
            return res;
        }

        // Method to read an array of long integers and decrement each by 1
        public long[] nextLongArrayDec(int n) {
            long[] res = new long[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextLong() - 1;
            }
            return res;
        }

        // Method to read an array of long integers with 1-based indexing
        public long[] nextLongArray1Index(int n) {
            long[] res = new long[n + 1];
            for (int i = 0; i < n; i++) {
                res[i + 1] = nextLong();
            }
            return res;
        }

        // Method to read an array of doubles
        public double[] nextDoubleArray(int n) {
            double[] res = new double[n];
            for (int i = 0; i < n; i++) {
                res[i] = nextDouble();
            }
            return res;
        }
    }
}

import java.io.*;
import java.math.BigInteger;
import java.util.*;
import static java.lang.Math.PI;
import static java.lang.System.in;
import static java.lang.System.out;

public class Main
{   
    // Array to store the minimum cost from each position to the end
    static int minCostFrom[];

    /**
     * Recursive function to calculate the minimum cost to reach the end of the array
     * @param cur Current index in the array
     * @param a Array of integers representing the heights
     * @param k Maximum number of steps that can be taken at once
     * @return Minimum cost to reach the end from the current index
     */
    static int solve(int cur, int[] a, int k)
    {
        int n = a.length; // Length of the array
        if(cur >= n) return Integer.MAX_VALUE; // If current index is out of bounds, return a large value
        if(cur == n-1)  return 0; // If current index is the last one, cost is 0
        if(minCostFrom[cur] != -1)  return minCostFrom[cur]; // Return cached result if available

        int step = Integer.MAX_VALUE; // Initialize step cost to a large value
        for(int i = 1; i <= k; i++) // Iterate over possible steps from 1 to k
        {
            int now = Integer.MAX_VALUE; // Initialize current step cost to a large value
            if(cur+i < n) // Check if the step is within bounds
                now = Math.abs(a[cur]-a[cur+i]) + solve(cur+i, a, k); // Calculate cost for this step
            step = Math.min(now, step); // Update step with the minimum cost
        }
        return minCostFrom[cur] = step; // Cache and return the minimum cost from current index
    }

    public static void main(String[] args) throws Exception
    {   
        Foster sc = new Foster(); // Custom input reader
        PrintWriter p = new PrintWriter(out); // PrintWriter for output
        int n = sc.nextInt(), k = sc.nextInt(); // Read number of elements and max steps
        minCostFrom = new int[n]; // Initialize minCostFrom array
        Arrays.fill(minCostFrom, -1); // Fill with -1 to indicate uncomputed states
        int a[] = sc.intArray(n); // Read array of integers
        p.println(solve(0, a, k)); // Compute and print the minimum cost from start
        p.close(); // Close the PrintWriter
    }

    // Custom input reader class
    static class Foster 
    {
        BufferedReader br = new BufferedReader(new InputStreamReader(in)); // BufferedReader for input
        StringTokenizer st = new StringTokenizer(""); // StringTokenizer for parsing input

        // Method to get the next token as a string
        String next() 
        {
            while (!st.hasMoreTokens())
                try 
                {
                    st = new StringTokenizer(br.readLine()); // Read and tokenize the next line
                } 
                catch (IOException e) 
                {
                    e.printStackTrace(); // Print stack trace on exception
                }
            return st.nextToken(); // Return the next token
        }

        // Method to get the next token as an integer
        int nextInt() 
        {
            return Integer.parseInt(next());
        }

        // Method to get the next token as a long
        long nextLong() 
        {
            return Long.parseLong(next());
        }

        // Method to get the next token as a double
        double nextDouble() 
        {
            return Double.parseDouble(next());
        }

        // Method to read an array of integers
        int[] intArray(int n)                   
        {
            int arr[] = new int[n];
            for(int i = 0; i < n; i++)
            {
                arr[i] = nextInt(); // Fill array with integers
            }
            return arr;
        }

        // Method to read an array of longs
        long[] longArray(int n)                 
        {
            long arr[] = new long[n];
            for(int i = 0; i < n; i++)
            {
                arr[i] = nextLong(); // Fill array with longs
            }
            return arr;
        }

        // Method to get the binary representation of an integer as an array of bits
        int[] getBits(int n)                    
        {
            int a[] = new int[31];
            for(int i = 0; i < 31; i++)
            {
                if(((1<<i) & n) != 0)
                    a[i] = 1; // Set bit if present
            }
            return a;
        }

        // Method to calculate power with optional modulus
        static long pow(long... a)
        {
            long mod = Long.MAX_VALUE; // Default modulus
            if(a.length == 3)   mod = a[2]; // Use provided modulus if available
            long res = 1;
            while(a[1] > 0)
            {
                if((a[1] & 1) == 1)
                    res = (res * a[0]) % mod; // Multiply result if exponent is odd
                a[1] /= 2; // Divide exponent by 2
                a[0] = (a[0] * a[0]) % mod; // Square the base
            }
            return res;
        }

        // Method to print objects to standard error
        static void print(Object... o) 
        {
            for(Object next : o)
            {
                System.err.print(next + " ");
            }
        }

        // Method to print objects to standard error with a newline
        static void println(Object... o) 
        {
            for(Object next : o)
            {
