import java.util.Scanner;

public class Main {

    public static void main(String[] args) {

        // Create a Scanner object to read input from the console
        Scanner scan = new Scanner(System.in);

        // Read a long integer input from the user
        long N = scan.nextLong();

        // Initialize a variable k to determine the length of the resulting string
        int k = 0;

        // Loop to determine the value of k such that the input N falls within a specific range
        for (int i = 1; i < 12; i++) {
            // Check if N is within the range defined by the formula for the i-th length
            if (26 * (Math.pow(26, i - 1) - 1) / 25 < N && N <= 26 * (Math.pow(26, i) - 1) / 25) {
                k = i; // Set k to the current value of i
