        w.close();
    }

    // Custom input reader class to handle input operations
    static class InputReader {
        private InputStream stream; // Input stream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1)
                throw new UnknownError(); // Throw an error if no more characters are available
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read data into the buffer and update numChars
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new UnknownError(); // Throw an error if an IOException occurs
                }
                if (numChars <= 0)
                    return -1; // Return -1 if end of stream is reached
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to peek at the next byte of input without advancing the buffer
        public int peek() {
            if (numChars == -1)
                return -1; // Return -1 if no more characters are available
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read data into the buffer and update numChars
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    return -1; // Return -1 if an IOException occurs
                }
                if (numChars <= 0)
                    return -1; // Return -1 if end of stream is reached
            }
            return buf[curChar]; // Return the next character from the buffer without advancing
        }

        // Method to skip a specified number of characters in the input
        public void skip(int x) {
            while (x-- > 0)
                read(); // Read and discard x characters
        }

        // Method to read the next integer from input
        public int nextInt() {
            return Integer.parseInt(next()); // Parse and return the next token as an integer
        }

        // Method to read the next long integer from input
        public long nextLong() {
            return Long.parseLong(next()); // Parse and return the next token as a long integer
        }

        // Method to read the next string from input
        public String nextString() {
            return next(); // Return the next token as a string
        }

        // Method to read the next token from input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip any leading whitespace characters
            StringBuffer res = new StringBuffer();
            do {
                res.appendCodePoint(c); // Append the character to the result
                c = read();
            } while (!isSpaceChar(c)); // Continue until a space character is encountered

            return res.toString(); // Return the accumulated string
        }

        // Method to read the next line of input
        public String nextLine() {
            StringBuffer buf = new StringBuffer();
            int c = read();
            while (c != '\n' && c != -1) {
                if (c != '\r')
                    buf.appendCodePoint(c); // Append the character to the buffer if it's not a carriage return
                c = read();
            }
            return buf.toString(); // Return the accumulated line
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip any leading whitespace characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw an exception if the character is not a digit
                res *= 10;
                res += c - '0'; // Accumulate the integer part
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Throw an exception if the character is not a digit
                    m /= 10;
                    res += (c - '0') * m; // Accumulate the fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the final result with the correct sign
        }

        // Method to read an array of integers from input
        public int[] nextIntArray(int n) {
            int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = nextInt(); // Read each integer into the array
            return a;
        }

        // Method to read an array of long integers from input
        public long[] nextLongArray(int n) {
            long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = nextLong(); // Read each long integer into the array
            return a;
        }

        // Method to check if there is more input available
        public boolean hasNext() {
            int value;
            while (isSpaceChar(value = peek()) && value != -1)
                read(); // Skip any whitespace characters
            return value != -1; // Return true if there is more input, false otherwise
        }

        // Helper method to check if a character is a whitespace character
        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner in = new Scanner(System.in);

        // Read two strings from the input
        String S = in.next();
        String T = in.next();

        // Initialize boolean flags to track various conditions
        boolean onazi = true; // Flag to check if strings S and T are identical
        boolean komozi = true; // Flag to check if both strings are lowercase
        boolean mozisu = false; // Flag to check if the length of S is between 1 and 10
        boolean tuika = false; // Flag to check if T is exactly one character longer than S

        // Check if all characters in S and T are identical
        for (int i = 0; i < S.length(); i++) {
            char a = S.charAt(i);
            char b = T.charAt(i);
            if (!(a == b)) {
                onazi = false; // Set flag to false if any character differs
            }
        }

        // Check if all characters in S are lowercase
        for (int i = 0; i < S.length(); i++) {
            char x = S.charAt(i);
            if (x >= 'A' && x <= 'Z') {
                komozi = false; // Set flag to false if any character is uppercase
            }
        }

        // Check if all characters in T are lowercase
        for (int i = 0; i < T.length(); i++) {
            char x = T.charAt(i);
            if (x >= 'A' && x <= 'Z') {
                komozi = false; // Set flag to false if any character is uppercase
            }
        }

        // Check if the length of S is between 1 and 10
        if (1 <= S.length() && S.length() <= 10) {
            mozisu = true; // Set flag to true if condition is met
        }

        // Check if T is exactly one character longer than S
        if (T.length() == (S.length() + 1)) {
            tuika = true; // Set flag to true if condition is met
        }

        // Print "Yes" if all conditions are met, otherwise print "No"
        if (onazi && komozi && mozisu && tuika) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }
}

