public class Main {

    public static void main(String[] args) throws IOException {
        // Initialize the FastScanner for input
        in = new FastScanner();

        // Read three long integers from input
        long a = in.longNext(), b = in.longNext(), k = in.longNext();

        // Check if 'a' is greater than or equal to 'k'
        if (a >= k) {
            // If true, subtract 'k' from 'a'
            a -= k;
        } else {
            // If false, subtract 'a' from 'k' and set 'a' to 0
            k -= a;
            a = 0;
            // Subtract the remaining 'k' from 'b', ensuring 'b' doesn't go below 0
            b = max(0, b - k);
        }
        // Output the values of 'a' and 'b'
        out.pp(a, b);

        // Close the output writer
        out.close();
    }

    // Initialize a FastWriter for efficient output
    private static final FastWriter out = new FastWriter();
    // Declare a FastScanner for input
    private static FastScanner in;
    // Declare an adjacency list for graph representation
    static ArrayList<Integer>[] adj;
    // A constant value often used in competitive programming
    private static long e97 = (long)1e9 + 7;

    // FastWriter class for efficient output operations
    static class FastWriter {
        private static final int IO_BUFFERS = 128 * 1024; // Buffer size
        private final StringBuilder out; // StringBuilder for output accumulation

        // Constructor initializes the StringBuilder with buffer size
        public FastWriter() {
            out = new StringBuilder(IO_BUFFERS);
        }

        // Append an object to the output
        public FastWriter p(Object object) {
            out.append(object);
            return this;
        }

        // Append formatted string to the output
        public FastWriter p(String format, Object... args) {
            out.append(String.format(format, args));
            return this;
        }

        // Append multiple objects to the output, separated by spaces
        public FastWriter pp(Object... args) {
            for (Object ob : args) {
                out.append(ob).append(" ");
            }
            out.append("\n");
            return this;
        }

        // Append an object followed by a newline
        public FastWriter println(Object object) {
            out.append(object).append("\n");
            return this;
        }

        // Write the accumulated output to a file
        public void toFile(String fileName) throws IOException {
            BufferedWriter writer = new BufferedWriter(new FileWriter(fileName));
            writer.write(out.toString());
            writer.close();
        }

        // Print the accumulated output to the console
        public void close() throws IOException {
