  // TreeList class extending ArrayList with sorted insertion
  static class TreeList<E> extends ArrayList<E> {

    Comparator<? super E> comparator; // Comparator for sorting

    // Constructor with comparator
    TreeList(Comparator<? super E> c) {
      super();
      comparator = c;
    }

    // Add method with sorted insertion
    public boolean add(E e) {
      int lowIndex = 0;
      int highIndex = size() - 1;
      int index = 0;

      if (size() == 0) {
        super.add(e); // Add directly if list is empty
        return true;
      }

      // Determine the correct index for insertion
      if (comparator.compare(e, get(0)) < 0) {
        index = 0;
      } else if (comparator.compare(e, get(highIndex)) > 0) {
        index = highIndex + 1;
      } else {
        while (lowIndex <= highIndex) {

          if (highIndex == lowIndex + 1 || highIndex == lowIndex) {
            index = highIndex;
            break;
          }

          int midIndex = (lowIndex + highIndex) / 2;

          if (comparator.compare(e, get(midIndex)) > 0) {
            lowIndex = midIndex;
          } else {
            highIndex = midIndex;
          }

        }
      }

      super.add(index, e); // Insert element at the determined index
      return true;
    }

  }

