        int[] a = new int[n+1];

        // Process each set
        while (k-->0){
            // Read the number of elements in the current set
            int d = in.Int();
            // Increment the count for each element in the set
            while (d-->0){
                int temp = in.Int();
                a[temp]++;
            }
        }

        // Counter for elements that are not present in any set
        int counter = 0;
        for (int i = 1; i <= n; i++) {
