    private static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024]; // Buffer for reading input
        private int curChar;
        private int numChars;
        private SpaceCharFilter filter;

        // Constructor to initialize the input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1) {
                throw new InputMismatchException();
            }
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Fill the buffer with new data
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) {
                    return -1;
                }
            }
            return buf[curChar++];
        }

        // Method to read the next integer from input
        public int Int() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            // Read the integer value
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to read the next string from input
        public String String() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            StringBuilder res = new StringBuilder();
            // Read the string value
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));
            return res.toString();
        }

        // Method to read the next double from input
        public double Double() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            // Read the integer part of the double
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E') {
                    return res * Math.pow(10, Int());
                }
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            }
            // Read the fractional part of the double
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E') {
                        return res * Math.pow(10, Int());
                    }
                    if (c < '0' || c > '9') {
                        throw new InputMismatchException();
                    }
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Method to read the next long from input
        public long Long() {
            int c = read();
            // Skip any space characters
            while (isSpaceChar(c)) {
                c = read();
            }
            int sgn = 1;
            // Check for negative sign
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            long res = 0;
            // Read the long value
            do {
                if (c < '0' || c > '9') {
                    throw new InputMismatchException();
                }
                res *= 10;
                res += c - '0';
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn;
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null) {
                return filter.isSpaceChar(c);
            }
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        // Method to read the next token as a string
        public String next() {
            return String();
        }

        // Interface for custom space character filtering
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }
