public class Main{
    // FastReader class to efficiently read input from the input stream
    public static class FastReader {
        private InputStream stream; // Input stream to read data from
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter to determine space characters

        // Constructor to initialize the FastReader with an input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of data from the input stream
        public int read() {
            if (numChars == -1)
                throw new InputMismatchException(); // Throw exception if no more characters
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Handle IO exception
                }
                if (numChars <= 0)
                    return -1; // Return -1 if end of stream is reached
            }
            return buf[curChar++]; // Return the next character from the buffer
        }

        // Method to read the next line of input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the input
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace in case of an exception
            }
            return str; // Return the read line
        }

        // Method to read the next integer from the input
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception for invalid input
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed integer
        }

        // Method to read the next long integer from the input
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception for invalid input
                res *= 10;
                res += c - '0'; // Convert character to long integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed long integer
        }

        // Method to read the next double from the input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Throw exception for invalid input
                res *= 10;
                res += c - '0'; // Convert character to double
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Throw exception for invalid input
                    m /= 10;
                    res += (c - '0') * m; // Convert fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the parsed double
        }

        // Method to read the next character from the input
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            return (char) c; // Return the next character
        }

        // Method to read the next word from the input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c));
            return res.toString(); // Return the parsed word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c); // Use custom filter if available
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Method to calculate the greatest common divisor (GCD) of two numbers
    static long gcd(long a, long b) {
        if (a == 0)
            return b; // Base case: if a is 0, return b
        return gcd(b % a, a); // Recursive call to find GCD
    }

    // Method to calculate the least common multiple (LCM) of two numbers
    static long lcm(long a, long b) {
        return (a * b) / gcd(a, b); // LCM formula using GCD
    }

    // Method to find the maximum subarray sum using Kadane's algorithm
    static long func(long a[], long size, int s) {
        long max1 = a[s]; // Initialize max1 with the first element
        long maxc = a[s]; // Initialize maxc with the first element
        for (int i = s + 1; i < size; i++) {
            maxc = Math.max(a[i], maxc + a[i]); // Update maxc with the maximum of current element or sum
            max1 = Math.max(maxc, max1); // Update max1 with the maximum of maxc or max1
        }
        return max1; // Return the maximum subarray sum
    }

    // Generic Pair class to hold two comparable objects
    public static class Pair<U extends Comparable<U>, V extends Comparable<V>> implements Comparable<Pair<U, V>> {
        public U x; // First element of the pair
        public V y; // Second element of the pair

        // Constructor to initialize the pair with two elements
        public Pair(U x, V y) {
            this.x = x;
            this.y = y;
        }

        // Method to calculate the hash code of the pair
        public int hashCode() {
            return (x == null ? 0 : x.hashCode() * 31) + (y == null ? 0 : y.hashCode());
        }

        // Method to check equality of two pairs
        public boolean equals(Object o) {
            if (this == o)
                return true; // Check if the same object
            if (o == null || getClass() != o.getClass())
                return false; // Check if the object is of the same class
            Pair<U, V> p = (Pair<U, V>) o;
            return (x == null ? p.x == null : x.equals(p.x)) && (y == null ? p.y == null : y.equals(p.y));
        }

        // Method to compare two pairs
        public int compareTo(Pair<U, V> b) {
            int cmpU = x.compareTo(b.x); // Compare first elements
            return cmpU != 0 ? cmpU : y.compareTo(b.y); // If first elements are equal, compare second elements
        }

        // Method to return the string representation of the pair
        public String toString() {
            return String.format("(%s, %s)", x.toString(), y.toString());
        }
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading data
        OutputStream outputStream = System.out; // Output stream for writing data
        FastReader sc = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        int n = sc.nextInt(); // Read the number of elements
        int k = sc.nextInt(); // Read the number of smallest elements to sum
        int a[] = new int[n]; // Array to store the elements

        int sum = 0; // Initialize sum to 0
        for (int i = 0; i < n; i++) {
            a[i] = sc.nextInt(); // Read each element into the array
        }

        Arrays.sort(a); // Sort the array in ascending order
        for (int i = 0; i < k; i++) {
            sum += a[i]; // Sum the first k elements (smallest elements)
        }

        w.println(sum); // Print the sum of the smallest k elements
        w.close(); // Close the PrintWriter
    }
}

import java.io.*;
