public class Main
{   
    // Array to store the minimum cost from each index to the end
    static int minCostFrom[];

    // Recursive function to calculate the minimum cost to reach the end of the array
    static int solve(int cur, int[] a)
    {
        int n = a.length;
        // If current index is out of bounds, return a large value indicating it's not a valid path
        if(cur >= n) return Integer.MAX_VALUE;
        // If current index is the last one, no cost is needed to reach the end
        if(cur == n-1)  return 0;
        // If the minimum cost from the current index is already computed, return it
        if(minCostFrom[cur] != -1)    return minCostFrom[cur];

        // Initialize costs for one-step and two-step moves
        int oneStep = Integer.MAX_VALUE, twoStep = Integer.MAX_VALUE;

        // Calculate cost for moving one step forward if within bounds
        if(cur+1 < n)
            oneStep = Math.abs(a[cur]-a[cur+1]) + solve(cur+1, a);

        // Calculate cost for moving two steps forward if within bounds
        if(cur+2 < n)
            twoStep = Math.abs(a[cur]-a[cur+2]) + solve(cur+2, a);

        // Store and return the minimum of the two possible costs
        return minCostFrom[cur] = Math.min(oneStep, twoStep);
    }

