public class Main{
	// InputReader instance for reading input
	public static InputReader scn = new InputReader();
	// PrintWriter instance for writing output
	public static PrintWriter out = new PrintWriter(System.out);

	public static void main(String[] args) throws Exception {

		// Array to store the smallest prime factor for each number up to 1000
		int[] div = new int[1001];
		div[1] = 1; // 1 is its own smallest factor

		// Populate the div array with smallest prime factors using a sieve-like approach
		for (int i = 2; i <= 1e3; i++) {
			if (div[i] == 0) { // If i is a prime number
				for (int j = i; j <= 1e3; j += i) {
					div[j] = i; // Mark i as the smallest prime factor for multiples of i
				}
			}
		}

		// Read the integer input n
		int n = scn.nextInt();
		// Iterate from n down to 2
		for (int i = n; i > 1; i--) {
			if(i == 980) {
				out.println(i); // Special case: print 980 if encountered
			}
			// HashMap to store the prime factorization of i
			HashMap<Integer, Integer> map = new HashMap<>();
			int k = i;
			// Decompose k into its prime factors
			while (k != 1) {
				if (map.containsKey(div[k])) {
					map.put(div[k], map.get(div[k]) + 1); // Increment count of prime factor
				} else {
					map.put(div[k], 1); // Initialize count of prime factor
				}
				k /= div[k]; // Divide k by its smallest prime factor
			}

			int z = -1; // Variable to check if all prime factors have the same power
			for (int x : map.keySet()) {
				if (z == -1) {
					z = map.get(x); // Set z to the power of the first prime factor
				} else if (map.get(x) != z) {
					z = -2; // If any power differs, set z to -2
				}
			}

			// If all prime factors have the same power greater than 1, print i and exit
			if (z > 1) {
				System.out.println(i);
				return;
			}
		}
		// If no number is found, print 1
		out.println(1);
		out.flush(); // Flush the output stream
	}

	// Custom InputReader class for fast input
	public static class InputReader {
		InputStream is;

		public InputReader() {
			is = System.in; // Initialize input stream to standard input
		}

		byte[] inbuf = new byte[1024]; // Buffer for input
		public int lenbuf = 0, ptrbuf = 0; // Buffer length and pointer

		// Read a single byte from input
		int readByte() {
			if (lenbuf == -1)
				throw new InputMismatchException();
			if (ptrbuf >= lenbuf) {
				ptrbuf = 0;
				try {
					lenbuf = is.read(inbuf); // Read into buffer
				} catch (IOException e) {
					throw new InputMismatchException();
				}
				if (lenbuf <= 0)
					return -1;
			}
			return inbuf[ptrbuf++];
		}

		// Check if a character is a space
		boolean isSpaceChar(int c) {
			return !(c >= 33 && c <= 126);
		}

		// Skip spaces and return the next non-space character
		int skip() {
			int b;
			while ((b = readByte()) != -1 && isSpaceChar(b))
				;
			return b;
		}

		// Read the next double from input
		double nextDouble() {
			return Double.parseDouble(next());
		}

		// Read the next character from input
		char nextChar() {
			return (char) skip();
		}

		// Read the next string from input
		String next() {
			int b = skip();
			StringBuilder sb = new StringBuilder();
			while (!(isSpaceChar(b))) { 
				sb.appendCodePoint(b);
				b = readByte();
			}
			return sb.toString();
		}

		// Read the next n characters from input
		char[] next(int n) {
			char[] buf = new char[n];
			int b = skip(), p = 0;
			while (p < n && !(isSpaceChar(b))) {
				buf[p++] = (char) b;
				b = readByte();
			}
			return n == p ? buf : Arrays.copyOf(buf, p);
		}

		// Read a matrix of characters from input
		char[][] nextMatrix(int n, int m) {
			char[][] map = new char[n][];
			for (int i = 0; i < n; i++)
				map[i] = next(m);
			return map;
		}

		// Read an array of integers from input
		int[] nextArray(int n) {
			int[] a = new int[n];
			for (int i = 0; i < n; i++)
				a[i] = nextInt();
			return a;
		}

		// Read the next integer from input
		int nextInt() {
			int num = 0, b;
			boolean minus = false;
			while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-'))
				;
			if (b == '-') {
				minus = true;
				b = readByte();
			}

			while (true) {
				if (b >= '0' && b <= '9') {
					num = num * 10 + (b - '0');
				} else {
					return minus ? -num : num;
				}
				b = readByte();
			}
		}

		// Read the next long integer from input
		long nextLong() {
			long num = 0;
			int b;
			boolean minus = false;
			while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-'))
				;
			if (b == '-') {
				minus = true;
				b = readByte();
			}

			while (true) {
				if (b >= '0' && b <= '9') {
					num = num * 10 + (b - '0');
				} else {
					return minus ? -num : num;
				}
				b = readByte();
			}
		}
	}
}

