		Scanner sc = new Scanner(System.in);
		String input_nml = ""; // String to store the input line for n, m, l
		String[] nml_data = new String[3]; // Array to store split values of n, m, l
		int n = 0; // Number of rows in matrix A
		int m = 0; // Number of columns in matrix A and rows in matrix B
		int l = 0; // Number of columns in matrix B
		boolean judge = true; // Flag to determine if input is valid

		// Read the first line of input and split it into n, m, l
		input_nml = sc.nextLine();
		nml_data = input_nml.split(" ");
		n = Integer.parseInt(nml_data[0]); // Parse n
		m = Integer.parseInt(nml_data[1]); // Parse m
		l = Integer.parseInt(nml_data[2]); // Parse l

		// Validate the input values for n, m, l
		if ((1 > n || n > 100) || (1 > m || m > 100) || (1 > l || l > 100)) {
			judge = false; // Set judge to false if any value is out of range
		}

		// Proceed only if the input values are valid
		if (judge == true) {
			String input_AB = ""; // String to store input lines for matrices A and B
			String[] A_in = new String[m]; // Array to store split values of a row in matrix A
			int[][] A_out = new int[n][m]; // 2D array to store matrix A
			String[] B_in = new String[l]; // Array to store split values of a row in matrix B
			int[][] B_out = new int[m][l]; // 2D array to store matrix B
			long[][] C_out = new long[n][l]; // 2D array to store the result matrix C
			String[] output_result = new String[n]; // Array to store the output strings for each row of matrix C

			// Read and parse matrix A
			out: for (int i = 0; i < n; i++) {
				input_AB = sc.nextLine(); // Read a line for matrix A
				A_in = input_AB.split(" "); // Split the line into individual elements

				for (int j = 0; j < m; j++) {
					A_out[i][j] = Integer.parseInt(A_in[j]); // Parse and store each element in matrix A

					// Validate the element value
					if (A_out[i][j] < 0 || A_out[i][j] > 10000) {
						judge = false; // Set judge to false if the value is out of range
						break out; // Exit the loop if invalid input is found
					}

				}

			}

			// Proceed only if matrix A is valid
			if (judge == true) {

				// Read and parse matrix B
				out: for (int k = 0; k < m; k++) {
					input_AB = sc.nextLine(); // Read a line for matrix B
					B_in = input_AB.split(" "); // Split the line into individual elements

					for (int p = 0; p < l; p++) {
						B_out[k][p] = Integer.parseInt(B_in[p]); // Parse and store each element in matrix B

						// Validate the element value
						if (B_out[k][p] < 0 || B_out[k][p] > 10000) {
							judge = false; // Set judge to false if the value is out of range
							break out; // Exit the loop if invalid input is found
						}

					}

				}

			}

			// Proceed only if both matrices A and B are valid
			if (judge == true) {

				// Perform matrix multiplication to compute matrix C
				for (int i = 0; i < n; i++) {
					output_result[i] = ""; // Initialize the output string for the current row
					for (int j = 0; j < l; j++) {

						for (int k = 0; k < m; k++) {
							// Calculate the dot product for the element C[i][j]
							C_out[i][j] += A_out[i][k] * B_out[k][j];

						}
						// Append the calculated value to the output string
						if (j == 0) {
							output_result[i] += "" + C_out[i][j];
						} else {
							output_result[i] += " " + C_out[i][j];
						}


					}

					// Print the result for the current row of matrix C
					System.out.println(output_result[i]);

				}

			}

		}

	}
}

import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.NoSuchElementException;

public class Main {
    // Create a static instance of FastScanner for input
    static FastScanner sc = new FastScanner();
    // Create a static instance of PrintWriter for output
    static PrintWriter out = new PrintWriter(System.out);

    public static void main(String[] args) {
        // Read an integer n from input
        int n = sc.nextInt();
        // Read a string S from input
        String S = sc.next();

        // Initialize the answer to 1, as there's at least one segment
        int ans = 1;
        // Initialize the current character to the first character of the string
        char c = S.charAt(0);

        // Iterate over the string starting from the second character
        for (int i = 1; i < n; i++) {
            // Get the current character
            char d = S.charAt(i);
            // If the current character is different from the previous one, increment the segment count
            if (c != d)
                ans++;
            // Update the current character to the new character
            c = d;
        }
        // Print the number of segments
        out.println(ans);
        // Flush the output stream
        out.flush();
    }

    // FastScanner class for fast input reading
    static class FastScanner {
        private final InputStream in = System.in; // InputStream for reading input
        private final byte[] buffer = new byte[1024]; // Buffer for storing input bytes
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true;
            } else {
                ptr = 0;
                try {
                    buflen = in.read(buffer); // Read data into the buffer
                } catch (IOException e) {
                    e.printStackTrace();
                }
                if (buflen <= 0) {
                    return false;
                }
            }
            return true;
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            else return -1;
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        // Skip non-printable characters
        private void skipUnprintable() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
        }

        // Check if there is another token to read
        public boolean hasNext() {
            skipUnprintable();
            return hasNextByte();
        }

        // Read the next token as a String
        public String next() {
            if (!hasNext()) throw new NoSuchElementException();
            StringBuilder sb = new StringBuilder();
            int b = readByte();
            while (isPrintableChar(b)) {
                sb.appendCodePoint(b);
                b = readByte();
            }
            return sb.toString();
        }

        // Read the next token as a long
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException();
            long n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException();
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }

        // Read the next token as an int
        public int nextInt() {
            return (int) nextLong();
        }

        // Read an array of integers
        public int[] nextIntArray(int N, boolean oneBased) {
            if (oneBased) {
                int[] array = new int[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            } else {
                int[] array = new int[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextInt();
                }
                return array;
            }
        }

        // Read an array of longs
        public long[] nextLongArray(int N, boolean oneBased) {
            if (oneBased) {
                long[] array = new long[N + 1];
                for (int i = 1; i <= N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            } else {
                long[] array = new long[N];
                for (int i = 0; i < N; i++) {
                    array[i] = sc.nextLong();
                }
                return array;
            }
        }
    }
}

