	  	// Read the number of rows (r) and columns (c) from the user
	  	int  r = scanner.nextInt();
	  	int  c = scanner.nextInt();

	  	// Declare a 2D array with extra space (5 additional rows and columns)
	  	int[][] array;
        array = new int[r + 5][c + 5];

        // Initialize the array with zeros
        // This loop iterates over each cell in the array up to the r and c indices
        for (int i = 0; i <= r; i++) {
        	for (int j = 0; j <= c; j++) {
        		array[i][j] = 0; // Set each element to zero
	        }
        }

        // Fill the array with user input values
        // This loop reads values into the array up to the r and c indices
        for (int i = 0; i < r; i++) {
        	for (int j = 0; j < c; j++) {
        		array[i][j] = scanner.nextInt(); // Read each element from input
	        }
        }

        // Calculate the sum of each row and column
        // The sums are stored in the last row and column respectively
        for (int i = 0; i <= r; i++) {
        	for (int j = 0; j <= c; j++) {
	            if( j < c ) {
	            	array[i][c] += array[i][j]; // Add to the row sum
	            }

	            if( i < r ) {
	            	array[r][j] += array[i][j]; // Add to the column sum
	            }

	            // Special case for the bottom-right corner of the array
	            if( i == r && j == c )
	        	  	array[r][c] /= 2; // Adjust the corner value

        	}
        }

        // Print the array with the calculated sums
        for (int i = 0; i <= r; i++) {
        	for (int j = 0; j <= c; j++) {
	            if( j == c && i < r )
        			System.out.println(array[i][j]); // Print row sums
	            else if( j == c && i == r )
        			System.out.println(array[i][j]); // Print the adjusted corner value
	            else
        			System.out.print(array[i][j] + " "); // Print the array elements
	        }
        }

        // Close the scanner to free up resources
        scanner.close();
  }
