				// Check if the number is within the range [A, B]
				if (A <= i && i <= B)
					ans += i; // Add the number to the answer
			} 
			// Check if the number is a two-digit number
			else if (i / 100 == 0) {
				// Calculate the sum of digits and check if it's within [A, B]
				if (A <= i % 10 + i / 10 && i % 10 + i / 10 <= B)
					ans += i; // Add the number to the answer
			} 
			// Check if the number is a three-digit number
			else if (i / 1000 == 0) {
				// Calculate the sum of digits and check if it's within [A, B]
				if (A <= i % 10 + i % 100 / 10 + i / 100 && i % 10 + i % 100 / 10 + i / 100 <= B)
					ans += i; // Add the number to the answer
			} 
			// Check if the number is a four-digit number
			else if (i / 10000 == 0) {
				// Calculate the sum of digits and check if it's within [A, B]
				if (A <= i % 10 + i % 100 / 10 + i % 1000 / 100 + i / 1000
						&& i % 10 + i % 100 / 10 + i % 1000 / 100 + i / 1000 <= B)
					ans += i; // Add the number to the answer
			} 
			// Special case for the number 10000
			else if (i == 10000) {
				// Check if the sum of digits (which is 1) is within [A, B]
				if (A <= 1 && 1 <= B)
					ans += i; // Add the number to the answer
			}
		}
		// Output the final accumulated sum
		System.out.println(ans);

	}

	// Method to calculate the greatest common divisor (GCD) of two numbers
	public static long gcd(long a, long b) {
		// Ensure a is greater than or equal to b
		if (a < b)
			return gcd(b, a);
		long c = 0;
		c = a % b; // Calculate remainder
		if (c == 0)
			return b; // If remainder is 0, b is the GCD
		return gcd(b, c); // Recursively call gcd with b and remainder
	}

	// Method to calculate the least common multiple (LCM) of two numbers
	public static long lcm(long m, long n) {
		// LCM is calculated using the formula: (m * n) / GCD(m, n)
		return m * n / gcd(m, n);
	}

	// Method to check if a number is prime
	public static boolean isPrime(int n) {
		if (n < 2)
			return false; // Numbers less than 2 are not prime
		if (n == 2)
			return true; // 2 is the only even prime number
		if (n % 2 == 0)
			return false; // Even numbers greater than 2 are not prime

		// Check divisibility from 3 to the square root of n
		for (int i = 3; i * i <= n; i += 2) {
			if (n % i == 0)
				return false; // If divisible, n is not prime
		}
		return true; // If no divisors found, n is prime
	}
}


class FastScanner {
	private final InputStream in = System.in; // Input stream for reading data
	private final byte[] buffer = new byte[1024]; // Buffer to store input data
	private int ptr = 0; // Pointer to current position in buffer
	private int buflen = 0; // Length of valid data in buffer

	// Check if there is another byte to read
	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true; // If pointer is within buffer length, return true
		} else {
			ptr = 0; // Reset pointer
			try {
				buflen = in.read(buffer); // Read data into buffer
			} catch (IOException e) {
				e.printStackTrace(); // Print stack trace if an error occurs
			}
			if (buflen <= 0) {
				return false; // If no data read, return false
			}
		}
		return true; // Data is available to read
	}

	// Read the next byte from the buffer
	private int readByte() {
		if (hasNextByte())
			return buffer[ptr++]; // Return the next byte and increment pointer
		else
			return -1; // Return -1 if no byte is available
	}

	// Check if a character is printable
	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126; // Printable characters are between 33 and 126
	}

	// Check if there is another token to read
	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr]))
			ptr++; // Skip non-printable characters
		return hasNextByte(); // Return true if there is a next byte
	}

	// Read the next token as a String
	public String next() {
		if (!hasNext())
			throw new NoSuchElementException(); // Throw exception if no next element
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b); // Append character to StringBuilder
			b = readByte(); // Read next byte
		}
		return sb.toString(); // Return the accumulated string
	}

	// Read the next token as a long
	public long nextLong() {
		if (!hasNext())
			throw new NoSuchElementException(); // Throw exception if no next element
		long n = 0;
		boolean minus = false; // Flag for negative numbers
		int b = readByte();
		if (b == '-') {
			minus = true; // Set flag if negative sign is found
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException(); // Throw exception if not a digit
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10; // Multiply current number by 10
				n += b - '0'; // Add the digit
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n; // Return the number, negated if necessary
			} else {
				throw new NumberFormatException(); // Throw exception if not a digit
			}
			b = readByte(); // Read next byte
		}
	}

	// Read the next token as an int
	public int nextInt() {
		long nl = nextLong(); // Read as long first
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
			throw new NumberFormatException(); // Throw exception if out of int range
		return (int) nl; // Cast to int and return
	}

	// Read the next token as a double
	public double nextDouble() {
		return Double.parseDouble(next()); // Parse the next token as a double
	}
}

import java.io.*;
import java.math.BigInteger;
import java.util.*;

public class Main {
    // BufferedReader for efficient input reading
    static BufferedReader br;

    // Method to read an integer from input
    static int cin() throws Exception {
        return Integer.valueOf(br.readLine());
    }

    // Method to read a line of input, split by spaces, and convert to an array of integers
    static int[] split() throws Exception {
        String[] cmd = br.readLine().split(" ");
        int[] ans = new int[cmd.length];
        for (int i = 0; i < cmd.length; i++) {
            ans[i] = Integer.valueOf(cmd[i]);
        }
        return ans;
    }

    // Method to solve the kMarsh problem
    static void kMarsh(String[] grid) {
        int n = grid.length; // Number of rows in the grid
        int m = grid[0].length(); // Number of columns in the grid

        // Convert the grid from String array to a 2D char array
        char[][] mat = new char[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                mat[i][j] = grid[i].charAt(j);
            }
        }

        // Array to store the first 'x' encountered in each column from a given row
        int[][] first = new int[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                int ind = n; // Default to the end of the column
                for (int k = j; k < n; k++) {
                    if (mat[k][i] == 'x') {
                        ind = k; // Update index if 'x' is found
                        break;
                    }
                }
                first[i][j] = ind;
            }
        }

        // 3D boolean array to check if a rectangle can be formed between columns j and k in row i
        boolean[][][] there = new boolean[n][m][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                for (int k = j; k < m; k++) {
                    boolean b1 = (mat[i][k] == 'x') ? false : true; // Check if current cell is not 'x'
                    boolean b2 = true;
                    if (k != j)
                        b2 = there[i][j][k - 1]; // Check previous state
                    if (!b1 || !b2)
                        there[i][j][k] = false; // Cannot form rectangle if any condition fails
                    else
                        there[i][j][k] = true; // Rectangle can be formed
                }
            }
        }

        int ans = 0; // Variable to store the maximum perimeter found
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (mat[i][j] == 'x')
                    continue; // Skip if current cell is 'x'
                int f1 = first[j][i] - 1; // Get the first 'x' index in column j
                for (int k = j + 1; k < m; k++) {
                    if (mat[i][k] == 'x')
                        break; // Stop if 'x' is encountered
                    int f2 = first[k][i] - 1; // Get the first 'x' index in column k
                    int x = Math.min(f1, f2); // Determine the maximum row index for rectangle
                    if (x == i)
                        continue; // Skip if no valid rectangle can be formed
                    if (!there[x][j][k])
                        continue; // Skip if rectangle cannot be formed
                    int p = 2 * (x - i + k - j); // Calculate perimeter of the rectangle

                    ans = Math.max(ans, p); // Update maximum perimeter
                }
            }
        }

        // Output the result
        if (ans != 0)
            System.out.println(ans);
        else
            System.out.println("impossible");
    }

    public static void main(String[] args) throws Exception {
        br = new BufferedReader(new InputStreamReader(System.in)); // Initialize BufferedReader for input

        String s = br.readLine(); // Read a line of input
        int b = 0; // Counter for 'B'
        int a = 0; // Counter for 'A'

        // Count occurrences of 'A' and 'B' in the first three characters
        for (int i = 0; i < 3; i++) {
            a = a + (s.charAt(i) == 'A' ? 1 : 0);
            b = b + (s.charAt(i) == 'B' ? 1 : 0);
        }

        // Output "No" if all three are 'A' or 'B', otherwise "Yes"
        if (a == 3 || b == 3)
            System.out.println("No");
        else
            System.out.println("Yes");
    }
}

