    // Constant MOD value, often used in competitive programming for modulo operations
    final static int MOD = (int)1e9+7;

    // Method to solve the problem
    void solve(){
        // Read the number of points
        int N = in.nextInt();
        // Read the maximum distance squared
        long D = in.nextLong();
        // Counter for points within the circle
        int cnt = 0;
        // Iterate over each point
        for(int i = 0; i < N; i++){
            // Read the x and y coordinates of the point
            long X = in.nextLong(), Y = in.nextLong();
            // Check if the point is within the circle of radius D
            if(X * X + Y * Y <= D * D) cnt++;
        }
        // Output the count of points within the circle
        out.println(cnt);
    }

    // Main method to start the program
    public static void main(String[] args) {
        // Create an instance of Main and call method m
        new Main().m();
