    private void m() {
        // Initialize FastScanner with standard input
        in = new FastScanner(System.in);
        // Initialize PrintWriter with standard output
        out = new PrintWriter(System.out);

        // Solve the problem
        solve();
        // Flush the output buffer
        out.flush();
        // Close the input and output streams
        in.close();
        out.close();
    }

    // Custom FastScanner class for fast input reading
    static class FastScanner {
        // Reader for input stream
        private Reader input;

        // Constructor with default input stream
        public FastScanner() {this(System.in);}
        // Constructor with specified input stream
        public FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));}

        // Close the input stream
        public void close() {
            try {
                this.input.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // Read the next integer from input
        public int nextInt() {
            long nl = nextLong();
            // Check for integer overflow
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
            return (int) nl;
        }

        // Read the next long integer from input
        public long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                // Read the number
                long ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) return ret * sign;
                    ret *= 10;
                    ret += b - '0';
                }
            } catch (IOException e) {
                e.printStackTrace();
                return -1;
            }
        }

        // Read the next double from input
        public double nextDouble() {
            try {
                double sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
                    b = input.read();
                }
                // Read the number
                double ret = b - '0';
                while (true) {
                    b = input.read();
                    if (b < '0' || '9' < b) break;
                    ret *= 10;
                    ret += b - '0';
                }
                // Handle decimal part
                if (b != '.') return sign * ret;
                double div = 1;
                b = input.read();
                while ('0' <= b && b <= '9') {
                    ret *= 10;
                    ret += b - '0';
                    div *= 10;
                    b = input.read();
                }
                return sign * ret / div;
            } catch (IOException e) {
                e.printStackTrace();
                return Double.NaN;
            }
        }

        // Read the next non-whitespace character from input
        public char nextChar() {
            try {
                int b = input.read();
                // Skip whitespace characters
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                return (char) b;
            } catch (IOException e) {
                e.printStackTrace();
                return 0;
            }
        }

        // Read the next string from input
        public String nextStr() {
