                StringBuilder sb = new StringBuilder();
                int b = input.read();
                // Skip leading whitespace
                while (Character.isWhitespace(b)) {
                    b = input.read();
                }
                // Read the string
                while (b != -1 && !Character.isWhitespace(b)) {
                    sb.append((char) b);
                    b = input.read();
                }
                return sb.toString();
            } catch (IOException e) {
                e.printStackTrace();
                return "";
            }
        }

        // Read the next line from input
        public String nextLine() {
            try {
                StringBuilder sb = new StringBuilder();
