public class Main {

    public static void main(String[] args) {

        // Create an instance of FastScanner to read input
        FastScanner fs = new FastScanner();

        // Read three long integers from input
        long N = fs.nextLong(); // Total number of items
        long A = fs.nextLong(); // Number of items of type A
        long B = fs.nextLong(); // Number of items of type B

        // Initialize the sum variable
        long s = 0;

        // Calculate the sum of A and B
        long x = A + B;

        // Calculate how many complete sets of (A + B) fit into N
        long y = (long) (N / x);

        // Calculate the total number of items of type A in complete sets
        s = y * A;

        // Calculate the remaining items after complete sets
        long nokori = N - x * y;

        // Add the remaining items to the sum
        // If remaining items are less than A, add all remaining items
        // Otherwise, add only A items
        if(nokori < A) {
            s += nokori;
        } else {
            s += A;
        }

        // Output the result
        System.out.println(s);
    }
}

class FastScanner {
    private final InputStream in = System.in; // Input stream for reading data
    private final byte[] buffer = new byte[1024]; // Buffer to store input data
    private int ptr = 0; // Pointer to the current position in the buffer
    private int buflen = 0; // Length of valid data in the buffer

    // Check if there is another byte to read
    private boolean hasNextByte() {
        if (ptr < buflen) {
            return true;
        } else {
            ptr = 0;
            try {
                buflen = in.read(buffer); // Read data into buffer
            } catch (IOException e) {
                e.printStackTrace();
            }
            if (buflen <= 0) {
                return false;
            }
        }
        return true;
    }

    // Read the next byte from the buffer
    private int readByte() { 
        if (hasNextByte()) return buffer[ptr++]; 
        else return -1;
    }

    // Check if a character is printable
    private static boolean isPrintableChar(int c) { 
        return 33 <= c && c <= 126;
    }

    // Check if there is another token to read
    public boolean hasNext() { 
        while(hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; 
        return hasNextByte();
    }

    // Read the next token as a String
    public String next() {
        if (!hasNext()) throw new NoSuchElementException();
        StringBuilder sb = new StringBuilder();
        int b = readByte();
        while(isPrintableChar(b)) {
            sb.appendCodePoint(b);
            b = readByte();
        }
        return sb.toString();
    }

    // Read the next token as a long integer
    public long nextLong() {
        if (!hasNext()) throw new NoSuchElementException();
        long n = 0;
        boolean minus = false;
        int b = readByte();
        if (b == '-') {
            minus = true;
            b = readByte();
        }
        if (b < '0' || '9' < b) {
            throw new NumberFormatException();
        }
        while(true){
            if ('0' <= b && b <= '9') {
                n *= 10;
                n += b - '0';
            } else if(b == -1 || !isPrintableChar(b)){
                return minus ? -n : n;
            } else {
                throw new NumberFormatException();
            }
            b = readByte();
        }
    }

    // Read the next token as an integer
    public int nextInt() {
        long nl = nextLong();
        if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
        return (int) nl;
    }

    // Read the next token as a double
    public double nextDouble() { 
        return Double.parseDouble(next());
    }
}

import java.io.BufferedReader;
