    	BufferedReader stdin = new BufferedReader(new InputStreamReader(System.in));
		String line; // Variable to store each line of input
		int numDS = -1; // Number of datasets to process
		int aSide = -1; // First side of the triangle
		int bSide = -1; // Second side of the triangle
		int cSide = -1; // Hypotenuse or third side of the triangle

		// List to store results for each dataset
		ArrayList<String> results = new ArrayList<String>();

    	try {
			// Read input until EOF or an empty line is encountered
			while ((line = stdin.readLine()) != null && line.length() != 0) {

				// Split the input line by spaces
				String[] checker = line.split(" ");

				// If the line contains only one number, it represents the number of datasets
				if (checker.length == 1){
					numDS = Integer.parseInt(checker[0]);
				} 
				// If the line contains three numbers, they represent the sides of a triangle
				else if (checker.length == 3){

					// Parse the three sides of the triangle
					int temp1 = Integer.parseInt(checker[0]);
					int temp2 = Integer.parseInt(checker[1]);
					int temp3 = Integer.parseInt(checker[2]);

					// Check if the sides are within the valid range (1 to 1000)
					if (temp1 < 1 || temp1 > 1000 ||
						temp2 < 1 || temp2 > 1000 ||
						temp3 < 1 || temp3 > 1000){
						// If any side is out of range, add "NO" to results
						results.add("NO");
					} else {

						// Determine which side is the largest (hypotenuse)
						if (temp1 > temp2 && temp1 > temp3){
							cSide = temp1;
							aSide = temp2;
							bSide = temp3;
						} else if (temp2 > temp1 && temp2 > temp3){
							cSide = temp2;
							aSide = temp1;
							bSide = temp3;
						} else {
							cSide = temp3;
							aSide = temp2;
							bSide = temp1;
						}

						// Check if the triangle is a right triangle using the Pythagorean theorem
						if ((cSide * cSide) == ((aSide * aSide) + (bSide * bSide))){
							results.add("YES");
						} else {
							results.add("NO");
						}

						// If the number of results matches the number of datasets, exit the loop
						if (results.size() == numDS){
							break;
						}
					}
				}
			}

