import java.util.Scanner;

public class Main {

	static int n; // Number of columns in the 2D array
	static int[][] a; // 2D array to store input values

	public static void main(String[] args) {
		Scanner sc = new Scanner(System.in); // Scanner object to read input
		n = sc.nextInt(); // Read the number of columns
		a = new int[2][n]; // Initialize a 2D array with 2 rows and n columns

		// Loop to fill the 2D array with input values
		for(int i = 0 ; i < 2 ; i++) {
			for(int j = 0 ; j < n ; j++) {
				a[i][j] = sc.nextInt(); // Read each element into the array
			}
		}

		// Start the depth-first search from the top-left corner of the array
		int ans = dfs(0, 0);

		// Print the result of the DFS
		System.out.println(ans);
	}

	// Depth-first search function to calculate the maximum sum path
	public static int dfs(int x, int y) {
		int ret = 0; // Variable to store the result of the current path

		// Base case: If starting at the top-left corner, add the value of that cell
		if(x == 0 && y == 0) {
			ret += a[x][y];
		}

		// Base case: If reaching the bottom-right corner, return 0 as no further path exists
		if(x == 1 && y == n - 1) {
			ret = 0;
		}

		// Check if both moving down and right are within bounds
		if(0 <= x + 1 && x + 1 < 2 && 0 <= y && y < n && 0 <= x && x < 2 && 0 <= y + 1 && y + 1 < n) {
			// Choose the maximum path sum between moving down or right
			ret += Math.max(dfs(x + 1, y) + a[x + 1][y], dfs(x, y + 1) + a[x][y + 1]);
		} 
		// Check if only moving down is within bounds
		else if(0 <= x + 1 && x + 1 < 2 && 0 <= y && y < n) {
			ret += dfs(x + 1, y) + a[x + 1][y];
		} 
		// Check if only moving right is within bounds
		else if(0 <= x && x < 2 && 0 <= y + 1 && y + 1 < n) {
			ret += dfs(x, y + 1) + a[x][y + 1];
		} 
		// If no moves are possible, return 0
		else {
			ret = 0;
		}

		// Return the maximum path sum from the current position
		return ret;
	}

}

