import java.io.*;
import java.util.*;

public class Main {

    public static void main(String[] args) throws IOException {
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        InputReader in = new InputReader(inputStream);
        InputReader.OutputWriter out = new InputReader.OutputWriter(outputStream);

        // Read the number of elements in the array
        int n = in.nextInt();
        int[] a = new int[n];

        // Populate the array with input values
        for (int i = 0; i < a.length; i++) {
            a[i] = in.nextInt();
        }

        // Initialize the minimum difference to the maximum possible integer value
        int min = Integer.MAX_VALUE;

        // Iterate over possible partition points in the array
        for (int i = 1; i < n; i++) {
            int sum1 = 0;
            int sum2 = 0;

            // Calculate the sum of elements for the two partitions
            for (int j = 0; j < a.length; j++) {
                if (j <= i) sum1 += a[j];
                else sum2 += a[j];
            }

            // Update the minimum difference between the two partition sums
            min = Math.min(min, Math.abs(sum1 - sum2));
        }

        // Output the minimum difference
        out.println(min);
        out.flush();
    }

    // Breadth-First Search (BFS) to find the shortest path to a target 'Y' in a grid
    private static int bfs(char[][] c, int i, int j, int length, boolean[][] visited) {
        // Queue to manage the BFS traversal
        LinkedList<Point> q = new LinkedList<>();
        q.add(new Point(i, j));
        int distance = 0;

        // Continue until the queue is empty
        while (!q.isEmpty()) {
            int size = q.size();

            // Process all nodes at the current distance
            for (int k = 0; k < size; k++) {
                Point current = q.pollFirst();
                visited[current.getI()][current.getJ()] = true;

                // Check all four possible directions (up, down, left, right)
                int up = current.getI() - 1;
                if (up >= 0) {
                    if (!visited[up][current.getJ()]) {
                        if (c[up][current.getJ()] == 'Y') return distance + 1;
                        else q.add(new Point(up, current.getJ()));
                    }
                }

                int down = current.getI() + 1;
                if (down < c.length) {
                    if (!visited[down][current.getJ()]) {
                        if (c[down][current.getJ()] == 'Y') return distance + 1;
                        else q.add(new Point(down, current.getJ()));
                    }
                }

                int left = current.getJ() - 1;
                if (left >= 0) {
                    if (!visited[current.getI()][left]) {
                        if (c[current.getI()][left] == 'Y') return distance + 1;
                        else q.add(new Point(current.getI(), left));
                    }
                }

                int right = current.getJ() + 1;
                if (right < c[i].length) {
                    if (!visited[current.getI()][right]) {
                        if (c[current.getI()][right] == 'Y') return distance + 1;
                        else q.add(new Point(current.getI(), right));
                    }
                }
            }
            // Increment the distance after processing all nodes at the current level
            distance++;
        }
        // Return a large value if no path to 'Y' is found
        return Integer.MAX_VALUE;
    }
}

