import java.io.*;
import java.math.BigInteger;
import java.util.*;

public class Main {
    static BufferedReader br;

    // Method to read an integer from the input
    static int cin() throws Exception {
        return Integer.valueOf(br.readLine());
    }

    // Method to read a line of input, split it by spaces, and convert it to an array of integers
    static int[] split() throws Exception {
        String[] cmd = br.readLine().split(" ");
        int[] ans = new int[cmd.length];
        for (int i = 0; i < cmd.length; i++) {
            ans[i] = Integer.valueOf(cmd[i]);
        }
        return ans;
    }

    // Method to solve the kMarsh problem
    static void kMarsh(String[] grid) {
        int n = grid.length; // Number of rows in the grid
        int m = grid[0].length(); // Number of columns in the grid

        // Convert the grid from String array to a 2D char array
        char[][] mat = new char[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                mat[i][j] = grid[i].charAt(j);
            }
        }

        // Array to store the first 'x' encountered in each column from a given row downwards
        int[][] first = new int[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                int ind = n; // Default index set to n (out of bounds)
                for (int k = j; k < n; k++) {
                    if (mat[k][i] == 'x') {
                        ind = k; // Update index if 'x' is found
                        break;
                    }
                }
                first[i][j] = ind;
            }
        }

        // 3D boolean array to check if there are no 'x' between two columns in a row
        boolean[][][] there = new boolean[n][m][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                for (int k = j; k < m; k++) {
                    boolean b1 = (mat[i][k] == 'x') ? false : true; // Check if current position is not 'x'
                    boolean b2 = true;
                    if (k != j)
                        b2 = there[i][j][k - 1]; // Check previous state
                    if (!b1 || !b2)
                        there[i][j][k] = false; // If any condition fails, set to false
                    else
                        there[i][j][k] = true; // Otherwise, set to true
                }
            }
        }

        int ans = 0; // Variable to store the maximum perimeter found
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (mat[i][j] == 'x')
                    continue; // Skip if the current position is 'x'
                int f1 = first[j][i] - 1; // Get the first 'x' index for the current column
                for (int k = j + 1; k < m; k++) {
                    if (mat[i][k] == 'x')
                        break; // Break if 'x' is encountered
                    int f2 = first[k][i] - 1; // Get the first 'x' index for the next column
                    int x = Math.min(f1, f2); // Find the minimum index of 'x' between two columns
                    if (x == i)
                        continue; // Continue if no valid rectangle can be formed
                    if (!there[x][j][k])
                        continue; // Continue if there is an 'x' between the columns
                    int p = 2 * (x - i + k - j); // Calculate the perimeter of the rectangle

                    ans = Math.max(ans, p); // Update the maximum perimeter found
                }
            }
        }

        // Print the result
        if (ans != 0)
            System.out.println(ans);
        else
            System.out.println("impossible");
    }

    public static void main(String[] args) throws Exception {
        br = new BufferedReader(new InputStreamReader(System.in));
        double l = Double.valueOf(br.readLine()); // Read a double value from input
        System.out.println(Math.pow(l / 3, 3)); // Calculate and print the cube of (l/3)
    }
}

