import java.util.Comparator;
import java.util.Scanner;

public class Main {
    // Scanner object to read input from the console
    Scanner sc = new Scanner(System.in);
    // String to store the input
    String s;

    // Method to initiate the process
    public void run(){
        // Read the next input token as a string
        s = sc.next();
        // Call the solve method to process the input
        solve();
    }

    // Method to solve the problem based on the input string
    public void solve(){
        // Variable to store the result, initialized to 0 (indicating "WA")
        int ans = 0;

        // Check if the first character of the string is 'A'
        if(s.substring(0, 1).equals("A")){
            // Variable to store the position of 'C', initialized to -1 (not found)
            int c = -1;

            // Loop through the string starting from the third character to the second last character
            for(int i = 2; i < s.length() - 1; i++) {
                // Check if the current character is 'C'
                if (s.substring(i, i + 1).equals("C")) {
                    // Store the position of 'C' and break the loop
                    c = i;
                    break;
                }
            }

            // If 'C' was found in the valid position
            if(c != -1) {
                // Flag to check if all other characters are lowercase letters
                int flag = 1;

                // Loop through the string starting from the second character
                for (int i = 1; i < s.length(); i++) {
                    // Skip the position of 'C'
                    if (i != c) {
                        // Get the current character
                        char t = s.charAt(i);

                        // Check if the character is a lowercase letter
                        if (t == 'a' || t == 'b' || t == 'c' || t == 'd' || t == 'e' || t == 'f'
                                || t == 'g' || t == 'h' || t == 'i' || t == 'j' || t == 'k' || t == 'l'
                                || t == 'm' || t == 'n' || t == 'o' || t == 'p' || t == 'q' || t == 'r'
                                || t == 's' || t == 't' || t == 'u' || t == 'v' || t == 'w' || t == 'x'
                                || t == 'y' || t == 'z') {
                            // Do nothing if it's a lowercase letter
                        } else {
                            // Set flag to -1 if any character is not a lowercase letter
                            flag = -1;
                        }
                    }
                }

                // If all conditions are met, set ans to 1 (indicating "AC")
                if(flag != -1) ans = 1;
            }
        }

        // Print the result based on the value of ans
        if(ans == 0){
            System.out.println("WA"); // Wrong Answer
        }
        else{
            System.out.println("AC"); // Accepted
        }
    }

    // Main method to start the program
    public static void main(String[] args){
        // Create an instance of Main and call the run method
        new Main().run();
    }

    // Class to represent a pair of integers
    static class Pair {
        int first, second;

        // Constructor to initialize the pair
        public Pair(int a, int b) {
            this.first = a;
            this.second = b;
        }
    }

    // Class to represent an edge with a destination and cost
    static class Edge{
        int to, cost;

        // Constructor to initialize the edge
        public Edge(int a, int b){
            this.to = a;
            this.cost = b;
        }
    }

    // Comparator class to compare pairs based on the first element
    class MyComparator implements Comparator {
        @Override
        public int compare (Object arg0, Object arg1) {
            int x = ((Pair)arg0).first;
            int y = ((Pair)arg1).first;

            // Return 1 if x < y, -1 if x > y, 0 if equal
            if (x < y) {
                return 1;
            } else if (x > y) {
                return -1;
            } else{
                return 0;
            }
        }
    }

    // Union-Find data structure for disjoint set operations
    static class UnionFind{
        int par[]; // Parent array
        int rank[]; // Rank array

        // Constructor to initialize the Union-Find structure
        public UnionFind(int maxn){
            par = new int[maxn];
            rank = new int[maxn];

            // Initialize each element to be its own parent and rank to 0
            for(int i = 0; i < maxn; i++){
                par[i] = i;
                rank[i] = 0;
            }
        }

        // Method to find the root of an element with path compression
        int find(int x){
            if(par[x] == x){
                return x;
            }
            else {
                return par[x] = find(par[x]);
            }
        }

        // Method to unite two sets
        void unite (int x, int y){
            x = find(x);
            y = find(y);
            if(x == y){
                return;
            }

            // Union by rank
            if(rank[x] < rank[y]){
                par[x] = y;
            }
            else{
                par[y] = x;
                if(rank[x] == rank[y]) rank[x]++;
            }
        }

        // Method to check if two elements are in the same set
        boolean same(int x, int y){
            return find(x) == find(y);
        }
    }
}

