        out = new PrintWriter(System.out);

        // Call the solve method to execute the solution
        solve();
        // Flush the output buffer
        out.flush();
        // Close the input and output streams
        in.close();
        out.close();
    }

    // Custom FastScanner class for efficient input reading
    static class FastScanner {
        private Reader input;

        // Constructor with default input stream
        public FastScanner() {this(System.in);}
        // Constructor with specified input stream
        public FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));}

        // Method to close the input stream
        public void close() {
            try {
                this.input.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        // Method to read the next integer
        public int nextInt() {return (int) nextLong();}

        // Method to read the next long integer
        public long nextLong() {
            try {
                int sign = 1;
                int b = input.read();
                // Skip non-numeric characters
                while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                    b = input.read();
                }
                // Handle negative numbers
                if (b == '-') {
                    sign = -1;
                    b = input.read();
                } else if (b == '+') {
