import java.io.*;
import java.util.*;
import java.lang.*;

public class Main {

    // FastReader class to efficiently read input from the console
    public static class FastReader {
        private InputStream stream; // Input stream for reading data
        private byte[] buf = new byte[1024]; // Buffer to store input data
        private int curChar; // Current character index in the buffer
        private int numChars; // Number of characters read into the buffer
        private SpaceCharFilter filter; // Optional filter for space characters

        // Constructor to initialize the input stream
        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1)
                throw new InputMismatchException(); // Throw exception if no more characters
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf); // Read data into buffer
                } catch (IOException e) {
                    throw new InputMismatchException(); // Handle IO exception
                }
                if (numChars <= 0)
                    return -1; // Return -1 if end of stream
            }
            return buf[curChar++]; // Return the next character
        }

        // Method to read the next line of input
        public String nextLine() {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            String str = "";
            try {
                str = br.readLine(); // Read a line from the console
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace on exception
            }
            return str;
        }

        // Method to read the next integer from input
        public int nextInt() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Validate digit
                res *= 10;
                res += c - '0'; // Convert character to integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed integer
        }

        // Method to read the next long integer from input
        public long nextLong() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            long res = 0;
            do {
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Validate digit
                res *= 10;
                res += c - '0'; // Convert character to long integer
                c = read();
            } while (!isSpaceChar(c));
            return res * sgn; // Return the parsed long integer
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            int sgn = 1;
            if (c == '-') {
                sgn = -1; // Handle negative numbers
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt()); // Handle scientific notation
                if (c < '0' || c > '9')
                    throw new InputMismatchException(); // Validate digit
                res *= 10;
                res += c - '0'; // Convert character to double
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt()); // Handle scientific notation
                    if (c < '0' || c > '9')
                        throw new InputMismatchException(); // Validate digit
                    m /= 10;
                    res += (c - '0') * m; // Add fractional part
                    c = read();
                }
            }
            return res * sgn; // Return the parsed double
        }

        // Method to read the next character from input
        public char nextChar() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            return (char) c; // Return the next character
        }

        // Method to read the next word from input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read(); // Skip space characters
            StringBuilder res = new StringBuilder();
            do {
                res.appendCodePoint(c); // Append character to result
                c = read();
            } while (!isSpaceChar(c));
            return res.toString(); // Return the parsed word
        }

        // Method to check if a character is a space character
        public boolean isSpaceChar(int c) {
            if (filter != null)
                return filter.isSpaceChar(c); // Use custom filter if available
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1; // Default space characters
        }

        // Interface for custom space character filter
        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);
        }
    }

    // Method to calculate the greatest common divisor (GCD) of two numbers
    static long gcd(long a, long b) {
        if (a == 0)
            return b; // Base case: if a is 0, return b
        return gcd(b % a, a); // Recursive call
    }

    // Method to calculate the least common multiple (LCM) of two numbers
    static long lcm(long a, long b) {
        return (a * b) / gcd(a, b); // LCM formula using GCD
    }

    // Method to find the maximum subarray sum using Kadane's algorithm
    static long func(long a[], long size, int s) {
        long max1 = a[s]; // Initialize max1 with the first element
        long maxc = a[s]; // Initialize maxc with the first element
        for (int i = s + 1; i < size; i++) {
            maxc = Math.max(a[i], maxc + a[i]); // Update maxc with the maximum of current element or sum
            max1 = Math.max(maxc, max1); // Update max1 with the maximum of maxc or max1
        }
        return max1; // Return the maximum subarray sum
    }

    // Main method to execute the program
    public static void main(String args[]) {
        InputStream inputStream = System.in; // Input stream for reading data
        OutputStream outputStream = System.out; // Output stream for writing data
        FastReader in = new FastReader(inputStream); // FastReader instance for input
        PrintWriter w = new PrintWriter(outputStream); // PrintWriter instance for output

        // Read two strings from input
        String n, m, s = "";
        n = in.next();
        m = in.next();

        // Compare the two strings as integers and concatenate accordingly
        if (Integer.parseInt(n) < Integer.parseInt(m)) {
            for (int i = 0; i < Integer.parseInt(m); i++) {
                s += n; // Concatenate n, m times
            }
        } else {
            for (int i = 0; i < Integer.parseInt(n); i++) {
                s += m; // Concatenate m, n times
            }
        }

        // Print the resulting string
        w.println(s);
        w.close(); // Close the PrintWriter
    }
