import java.util.HashSet;
import java.io.Closeable;
import java.util.Set;
import java.io.IOException;
import java.util.NoSuchElementException;
import java.io.InputStream;

public class Main {
    public static void main(String[] args) {
        // Initialize input and output streams
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;

        // Create a FastScanner object for efficient input reading
        FastScanner in = new FastScanner(inputStream);

        // Create a PrintWriter object for efficient output writing
        PrintWriter out = new PrintWriter(outputStream);

        // Create an instance of the BKagamiMochi class to solve the problem
        BKagamiMochi solver = new BKagamiMochi();

        // Call the solve method to execute the solution logic
        solver.solve(1, in, out);

        // Close the PrintWriter to flush the output
        out.close();
    }

    static class BKagamiMochi {
        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            // Read the number of mochi from input
            int N = in.nextInt();

            // Use a HashSet to store unique mochi diameters
            Set<Integer> mochi = new HashSet<>();

            // Read each mochi diameter and add it to the set
            for (int i = 0; i < N; i++) {
                mochi.add(in.nextInt());
            }

            // Output the number of unique mochi diameters
            out.println(mochi.size());
        }
    }

    static class FastScanner implements Closeable {
        private final InputStream in; // InputStream for reading input
        private final byte[] buffer = new byte[1024]; // Buffer for storing input bytes
        private int ptr = 0; // Pointer to the current position in the buffer
        private int buflen = 0; // Length of valid data in the buffer

        public FastScanner(InputStream in) {
            this.in = in; // Initialize the input stream
        }

        // Check if there is another byte to read
        private boolean hasNextByte() {
            if (ptr < buflen) {
                return true; // There is more data in the buffer
            } else {
                ptr = 0; // Reset pointer
                try {
                    buflen = in.read(buffer); // Read more data into the buffer
                } catch (IOException e) {
                    e.printStackTrace(); // Print stack trace on error
                }
                if (buflen <= 0) {
                    return false; // No more data to read
                }
            }
            return true; // Data is available
        }

        // Read the next byte from the buffer
        private int readByte() {
            if (hasNextByte()) return buffer[ptr++]; // Return the next byte
            else return -1; // Indicate end of stream
        }

        // Check if a character is printable
        private static boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126; // ASCII range for printable characters
        }

        // Check if there is another token to read
        public boolean hasNext() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++; // Skip non-printable characters
            return hasNextByte(); // Return true if there is more data
        }

        // Read the next long integer from input
        public long nextLong() {
            if (!hasNext()) throw new NoSuchElementException(); // No more elements
            long n = 0; // Initialize result
            boolean minus = false; // Flag for negative numbers
            int b = readByte(); // Read the first byte
            if (b == '-') {
                minus = true; // Set negative flag
                b = readByte(); // Read the next byte
            }
            if (b < '0' || '9' < b) {
                throw new NumberFormatException(); // Invalid number format
            }
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10; // Shift digits left
                    n += b - '0'; // Add the new digit
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n; // Return the result
                } else {
                    throw new NumberFormatException(); // Invalid number format
                }
                b = readByte(); // Read the next byte
            }
        }

        // Read the next integer from input
        public int nextInt() {
            long nl = nextLong(); // Read as long
            if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException(); // Check range
            return (int) nl; // Cast to int
        }

        // Close the input stream
        public void close() {
            try {
                in.close(); // Close the stream
            } catch (IOException e) {
                e.printStackTrace(); // Print stack trace on error
            }
        }
    }
}

