public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        // Read the number of steps (n) and the number of broken steps (m)
        int n = sc.nextInt();
        int m = sc.nextInt();

        // Initialize flag to check for consecutive broken steps and answer variable
        int flag = 1;
        int ans = 0;

        // Array to store the indices of broken steps
        int[] a = new int[m];
        for (int i = 0; i < m; i++) {
            // Store the zero-based index of broken steps
            a[i] = sc.nextInt() - 1;
        }

        // Check if there are at least two broken steps
        if (m >= 2) {
            // Check for consecutive broken steps
            for (int i = 0; i < m - 1; i++) {
                if (a[i + 1] == a[i] + 1) {
                    // If consecutive broken steps are found, set flag to 0
                    flag = 0;
                    break;
                }
            }
        }

        // Array to store the number of ways to reach each step
        int[] way = new int[n];
        int ccnt = 0; // Counter for broken steps
        for (int i = 0; i < n; i++) {
            for (int j = ccnt; j < m; j++) {
                if (i == a[j]) {
                    // Mark the step as broken
                    way[i] = -1;
                    ccnt++;
                    break;
                }
            }
        }

        // Handle base cases for different values of n
        if (n == 1) {
            // If there's only one step, there's one way to stand on it
            way[0] = 1;
        } else if (n == 2) {
            if (a.length == 0) {
                // If no broken steps, two ways to reach the second step
                way[0] = 1;
                way[1] = 2;
            } else if (a.length == 1) {
                // If one broken step, only one way to reach the second step
                way[0] = 0;
                way[1] = 1;
            }
        } else if (n >= 3) {
            // Initialize the first two steps based on whether they are broken
            if (way[0] != -1) {
                way[0] = 1;
            } else {
                way[0] = 0;
            }

            if (way[1] != -1) {
                if (way[0] == 0) {
                    way[1] = 1;
                } else if (way[0] == 1) {
                    way[1] = 2;
                }
            } else if (way[1] == -1) {
                way[1] = 0;
            }

            // Calculate the number of ways for each step using dynamic programming
            for (int i = 2; i < n; i++) {
                if (way[i] != -1) {
                    // Number of ways to reach step i is the sum of ways to reach the two previous steps
                    way[i] = way[i - 1] + way[i - 2];
                    // Apply modulo operation to prevent overflow
                    way[i] = way[i] % 1000000007;
                } else {
                    // If the step is broken, no way to reach it
                    way[i] = 0;
                }
            }
        }

        // The answer is the number of ways to reach the last step
        ans = way[n - 1] % 1000000007;

        // If there are consecutive broken steps, print 0
        if (flag == 0) {
            System.out.println("0");
        } else {
            // Otherwise, print the calculated number of ways
            System.out.println(ans);
        }

        // This loop does nothing and can be removed
        for (int i = 0; i < n; i++) {
            // No operation
        }
    }
}

