        // Create an InputReader object to read input from the standard input stream
        InputReader in = new InputReader(System.in);
        // Create a PrintWriter object to write output to the standard output stream
        PrintWriter w = new PrintWriter(System.out);

        // Read an integer n from input, which represents the size of the array
        int n = in.nextInt();
        // Read an array of integers of size n from input
        int[] a = in.nextIntArray(n);

        // Create a HashSet to keep track of visited indices
        HashSet<Integer> hs = new HashSet<>();
        // Add the starting index (1) to the HashSet
        hs.add(1);

        // Initialize variables: c to track the current index, st to count steps
        int c = 1, st = 0;

        // Infinite loop to traverse the array based on the problem's logic
        while (true) {
            // Increment the step counter
            st++;
            // Update c to the value at the current index in the array (1-based index)
            c = a[c - 1];

            // Check if the current index points to the target value (2)
            if (c == 2) {
                // If found, print the number of steps taken and exit
                w.println(st);
                w.close();
                return;
            }

            // Check if the current index has already been visited
            if (hs.contains(c)) {
                // If a cycle is detected, print -1 and exit
                w.println(-1);
                w.close();
                return;
            }

            // Add the current index to the HashSet to mark it as visited
            hs.add(c);
        }
    }

    // Custom InputReader class to handle input operations
    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curChar;
        private int numChars;

        // Constructor to initialize the InputReader with an input stream
        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        // Method to read the next byte of input
        public int read() {
            if (numChars == -1)
                throw new UnknownError();
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    // Read bytes into the buffer
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new UnknownError();
                }
                if (numChars <= 0)
                    return -1;
            }
            return buf[curChar++];
        }

        // Method to peek at the next byte of input without advancing the cursor
        public int peek() {
            if (numChars == -1)
                return -1;
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    return -1;
                }
                if (numChars <= 0)
                    return -1;
            }
            return buf[curChar];
        }

        // Method to skip a specified number of bytes
        public void skip(int x) {
            while (x-- > 0)
                read();
        }

        // Method to read the next integer from input
        public int nextInt() {
            return Integer.parseInt(next());
        }

        // Method to read the next long integer from input
        public long nextLong() {
            return Long.parseLong(next());
        }

        // Method to read the next string from input
        public String nextString() {
            return next();
        }

        // Method to read the next token from input
        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            StringBuffer res = new StringBuffer();
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString();
        }

        // Method to read the next line from input
        public String nextLine() {
            StringBuffer buf = new StringBuffer();
            int c = read();
            while (c != '\n' && c != -1) {
                if (c != '\r')
                    buf.appendCodePoint(c);
                c = read();
            }
            return buf.toString();
        }

        // Method to read the next double from input
        public double nextDouble() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            double res = 0;
            while (!isSpaceChar(c) && c != '.') {
                if (c == 'e' || c == 'E')
                    return res * Math.pow(10, nextInt());
                if (c < '0' || c > '9')
                    throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            }
            if (c == '.') {
                c = read();
                double m = 1;
                while (!isSpaceChar(c)) {
                    if (c == 'e' || c == 'E')
                        return res * Math.pow(10, nextInt());
                    if (c < '0' || c > '9')
                        throw new InputMismatchException();
                    m /= 10;
                    res += (c - '0') * m;
                    c = read();
                }
            }
            return res * sgn;
        }

        // Method to read an array of integers from input
        public int[] nextIntArray(int n) {
            int[] a = new int[n];
            for (int i = 0; i < n; i++)
                a[i] = nextInt();
            return a;
        }

        // Method to read an array of long integers from input
        public long[] nextLongArray(int n) {
            long[] a = new long[n];
            for (int i = 0; i < n; i++)
                a[i] = nextLong();
            return a;
        }

        // Method to check if there is more input available
        public boolean hasNext() {
            int value;
            while (isSpaceChar(value = peek()) && value != -1)
                read();
            return value != -1;
        }

        // Helper method to check if a character is a whitespace character
        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }
    }
}

