            long i; // Variable to store the greatest common divisor (GCD)

            // Check if 'a' is greater than 'b'
            if (a > b) {
                // Infinite loop to find the least common multiple (LCM) of 'a' and 'b'
                for (;;) {
                    // If 'a1' is a multiple of 'b', break the loop
                    if (a1 % b == 0) {
                        break;
                    }
                    // Increment 'a1' by 'a' to find the next multiple of 'a'
                    a1 += a;
                }
                // Check if 'a' is a multiple of 'b'
                if (a % b == 0) {
                    // If true, print 'b' and the LCM 'a1'
                    System.out.println(b + " " + a1);
                } else {
                    // Find the greatest common divisor (GCD) of 'a' and 'b'
                    for (i = b / 2; i > 0; i--) {
                        // If 'i' is a divisor of both 'a' and 'b', break the loop
                        if (a % i == 0 && b % i == 0) {
                            break;
                        }
                    }
                    // Print the GCD 'i' and the LCM 'a1'
                    System.out.println(i + " " + a1);
                }
            }
            // Check if 'a' is less than 'b'
            else if (a < b) {
                // Infinite loop to find the least common multiple (LCM) of 'a' and 'b'
                for (;;) {
                    // If 'b1' is a multiple of 'a', break the loop
                    if (b1 % a == 0) {
                        break;
                    }
                    // Increment 'b1' by 'b' to find the next multiple of 'b'
                    b1 += b;
                }
                // Check if 'b' is a multiple of 'a'
                if (b % a == 0) {
                    // If true, print 'a' and the LCM 'b1'
                    System.out.println(a + " " + b1);
                } else {
                    // Find the greatest common divisor (GCD) of 'a' and 'b'
                    for (i = a / 2; i > 0; i--) {
                        // If 'i' is a divisor of both 'a' and 'b', break the loop
                        if (a % i == 0 && b % i == 0) {
