		new Main().run(); // Create an instance of Main and run it
	}

	private byte[] inbuf = new byte[1024]; // Buffer for input
	public int lenbuf = 0, ptrbuf = 0; // Buffer length and pointer

	// Method to read a byte from input
	private int readByte() {
		if (lenbuf == -1)
			throw new InputMismatchException(); // Throw exception if buffer length is -1
		if (ptrbuf >= lenbuf) {
			ptrbuf = 0; // Reset pointer
			try {
				lenbuf = is.read(inbuf); // Read into buffer
			} catch (IOException e) {
				throw new InputMismatchException(); // Throw exception on IO error
			}
			if (lenbuf <= 0)
				return -1; // Return -1 if no bytes read
		}
		return inbuf[ptrbuf++]; // Return next byte
	}

	// Method to check if a character is a space
	private boolean isSpaceChar(int c) {
		return !(c >= 33 && c <= 126); // Return true if character is not printable
	}

	// Method to skip spaces
	private int skip() {
		int b;
		while ((b = readByte()) != -1 && isSpaceChar(b))
			;
		return b; // Return first non-space character
	}

	// Method to read a double from input
	private double nd() {
		return Double.parseDouble(ns()); // Parse and return a double
	}

	// Method to read a character from input
	private char nc() {
		return (char) skip(); // Return next non-space character
	}

	// Method to read a string from input
	private String ns() {
		int b = skip(); // Skip spaces
		StringBuilder sb = new StringBuilder(); // StringBuilder for building the string
		while (!(isSpaceChar(b))) { 
			sb.appendCodePoint(b); // Append character to StringBuilder
			b = readByte(); // Read next byte
		}
		return sb.toString(); // Return the built string
	}

	// Method to read a character array of length n
	private char[] ns(int n) {
		char[] buf = new char[n]; // Buffer for characters
		int b = skip(), p = 0; // Skip spaces and initialize pointer
		while (p < n && !(isSpaceChar(b))) {
			buf[p++] = (char) b; // Add character to buffer
			b = readByte(); // Read next byte
		}
		return n == p ? buf : Arrays.copyOf(buf, p); // Return buffer or its copy
	}

	// Method to read a 2D character array
	private char[][] nm(int n, int m) {
		char[][] map = new char[n][]; // Initialize 2D array
		for (int i = 0; i < n; i++)
			map[i] = ns(m); // Read each row
		return map; // Return the 2D array
	}

	// Method to read an integer array of length n
	private int[] na(int n) {
		int[] a = new int[n]; // Initialize array
		for (int i = 0; i < n; i++)
			a[i] = ni(); // Read each integer
		return a; // Return the array
	}

	// Method to read an integer from input
	private int ni() {
		int num = 0, b;
		boolean minus = false; // Flag for negative numbers
		while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-'))
			;
		if (b == '-') {
			minus = true; // Set flag if negative
			b = readByte(); // Read next byte
		}

		while (true) {
			if (b >= '0' && b <= '9') {
				num = num * 10 + (b - '0'); // Build the number
			} else {
				return minus ? -num : num; // Return the number with correct sign
			}
			b = readByte(); // Read next byte
		}
	}

	// Method to read a long integer from input
	private long nl() {
		long num = 0;
		int b;
		boolean minus = false; // Flag for negative numbers
		while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-'))
			;
		if (b == '-') {
			minus = true; // Set flag if negative
			b = readByte(); // Read next byte
		}

		while (true) {
			if (b >= '0' && b <= '9') {
				num = num * 10 + (b - '0'); // Build the number
			} else {
				return minus ? -num : num; // Return the number with correct sign
			}
			b = readByte(); // Read next byte
		}
	}

	// Utility method to print objects for debugging
	private static void tr(Object... o) {
		System.out.println(Arrays.deepToString(o)); // Print objects as a deep string
	}
