    }

    // Method to solve the problem and print the result
    void solve(PrintWriter out) {
        // Check if A and B are equal
        if (A == B) {
            // If equal, print the sum of A and B
            out.println(A + B);
        } else if (A > B) {
            // If A is greater than B, print 2 * A - 1
            out.println(2 * A - 1);
        } else {
            // If B is greater than A, print 2 * B - 1
            out.println(2 * B - 1);
        }
    }

