class Main {
    /**
     * Checks if the given string is a "strong anagram".
     * A strong anagram is defined by a specific symmetry and mirroring property
     * around its center.
     *
     * @param s The input string to be checked.
     * @return true if the string is a strong anagram, false otherwise.
     */
    static boolean isStrongAnagram(String s) {
        int length = s.length(); // Get the length of the string
        int mid = (length - 1) / 2; // Calculate the middle index of the string
        boolean isMidOdd = mid % 2 == 1; // Check if the middle index is odd
        int mid1 = (mid - 1) / 2; // Calculate the middle index of the first half
        if (!isMidOdd) mid1++; // Adjust mid1 if the middle index is not odd
        int start2 = (length + 1) / 2; // Calculate the starting index of the second half
        int mid2 = start2 + mid1; // Calculate the middle index of the second half

        // Stacks to help with symmetry checking
        Stack<Character> stackAll = new Stack<>();
        Stack<Character> stackSub = new Stack<>();
        char c, tmp;

        // Iterate over each character in the string
        for (int i = 0; i < length; i++) {
            c = s.charAt(i); // Get the current character

            if (i < mid) { // First half of the string
                stackAll.push(c); // Push character onto the main stack
                if (i < mid1) {
                    stackSub.push(c); // Push onto the sub stack if within the first quarter
                } else if (!isMidOdd || i > mid1) {
                    // Check symmetry for the first half
                    tmp = stackSub.pop();
                    if (c != tmp) return false; // If not symmetric, return false
                }
            } else if (i == mid) { // Middle character
                if (!stackSub.isEmpty()) return false; // Ensure sub stack is empty at the middle
            } else { // Second half of the string
                tmp = stackAll.pop(); // Pop from the main stack
                if (c != tmp) return false; // If not symmetric, return false
                if (i >= start2) {
                    if (i < mid2) {
                        stackSub.push(c); // Push onto the sub stack if within the third quarter
                    } else if (!isMidOdd || i > mid2) {
                        // Check symmetry for the second half
                        tmp = stackSub.pop();
                        if (c != tmp) return false; // If not symmetric, return false
                    }
                }
            }
        }

        // Ensure both stacks are empty at the end
        if (!stackAll.isEmpty() || !stackSub.isEmpty()) return false;
        return true; // If all checks pass, return true
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in); // Scanner for input
        PrintWriter out = new PrintWriter(System.out); // PrintWriter for output

        String s = sc.next(); // Read the input string

        // Check if the string is a strong anagram and print the result
        if (isStrongAnagram(s)) {
            out.println("Yes");
        } else {
            out.println("No");
        }
        out.flush(); // Flush the output
    }
}
